window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["characters"]={"updatedAt":"2026-06-16","count":64,"chars":[{"id":"vuong-lam","name":"Vương Lâm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lấy toàn bộ tiên ngọc Phẩm Linh Các","text":"Với thân phận Đệ thất tử Tử hệ đã 103 năm chưa lĩnh tiên ngọc, Vương Lâm vào tiên cảnh tầng bảy Phẩm Linh Các, chọn lấy toàn bộ và thu trọn 123.600 khối tiên ngọc cao như núi vào túi trữ vật, định bế quan trong ba tháng để đột phá Anh Biến trung kỳ, tranh đoạt danh hiệu thiên vận thất tử."},{"chuong":"@c0458","importance":"normal","tieuDe":"Năm người vây kích tại Tử Lâm Các","text":"Vừa về Tử Lâm Các, hắn bị năm người hợp vây gồm tứ sư tỷ Tử hệ, Triệu Tinh Sát, đệ tử thứ hai Lam tông, Tư Mã Như Phong và một người y phục xanh nửa bước vấn đỉnh; tứ sư tỷ bắt quyết thi triển Tử thuật - Na di bao trùm mười dặm để khởi chiến."},{"chuong":"@c0459","importance":"normal","tieuDe":"Bị vây khốn thạch lâm khốn địa","text":"Vương Lâm bị tứ sư tỷ cùng Triệu Tinh Sát, nhị sư huynh và hai người Thanh-Lam hai hệ liên thủ khóa không gian, phát bốn đạo sát khí chấn nhiếp rồi na di tới thạch lâm khốn địa ngoài Thiên Vận Tông hơn mười ngàn dặm. Tứ sư tỷ hẹn ba năm sau tới thả ra, để hắn yên tĩnh bế quan."},{"bridge":true,"khoang":"@c0459–@c0459","text":"Hắn thử phá vây nhiều cách — chém kiếm quang bằng tiên kiếm, bay thẳng lên trên chịu lực cản tương đương Anh Biến hậu kỳ, rồi cho Hứa Lập Quốc và loan đao lao thử — đều bị trận pháp triệt tiêu."},{"chuong":"@c0459","importance":"normal","tieuDe":"Quyết tu luyện đột phá Anh Biến trung kỳ","text":"Nhận ra kẻ địch định vây tới khi tranh đoạt danh hiệu Thiên Vận Thất Tử kết thúc, Vương Lâm quyết không chờ ba năm mà tự phá nơi này. Hắn tìm được biên giới thạch lâm, ngồi khoanh chân hấp thu lượng lớn tiên ngọc luyện công, sau lưng hiện quầng sáng vàng báo hiệu tiên lực đạt bão hòa."},{"chuong":"@c0460","importance":"normal","tieuDe":"Hoàn tất hấp thu tiên lực","text":"Toàn bộ tiên lực điên cuồng nhập thể, Vương Lâm dồn toàn lực hấp thu suốt ba tháng tại thạch lâm cách Thiên Vận Tông hơn mười ngàn dặm."},{"chuong":"@c0460","importance":"normal","tieuDe":"Đột phá chấn thiên địa","text":"Mở mắt phát hai luồng quang như trăng rằm, một cái nhấn tay làm thạch lâm mười dặm tan thành bụi; há miệng hút thu khí tức như phễu rồi thét dài chấn động thiên địa, vụt đứng dậy dáng như đội trời đạp đất."},{"chuong":"@c0461","importance":"normal","tieuDe":"Phá trận thoát thạch lâm","text":"Sau ba tháng bị tấm màn sáng hình vòm vây khốn trong thạch lâm rộng mười dặm, Vương Lâm bay lên sát đỉnh màn, dùng Tịch Diệt Chỉ điểm tạo vô số vết nứt nhưng trận tự khôi phục; hắn chuyển sang Hóa Ma Chỉ nghịch hóa toàn bộ tiên lực thành ma hỏa tím, thiêu rụi cả tấm màn chỉ trong ba nhịp thở."},{"chuong":"@c0461","importance":"normal","tieuDe":"Trở về Thiên Vận Tông báo thù","text":"Không thuộc địa hình, Vương Lâm thả nguyên thần Tào Nhất Đấu dẫn đường, thuấn di ba mươi vạn dặm về hướng tây; hồi tưởng bị Tử hệ nhất mạch chèn ép na di vây khốn, hắn lập thề ai phạm ta giết không tha, xuất hiện thành cầu vồng tím từ đằng đông ngay giữa thọ yến ngàn năm của Thiên Vận Tử đúng lúc Triệu Tinh Sát chúc rượu."},{"chuong":"@c0462","importance":"normal","tieuDe":"Xông vào thọ yến truy sát kẻ thù","text":"Cưỡi đám mây tím phá không tới Tử Tông Sơn trên Thiên Vận Tinh, kinh động cả buổi thọ yến của sư tôn Tử hệ. Hắn dùng Cấm Phiên xé tan Thượng chi lực của nhị sư huynh, cảnh cáo các tu sĩ tông phái khác không được can dự, rồi khơi ma hỏa quyết tâm đòi mạng."},{"chuong":"@c0462","importance":"normal","tieuDe":"Ma hỏa tự bạo phá quyết Triệu Tinh Sát","text":"Khi Triệu Tinh Sát bước ra dùng Đại tự tại thiên địa quyết bọc ma hỏa hòng cản, Vương Lâm hô “Bạo”, ma hỏa tự nổ phát tiết ma khí và lửa tím, thiêu vỡ quầng sáng trắng, quét nghìn trượng tạo hố lớn khiến mọi tu sĩ tản chạy."},{"chuong":"@c0462","importance":"normal","tieuDe":"Đả thương nguyên thần Hứa Lập Quốc","text":"Vương Lâm vung tiên kiếm và loan đao chém tan màn sương đen Tiên Ma thể của Hứa Lập Quốc, rồi dùng Côn Cực Tiên kéo dài đánh trúng nguyên thần đang thuấn di trốn cách nghìn trượng, khiến nguyên thần run rẩy sắp tan, lưng hiện vết thương sâu, phát tiết lượng lớn tiên lực tinh hoa."},{"chuong":"@c0463","importance":"normal","tieuDe":"Uy hiếp Triệu Tinh Sát giữa Tử Tông","text":"Vương Lâm thu nốt nguyên thần đối phương vào Tôn Hồn Phiên rồi chỉ thẳng Triệu Tinh Sát, tuyên bố ai cản trở sẽ thành kẻ thù. Các chấp pháp trưởng lão Tử Tông do dự không ai dám tiến lên."},{"chuong":"@c0463","importance":"normal","tieuDe":"Đối đầu Cổ Yêu, triệu Hồn Thú","text":"Khi Triệu Tinh Sát triệu hư ảnh cổ yêu trăm trượng, Vương Lâm dùng Tôn Hồn Phiên thu hồi chủ hồn bị lốc xoáy đỏ hút, rồi vỗ Xạ Thần Xa triệu Hồn Thú đâm xuyên thân yêu vật. Ánh mắt lạnh thấu xương của cổ yêu khiến hắn liên tưởng tới hóa thân của cổ thần thiên đạo sứ giả."},{"bridge":true,"khoang":"@c0463–@c0463","text":"Sau khi Xích Liệt quát đuổi cổ yêu kết thúc trận, Vương Lâm điềm tĩnh thu Khu Thú Quyển, ung dung đi tới ngồi vào bàn trống thứ ba dưới chỗ tứ sư tỷ — vị trí thuộc về hắn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Thay chủ yến hội Tử hệ","text":"Sau khi Xích Liệt bắt Triệu Sát Tinh đi, Vương Lâm trở thành tâm điểm yến hội ngày cuối, được các tu sĩ tông phái kéo đến chúc rượu vì nhận định hắn chắc chắn trở thành Thiên Vận Thất Tử."},{"chuong":"@c0464","importance":"normal","tieuDe":"Nhận ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ trao ngọc giản chứa cấm pháp đại na di và một cấm pháp do sư tôn phỏng tiên thuật sáng tạo, coi như xin lỗi việc tháng trước; Vương Lâm nhận, không muốn trở mặt hoàn toàn."},{"chuong":"@c0464","importance":"normal","tieuDe":"Tu thành thuật đại na di","text":"Trong mật thất tầng ba Tử Lâm Các, Vương Lâm thử cấm pháp dịch chuyển mười vạn dặm, bước bảy bước trong hào quang bạc rồi xuất hiện trên đỉnh núi cách đó mười vạn dặm, xác nhận đã tới đúng Thiên Vận Tinh."},{"chuong":"@c0464","importance":"major","tieuDe":"Khai mở tu luyện tiên thuật","text":"Vương Lâm đặt tên Cửu Chuyển Luyện Tiên Quyết cho cấm pháp thứ hai, tu liên tiếp nhất chuyển, nhị chuyển, tam chuyển, ngưng tụ luồng kim tiên lực sắc bén ở tay trái — đánh dấu lần đầu tu thành tiên thuật chân chính nhờ đã có tiên thể bậc trung."},{"chuong":"@c0464","importance":"normal","tieuDe":"Dự lễ giảng đạo Thiên Vận Tử","text":"Trời sáng, Vương Lâm tới dự lễ giảng đạo vạn năm một lần của sư tôn; quét mắt nhận ra ba cao thủ trong sáu tông: Tư Mã Như Phong, nam tử họ Vương của Thanh Tông (nửa bước Vấn Đỉnh) và người trung niên Cam Tông từng đánh Sất Hổ."},{"chuong":"@c0465","importance":"normal","tieuDe":"Dự thọ yến vạn năm Thiên Vận Tử","text":"Với thân phận đệ tử Tử Hệ, Vương Lâm dự đại thọ vạn năm của Thiên Vận Tử, đánh giá thực lực thất hệ và nhận thấy nhiều đệ tử ẩn giấu bản lãnh, trừ ba người Tử Hệ thì các Hệ khác đều có thể hoành hành ở Chu Tước Tinh. Hắn chứng kiến Tôn trưởng lão từ tu chân liên minh giáng lâm bằng kim quang trận pháp khổng lồ."},{"bridge":true,"khoang":"@c0465","text":"Khi Thiên Vận Tử bắt đầu giảng Thiên Vận Chi Đạo, con tiểu điêu ba mắt của Tôn trưởng lão bất ngờ bay tới đậu lên vai Vương Lâm, ba mắt phát tia sáng âm u dò xét hắn; Vương Lâm thấy con chim quen quen liền chăm chú quan sát."},{"chuong":"@c0466","importance":"normal","tieuDe":"Tinh Ngân điêu tìm tới","text":"Một con tử điêu ba mắt đậu trên vai Vương Lâm; qua truyền thừa ký ức cổ thần Đồ Ti hắn nhận ra đó là Tinh Ngân điêu còn nhỏ. Con chim không màng thượng phẩm tinh thạch, chỉ chăm chú nhìn hắn vì bị khí tức cổ thần cực yếu trên người hắn thu hút, song lượng khí tức quá ít khiến hắn thất vọng."},{"chuong":"@c0466","importance":"normal","tieuDe":"Vấn đạo trước sư tôn","text":"Được Thiên Vận Tử gọi đích danh chỉ điểm trước tu sĩ bốn phía và đệ tử lục hệ, Vương Lâm cung kính hỏi cách phân biệt tu tiên, tu chân và tu đạo. Nghe sư tôn giảng ba bước tu đạo, hắn vẫn hoài nghi có thực sự tồn tại bước thứ ba hay không, dẫn tới việc Thiên Vận Tử tiết lộ về ‘hắn’."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Vương Lâm thử dụ tử điêu bằng tiên ngọc; con chim đoạt nuốt liền hai khối với tốc độ khó tưởng tượng rồi đậu sang vai Tôn trưởng lão, mắt vẫn dán vào túi trữ vật của hắn."},{"chuong":"@c0467","importance":"normal","tieuDe":"Gặp lại Lăng Thiên Hầu","text":"Tại lễ đại thọ vạn năm, Vương Lâm lặng nghe trọn ba ngày giảng đạo của Thiên Vận Tử và dần có lĩnh ngộ. Hắn chứng kiến Tiên thuật lần đầu trong đời khi Thiên Vận Tử thi triển trung phẩm Dẫn Tiên thuật, đồng thời nhận ra xà hình bảo kiếm dưới chân Lăng Thiên Hầu chính là Vũ chi đệ nhị kiếm từng thấy ở Tiên giới."},{"bridge":true,"khoang":"@c0467","text":"Khi thiên uy vô thanh của Dẫn Tiên thuật giáng xuống khiến tiên lực trong người hỗn loạn, Vương Lâm vận tam chuyển kim tiên lực từ cánh tay trái lưu chuyển toàn thân, khống chế không để nó hòa lẫn tiên lực vốn có, nhờ đó dần đứng vững lại."},{"chuong":"@c0468","importance":"normal","tieuDe":"Trụ vững khảo nghiệm áp lực Tử hệ","text":"Trong khảo nghiệm áp lực phân loại đệ tử tại đại thọ Thiên Vận Tử, Vương Lâm cùng Tứ sư tỷ là hai người duy nhất của Tử hệ trụ vững; hắn vận kim tiên lực ba vòng khôi phục sắc mặt, được Tứ sư tỷ liếc nhìn đầy thâm ý."},{"chuong":"@c0468","importance":"normal","tieuDe":"Giấu Tôn Hồn Phiên trước Kỳ Lân thú","text":"Khi Lăng Thiên Hầu triệu Kỳ Lân thú từ mi tâm, Tôn Hồn Phiên trong nguyên thần Vương Lâm phát tiếng gầm rít cộng hưởng khiến Kỳ Lân thú dừng lại quét mắt tìm kiếm; hắn lập tức vận Tôn Hồn Phiên che giấu toàn bộ tàn hồn, tránh bị phát hiện."},{"bridge":true,"khoang":"@c0468","text":"Quan sát Dẫn Tiên thuật của Thiên Vận Tử, Vương Lâm lĩnh hội sâu thêm rằng Tiên thuật do hư ảo tạo thành nhưng tồn tại vĩnh hằng, chỉ cần có khẩu quyết, phương pháp và tư cách là thi triển được ở bất kỳ đâu."},{"chuong":"@c0469","importance":"normal","tieuDe":"Tranh phong hiệu, đấu Triệu Hân Mộng","text":"Vương Lâm (Lão Thất) ban đầu định bỏ cuộc tranh phong hiệu Thiên Vận Thất tử vì linh cảm điều bất thường nơi Vận Đường, nhưng bị Thiên Vận Tử đích thân khuyên giải — người thứ hai sau Tôn Vân được sư phụ khuyên — nên đổi ý quyết tranh đoạt. Hắn khai chiến với Tứ sư tỷ Triệu Hân Mộng: nàng dùng Tử Ma thủ mô phỏng từ Hoá Ma chỉ của hắn, Vương Lâm đáp trả bằng Hoá Ma chỉ khiến ma khí ngập trời gào rít bao phủ bốn phía."},{"chuong":"@c0470","importance":"normal","tieuDe":"Phá bẫy hấp thu ma lực","text":"Vương Lâm thi triển Hoá Ma chỉ đối đầu Tử Ma thủ của Triệu Hân Mộng; nàng dùng hạt châu hô ‘Thu’ hút ma lực để cướp đoạt, nhưng Vương Lâm vạch trần đây chỉ là tia hư ảo do tiên lực chuyển hoá, tâm niệm khẽ động liền khiến nó tự sụp. Hắn từ chối nhường, viện lời hứa với Tư Đồ Nam không truyền ba thức sát chiêu ra ngoài."},{"chuong":"@c0470","importance":"normal","tieuDe":"Ngũ chuyển luyện tiên trong vài ngày","text":"Đối đáp Cửu chuyển luyện tiên quyết của Triệu Hân Mộng, Vương Lâm dù mới nhận công pháp vài ngày đã lập tức tu ra tam chuyển, tứ chuyển rồi ngũ chuyển kim tiên lực, chịu đau đớn cực lớn mà thần sắc thong dong, lại rút chiến phủ Cự Ma Tộc và Xạ Thần xa uy hiếp. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi bỏ cuộc."},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Trần Đào","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm hơn mười trượng thay vì trăm trượng như dự tính. Vương Lâm phóng ngũ chuyển kim tiên lực, bị Trần Đào đẩy lên cửu chuyển phản công; hắn dùng chiến phủ chém rồi thi Đại Na Di khiến cơn lốc cửu chuyển biến mất ngay trước mặt, sau đó triệu Hồn thú từ Xạ Thần xa khiến cả trường chấn động."},{"chuong":"@c0471","importance":"normal","tieuDe":"Lần đầu mở phong ấn Xạ Thần xa","text":"Trong trận đấu với Trần Đào tại lễ chúc thọ, Vương Lâm lần đầu kết ấn mở đạo phong ấn thứ nhất của Xạ Thần xa, khiến Hồn thú bạo tăng từ mười trượng lên hơn trăm trượng và đoạt được thiên uy thần thông mới."},{"chuong":"@c0471","importance":"normal","tieuDe":"Thi triển Hoàng tuyền chỉ","text":"Biết mình không phải đối thủ Vấn Đỉnh kỳ nhưng không từ bỏ, Vương Lâm cưỡng dùng sát chiêu cuối Hoàng tuyền chỉ của Tư Đồ Nam: tiêu tan sinh mạng, hiện Sinh tử luân hồi ý cảnh, khiến toàn trường sững sờ và các đại nhân vật như Thiên Vận Tử, Lăng Thiên Hầu chú ý."},{"chuong":"@c0472","importance":"normal","tieuDe":"Bại trận trước Trần Đào","text":"Phóng hai đạo Hoàng tuyền chỉ (một từ ngón út, một từ Luân hồi ý cảnh hóa thành) công kích Trần Đào gây nổ kinh thiên động địa, nhưng Trần Đào nhờ kỳ ngộ đạt Vấn Đỉnh trung kỳ nên đỡ được. Vương Lâm bị đẩy lùi hơn trăm trượng, phun một ngụm tiên huyết, tiên lực hỗn loạn nên tuyên bố bỏ cuộc; Trần Đào do đó đoạt phong hiệu Thiên Vận Thất tử của Tử hệ."},{"chuong":"@c0472","importance":"major","tieuDe":"Thành đệ tử chân chính Thiên Vận Tử","text":"Được Thiên Vận Tử gọi theo về Tổng tông tế bái Tổ linh, hứa truyền Cấm pháp thần thông và ban pháp bảo bản mạng, chính thức trở thành đệ tử chân chính. Giải đúng câu đố ba ngọn núi (nhìn ra hai sườn núi hai bên là giả do Chân huyễn pháp) nên được đặc ân tự chọn Cấm pháp thần thông thay vì bị chỉ định."},{"chuong":"@c0472","importance":"normal","tieuDe":"Vượt kỷ lục Toái Tiên chi địa","text":"Leo ngọn núi trắng phủ Cửu U chi hàn không dùng thuấn di, đạp băng đối mặt khảo nghiệm Toái Tiên chi địa. Đi được hai mươi mốt bước (vượt xa cực hạn Anh Biến trung kỳ mà Thiên Vận Tử dự đoán), rồi bước thứ hai mươi hai và thêm năm bước nữa, tiến gần kỷ lục hai mươi sáu bước của Tôn Vân."},{"chuong":"@c0473","importance":"major","tieuDe":"Bái sư nhập Thiên Vận Tông","text":"Vương Lâm chính thức quỳ bái Thiên Vận Tử, được thu làm đệ tử thứ bảy của Tử hệ dưới ánh sáng chín màu. Hắn thề chỉ cần sư phụ và Thiên Vận Tông không phụ hắn thì hắn sẽ không phụ lại; một tòa Tế đàn bảy màu hạ xuống, lệnh bài khắc danh tự cháy hóa lửa tím bay về tế đàn. Sau đó được Thiên Vận Tử hỏi muốn chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Chọn Cấm pháp thần thông phòng thân","text":"Vương Lâm điểm lại sở học (Cấm pháp Đại Na Di, Ngân Long la bàn) và nhận ra chúng chỉ hữu dụng với tu sĩ Vấn Đỉnh, không đủ đối phó kẻ vượt Vấn Đỉnh hay đạt cảnh giới Toái Niết. Hắn xin Thiên Vận Tử truyền ‘Sinh tồn pháp thuật’ nhưng bị từ chối, nên được sư phụ điểm ánh sáng bảy màu đưa vào thế giới bảy màu để tự chọn theo cơ duyên."},{"chuong":"@c0474","importance":"normal","tieuDe":"Từ chối Sát Lục Tiên quyết","text":"Trong thế giới bảy màu, Vương Lâm phát hiện một Thiên Vận Tử áo xám dị thường (người ‘hơn một người’ — thứ 3601), mọi công kích đều xuyên qua như ảo ảnh. Qua sáu lần chạm mặt, người áo xám tiết lộ Thiên Vận Tử đưa hắn tới chính vì Sát Lục Tiên quyết, ra điều kiện ‘xuất thủ không lưu người sống’. Vương Lâm thi triển Sinh tử Luân hồi ý cảnh rồi trầm mặc từ chối: ‘Ta không học!’, sau đó nhận lấy ngọc giản người áo xám để lại."},{"chuong":"@c0476","importance":"normal","tieuDe":"Rời Thiên Vận Tinh tới Địa Tinh","text":"Vương Lâm dùng Truyền tống trận khổng lồ của Huyền Uyên Phái do Triệu Tứ kích hoạt, vượt liên tinh cầu rời Thiên Vận Tinh để tới Địa Tinh, mang theo lệnh bài khắc chữ “Thất” biểu thị thân phận Tử hệ Lão Thất."},{"chuong":"@c0476","importance":"normal","tieuDe":"Nhậm chức sứ giả Linh Nhạc quốc","text":"Tới Huyền Uyên Phái được Thiếu Tông Hứa Vân Sơn nghênh đón và kết giao; sau hai ngày, hắn được đưa tới Ngũ cấp tu chân quốc Linh Nhạc quốc để nhận chức sứ giả, ngầm tìm chỗ tĩnh tu tránh cạnh tranh ở Thiên Vận Tông."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Trong hoa viên, Vương Lâm ngẫm về việc đề cao tu vi để đối phó mối uy hiếp Thác Lâm, nghiền ngẫm Sát lục tiên quyết, Sinh chi lạc ấn hộ thể và việc Thiên nghịch châu còn thiếu kim thuộc tính, nhớ tới Chu Tước Tinh xa xôi."},{"chuong":"@c0477","importance":"normal","tieuDe":"Nhậm Sứ giả Huyền Uyên Phái","text":"Vương Lâm chính thức nhậm chức Sứ giả của Huyền Uyên Phái tại Linh Nhạc quốc, được hơn trăm tu sĩ cung kính đón tiếp. Hứa Vân Sơn cáo từ rời đi, để mình hắn ở lại tọa trấn Thông Thiên tháp."},{"bridge":true,"khoang":"@c0477","text":"Hắn tuyên bố bế quan, cấm mọi người bước vào phạm vi ngàn dặm, dùng Cấm Phiên phóng hắc khí tạo màn sương đen và thả Chủ hồn từ Tôn Hồn Phiên ra phòng bị, rồi nghiên cứu Sát Lục Tiên quyết suốt hơn một tháng nhưng không tìm được điểm khởi đầu."},{"chuong":"@c0477","importance":"normal","tieuDe":"Áp chế Xạ Thần xa cắn trả","text":"Xạ Thần xa lần đầu cắn trả kể từ khi giải khai đạo phong ấn đầu tiên. Vương Lâm đã chuẩn bị trước, đại chiến với Khuất thú bên trong mấy ngày, dùng bí pháp áp chế khiến lần cắn trả thất bại."},{"chuong":"@c0477","importance":"normal","tieuDe":"Thu cấm chế, quyết đi Đông Hải","text":"Vương Lâm ngộ ra Sát Lục Tiên quyết phải cảm ngộ từ giết chóc thật, bèn thu hết màn sương đen ngàn dặm ngưng tụ thành khối cầu điện quang đen hóa Cấm Phiên tím đen, thu Chủ hồn vào Tôn Hồn Phiên tế luyện. Nhớ lời sư phụ dặn đến Đông Hải trong ba tháng (còn hơn một tháng), hắn lên đường, trước hết tới Ngũ Linh Sơn gặp Thiên Thai lão nhân."},{"chuong":"@c0478","importance":"normal","tieuDe":"Chọn Địa Ma Bắc Giới tu Sát Lục Tiên quyết","text":"Vương Lâm hỏi Thiên Thai lão nhân về nơi yêu thú tụ tập, nhận ngọc giản ghi ba chỗ rồi thuấn di tới Cực Bắc Địa Tinh, bước thẳng qua tấm bia Địa Ma Bắc Giới vào làn sương mù để tu luyện Sát Lục Tiên quyết — công pháp phải ở trong giết chóc mới lĩnh ngộ huyền diệu."},{"bridge":true,"khoang":"@c0478","text":"Hắn để tâm tới Đại La Kiếm Tông nhằm tìm tung tích Chu Dật tiền bối, đồng thời tò mò về Diệu Kim quả mà nhóm kiếm tu tranh chấp."},{"chuong":"@c0479","importance":"normal","tieuDe":"Nuôi Văn thú bằng yêu thú Hóa Thần","text":"Phi hành trong Tùng Mãng Sơn mạch tu luyện Sát Lục Tiên quyết, Vương Lâm giết tiểu thú sương đen và Bôn Ngưu thú (tương đương Hóa Thần kỳ), thu bụi khí nghi là sinh lực và thả Văn thú hấp thu nội đan, huyết nhục con mồi để thúc nó lớn lên."},{"chuong":"@c0479","importance":"normal","tieuDe":"Lần theo Đại La Kiếm Tông tìm Diệu Kim quả","text":"Vương Lâm dùng thần thức theo dõi đoàn Đại La Kiếm Tông, dự định dùng hai lão Anh Biến sơ kỳ làm thí luyện giả cho Sát Lục Tiên quyết, rồi cưỡi Văn thú bay nhanh về phía Nam nơi có Diệu Kim quả."},{"chuong":"@c0480","importance":"normal","tieuDe":"Bám theo đoàn Đại La Kiếm Tông","text":"Ngồi trên Văn thú vô thanh vô tức, Vương Lâm âm thầm đi theo đoàn Đại La Kiếm Tông tiến vào Địa Ma Bắc Giới tìm Diệu Kim quả. Dựa vào ký ức Cổ Thần Đồ Ti, hắn nhận ra Diệu Kim quả thực chất là kim linh căn mà các tu sĩ kiếm tông không biết cách dùng đúng — nuốt vào khiến thân thể cứng rắn, là thuốc bổ hi���m có với Cổ Thần thuở nhỏ. Hắn nhắm đoạt vật này cho Văn thú đang loé bạch mang khát vọng, vỗ đầu nó gật đầu cho phép."},{"chuong":"@c0483","importance":"normal","tieuDe":"Giết Thạch Phương đoạt xá","text":"Tại sơn cốc, Vương Lâm phá Huyết Thủ ấn, diệt Thiên Quỷ đầu rồi dùng kính tản tia sáng phát Tứ chuyển hàm tiên lực vỗ tan kiếm quang của Thạch Phương. Tiên ảnh đánh trọng thương nguyên thần ly thể, Văn thú nuốt sạch thân xác chỉ còn hài cốt; dù Thạch Phương đoạt xá Quách Tà Dật siêu tốc rồi cầu xin hiến ngọc giản, Vương Lâm vẫn phóng khí xám khiến hắn nổ tung."},{"chuong":"@c0483","importance":"minor","tieuDe":"Hái Diệu Kim quả","text":"Vương Lâm tới mảng hoa vàng phía Tây sơn cốc hái một Diệu Kim quả, định dùng tăng kim thuộc tính cho Nghịch Thiên châu (sau trận Chu Tước mộ vẫn thiếu gần một nửa), nếu không thì cho Văn thú ăn; chưa l��p tức tra hỏi Trưởng lão Đại La Kiếm Tông đang bị giam."},{"chuong":"@c0484","importance":"normal","tieuDe":"Luyện thành bốn kim linh căn","text":"Hiểu ra Diệu Kim quả không trực tiếp làm viên mãn kim thuộc tính của Nghịch Thiên châu, Vương Lâm dùng phương pháp điều hoà thừa kế trong ký ức Đồ Ti: bố trí ngọc giản khắc văn, kết thủ ấn cổ quái và thốt Chú ngôn ép hoa, quả, cành cây héo rũ. Quá trình khoảng nửa nén hương, hắn bới đất thu được bốn kim linh căn cỡ ngón tay cái, kỳ dị giống nhân sâm."},{"chuong":"@c0484","importance":"normal","tieuDe":"Phân chia kim linh căn","text":"Hắn ném một kim linh căn cho Văn thú khiến nó bắt đầu biến hoá, kim quang bọc thành lồng vàng; một rễ cho Lôi Oa; một rễ cuối tặng Thiên Cầm coi như đền cơ duyên đã chiếm. Thân cây hắn thu lại lưu cho bổn tôn."},{"bridge":true,"khoang":"@c0484","text":"Hoá khói rời sơn cốc, nhoáng qua dãy núi phóng vào chỗ sâu Địa Ma Bắc giới."},{"chuong":"@c0485","importance":"normal","tieuDe":"Tra Hỏi Bí Mật Đông Hải","text":"Vương Lâm khống chế lão già thấp người của Đại La Kiếm Tông bằng phi kiếm cực cứng và thanh loan đao quỷ dị, ép lão khai bí mật về Kiếm Tôn từ tiên giới trở về cùng Đông Hải Yêu Linh chi môn — ba đại cấm địa, huyết tinh thí luyện, phần thưởng Yêu Linh quán đính. Khai xong, hắn để loan đao xuyên đầu giết lão rồi rời đi; khi lão dùng Tam phân thần thức thuật tái sinh, khí xám truy sát của hắn quay lại hút sạch sức sống lão."},{"chuong":"@c0485","importance":"normal","tieuDe":"Sát Lục Tiên Quyết Ba Phân","text":"Ẩn trong Địa Ma Bắc giới hai mươi ngày tu Sát lục tiên quyết, Vương Lâm chuyển hoá sinh lực thành Sinh ấn, lần này ngưng kết được ba phân — ba phù văn xám bao phủ toàn thân khiến thân thể cứng hoá, kiếm chỉ miết qua không xuyên thấu. Còn sáu ngày là hết hạn ba tháng, hắn ra khỏi Địa Ma Bắc giới, ánh mắt quyết đoán hướng về Đông Hải, định đi cứu Chu Dật và tìm kim thuộc tính giúp Nghịch Thiên châu viên mãn để Lý Mộ Uyển thức tỉnh."},{"bridge":true,"khoang":"@c0487","text":"Được Thiên Vận Tử cử đi Đông Hải Yêu Linh, hóa đạo cầu vồng tử quang tới hội hợp với Tôn Vân Sơn rồi cùng vào trận pháp tinh không của Huyền Uyên phái để di chuyển tới cửa Đông Hải."},{"chuong":"@c0488","importance":"normal","tieuDe":"Bái kiến sư tôn trước cửa Đông Hải","text":"Vương Lâm hóa thân ảnh tử sắc phóng tới cửa Đông Hải Yêu Linh, tách khỏi Tôn Vân Sơn rồi cung kính tham kiến sư tôn Thiên Vận Tử. Hắn được tu sĩ nhận ra qua áo tử sắc và tử sắc lệnh bài là Tử Hệ Lão Thất Thiên Vận Tông, đứng vào hàng cùng chín đồng môn, được Thiên Vận Tử nhìn đầy thâm ý và nhắc có thể lấy được bảo vật."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Sự xuất hiện của hắn thu hút chú ý của Lăng Thiên Hậu, Tham Lang, Diêu Tích Tuyết cùng nhiều lão quái; thủy triều Đông Hải năm nghìn năm một lần bắt đầu khởi động."},{"chuong":"@c0489","importance":"normal","tieuDe":"Chứng kiến thủy triều Đông Hải Yêu Linh","text":"Lần đầu đặt chân tới cửa Đông Hải Yêu Linh, Vương Lâm chứng kiến hiện tượng thủy triều năm nghìn năm một lần: vật trôi nổi xoay tròn ngưng tụ thành cột thanh khí cao ngàn trượng rồi nổ tan phát hồng quang. Đạo tâm hắn kiên định, không bị thần thông xoay tròn lôi cuốn. Khi cổ uy áp nồng hơn thiên uy gấp bội đè xuống như Thập Vạn Đại Sơn khiến thân thể rắc rắc sắp vỡ, hắn dùng đạo khí xám lóe trên mi tâm hóa thành ký hiệu bao trùm toàn thân, gắng chống đỡ tới cực hạn."},{"chuong":"@c0490","importance":"normal","tieuDe":"Phá hồng quang nhìn thấy lệnh bài","text":"Khi cửa Đông Hải Yêu Linh bên ngoài Thiên Vận Tinh mở ra, hồng quang nghìn năm điên cuồng rút về như thủy triều, cuốn theo vô số pháp bảo, linh thạch, yêu thú vô chủ. Nhờ ký ức Cổ Thần Đồ Ti, Vương Lâm nhận ra nhiều vật luyện khí quý cùng một thanh đại kiếm rỉ sét hình cánh cửa trong hồng quang. Trước con sóng cuối ngăn cản thần thức, hắn vận ba đạo ấn ký khí xám trên mi tâm thành thần thông ánh mắt, chịu đau đớn chảy máu mắt để xuyên thủng tầng tầng hồng quang, nhìn rõ một khối lệnh bài kim quang khắc ký hiệu khiến mọi cao thủ đại biến sắc."},{"chuong":"@c0491","importance":"normal","tieuDe":"Tiến nhập thế giới Đông Hải yêu linh","text":"Cố ý chậm chân vào cánh cửa Đông Hải yêu linh sau cùng, bị một lực kỳ dị đẩy tản khỏi chín đồng môn, một mình rơi xuống hoang nguyên giữa thế giới hỗn độn tự hình thành bên trong."},{"chuong":"@c0491","importance":"normal","tieuDe":"Lập kế hoạch năm trăm năm","text":"Định ở lại năm trăm năm để tu Sát lục tiên quyết tới đại thành (ngưng kết lạc ấn sinh mệnh chống Thác Sâm), tìm cứu Chu Dật nơi phong ấn của Lăng Thiên Hậu, và truy tìm thanh đại kiếm Cự Phú để học kiếm kỹ kiếm hồn, tất cả nhằm đề phòng Thác Sâm thoát khốn truy sát."},{"chuong":"@c0492","importance":"normal","tieuDe":"Phát hiện sơn cốc trận pháp thượng cổ","text":"Sau khi bay mười ngày qua bình nguyên hoang vu, Vương Lâm phát hiện vùng núi non trùng điệp, chứng kiến một người nửa xích lõa không có linh lực nhưng linh tính kinh người săn giết dã thú. Theo người này tới một sơn cốc, hắn nhận ra bên ngoài cốc có trận pháp ẩn giấu khí tức sinh mạng do tu sĩ thượng cổ bố trí, thủ pháp khác hẳn liên minh tu chân, trong thời gian ngắn không thể phá giải."},{"bridge":true,"khoang":"@c0492","text":"Hắn trầm tư về khối lệnh bài bí ẩn từng khiến Thiên Vận Tử và Lăng Thiên Hậu biến sắc, định mượn năm trăm năm ẩn náu ở tinh cầu để tăng nhanh tu vi và tránh Thác Sâm. Khi thử trận pháp thì bị luồng khí xanh thôn phệ linh quang phản kích; cuối cùng hắn làm tan trường côn, dùng lực vô hình giam bốn người trong cốc để tra hỏi, rồi hai người nữa từ trong cốc đi ra."},{"chuong":"@c0493","importance":"normal","tieuDe":"Phá trận sơn cốc bộ tộc xích lõa","text":"Vương Lâm quan sát thượng cổ trận pháp ngoài sơn cốc bộ tộc thân trâu mình người, bắt giữ rồi thả tộc nhân, đối thoại với trưởng lão Âu Dương Hoa và được chỉ điểm về Cổ yêu thành. Sau đó hắn nhận ra Âu Dương Hoa trước mặt chỉ là thế thân hư ảo, dùng Cấm Phiên phóng chín trăm chín mươi chín đạo cấm khí công phá trận, rồi triển khai Cấm pháp chi mâu nghênh chiến thanh ảnh xanh do trận tạo."},{"chuong":"@c0494","importance":"normal","tieuDe":"Phá trận thượng cổ sơn cốc","text":"Bị vây trong trận pháp thượng cổ của Âu Dương Hoa, Vương Lâm dùng trường mâu cấm khí câu giờ, vận thượng cổ cấm chế của cổ thần để tính toán rồi phóng ra tám mươi ba tổ hợp cấm chế đánh tan lồng thanh quang thôn phệ vạn vật, áp sát sơn cốc khiến Âu Dương Hoa hoảng sợ cầu tha."},{"chuong":"@c0495","importance":"normal","tieuDe":"Bức tranh Hoàng Long chấn động","text":"Vào sơn cốc tộc Âu Dương Hoa, khôi phục trận pháp cổ bảo vệ tộc nhân rồi tặng ba bình ngọc đan dược cố bổn bồi nguyên làm lời tạ lỗi. Tại nhà Âu Dương Hoa, hắn thấy bức tranh ố vàng vẽ Hoàng Long thượng tiên; nguyên thần chấn động, hồi tưởng quê nhà Chu Tước tinh và thời thiếu niên từ sơn thôn ra ngoài gia nhập Hằng Nhạc phái."},{"chuong":"@c0496","importance":"normal","tieuDe":"Hấp thu yêu lực ngọc yêu linh","text":"Tại sơn cốc bộ tộc Âu Dương Hoa, Vương Lâm dùng hơn mười bình ngọc đan dược đổi lấy ngọc yêu linh (kết tinh tiên lực) khảm trong vách đá xanh thẫm. Hắn chụp lấy tinh thạch trắng, hấp thu khí tức cực lạnh yêu dị: khí tức chạy theo các khớp xương chứ không qua kinh mạch, tụ tại đan điền hóa thành tinh thể cỡ hạt gạo xoay như tinh vân, toàn thân biến hóa rõ ràng."},{"bridge":true,"khoang":"@c0496–@c0496","text":"Trầm ngâm về bức tranh người giống Hoàng Long chân nhân của Hằng Nhạc phái, nghe Âu Dương Hoa giải thích về Thiên Yêu quận, đêm yêu linh và quy luật người bên ngoài; khi đi qua khu cư dân, xoa đầu một hài đồng và nhớ tới Đại Ngưu lúc nhỏ."},{"chuong":"@c0497","importance":"normal","tieuDe":"Đổi yêu lực kết tinh ở Hồ Lô Cốc","text":"Tại thung lũng Hồ Lô Cốc trên Thiên Vận Tinh, Vương Lâm hấp thu yêu lực hống khiến yêu khí trong người biến hóa thành đoàn yêu hỏa; hắn nhận định yêu lực kết tinh giống tiên lực nhưng quỷ dị, có thể dung hợp đẩy tu vi. Hắn phất tay áo cho Âu Dương Hoa hơn mười bình ngọc để đổi lấy yêu lực kết tinh duy nhất của thung lũng, rồi ngồi thiền nghiên cứu trong đan điền."},{"bridge":true,"khoang":"@c0497","text":"Vương Lâm tách một tia nguyên thần hóa thần thức phóng đi xa, thấy yêu linh Đông Hải tạo đạo khí tím khuếch tán hình tròn hủy diệt sinh khí, rồi phát hiện Hắc y nam tử đang hấp thu yêu lực và tuyên bố coi hắn là con mồi; hắn nhận ra đối thủ là tu sĩ Ứng Biến hậu kỳ đại viên mãn."},{"chuong":"@c0497","importance":"normal","tieuDe":"Hiện thân cứu Hồ Lô Cốc","text":"Khi trận pháp thung lũng bị sóng yêu khí công phá sắp vỡ và Hắc y nam tử hóa điện quang phi kiếm lao tới, Vương Lâm bước một bước hóa khói nhẹ xuất hiện ở cửa cốc bên cạnh Âu Dương Hoa; lúc này hắn vẫn để đối thủ lầm tưởng mình chỉ Ứng Biến trung kỳ."},{"chuong":"@c0498","importance":"normal","tieuDe":"Giao chiến La mỗ ngoài thung lũng yêu linh","text":"Tại Thiên Yêu quận, Vương Lâm gia cố trận pháp thung lũng giam yêu linh bằng Cấm Phiên rồi bước ra ngoài đối đầu hắc y nam tử La mỗ. Hắn diệt một đầu yêu linh thú, xuất kiếm tiên cùng loan đao làm rạn phi kiếm địch và đả thương ngực y. Khi La mỗ tung Kiếm toái cùng Địa diệt chi hỏa hóa sáu rồng lửa, Vương Lâm thi triển Sinh Chi Lạc Ấn chống đỡ, gây vụ nổ long trời rồi bước ra từ bóng tối suýt điểm trúng đối phương."},{"bridge":true,"khoang":"@c0499","text":"Giao chiến với Hắc y nam tử (La mỗ) trong vùng Yêu linh khí lãng: bị phối hợp kiếm vỡ hàn quang và hắc hỏa phá mất một tầng Sinh chi lạc ấn, đáp trả bằng Côn Cực Tiên đả thương nguyên thần đối phương; khi đối thủ phun độc khí rút lui, hắn niệm thần chú Phong gọi gió phá độc thoát ra rồi truy kích, quyết không tha."},{"chuong":"@c0500","importance":"normal","tieuDe":"Mở Xạ Thần Xa ép lui Hắc y nam tử","text":"Trong trận sinh tử với Hắc y nam tử (Anh Biến hậu kỳ đại viên mãn), Vương Lâm dùng chủ hồn — gồm tàn hồn kỳ lân — làm mồi nhử Quỷ ảnh, thừa cơ ném Khu Thú Quyển. Hắn thi triển Hóa ma chỉ và Sinh chi lạc ấn xuyên qua khói độc, rồi mở Xạ Thần Xa, dùng Cửu Tự Chân Ngôn khống chế Hồn thú nhằm thẳng đối thủ, buộc Hắc y nam tử bỏ thân xác cho nguyên thần chạy trốn."},{"chuong":"@c0501","importance":"normal","tieuDe":"Bắt sống nguyên thần La Vân","text":"Sau khi hồn thú thiêu hủy thân thể Hắc y nam tử, Vương Lâm lần đầu phối hợp ăn ý với hồn thú qua Xạ Thần Xa, dùng Côn Cực Tiên quấn bắt nguyên thần đối phương (Anh Biến hậu kỳ đại viên mãn) trước khi hắn kịp tự nổ, giam vào hồn phiên. Khi hồn thú phẫn nộ vì bị cướp mồi, Xạ Thần Xa hóa Khu Thú Quyển hút mạnh tiên lực, Vương Lâm phải dùng tiên ngọc chống đỡ."},{"chuong":"@c0501","importance":"normal","tieuDe":"Thi triển Sưu Hồn Thuật đoạt ký ức","text":"Vương Lâm lập cấm chế ngăn La Vân tự bạo, ép hắn lộ thân phận người Thiên Quỷ Đạo, rồi niệm Sưu Hồn rút kết tinh trong đan điền cùng toàn bộ ký ức của La Vân. Hắn dự định luyện nguyên thần đã suy yếu của La Vân thành một chủ hồn trong Tôn hồn phiên, và thấy trong ký ức có vài thuật ma cấm Thiên Quỷ Đạo đáng tu luyện."},{"chuong":"@c0502","importance":"normal","tieuDe":"Thấu hiểu cơ chế vùng đất yêu linh","text":"Qua ký ức La Vân, Vương Lâm nắm rõ vùng đất yêu linh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh; dung hợp được thì tu vi tăng vọt và có cơ hội vào cảnh thần chi thủy. Hắn định kế hoạch nhập Thiên Yêu quận để đạt chiến công, và phát hiện yêu tinh La Vân cộng yêu lực đã hấp thu vừa đủ ba giáp — hiểu vì sao La Vân muốn giết mình."},{"bridge":true,"khoang":"@c0502","text":"Hắn liên tưởng thần chi thủy với Thủy cảnh, nhớ lại tài liệu Cực Cảnh - Đạo cảnh - Thủy cảnh từng chiếm ở động tiên ngầm trong Tu Ma Hải, mơ tưởng kết hợp Cực cảnh và Thủy cảnh thành đại đạo luân hồi rồi tự kiềm chế."},{"bridge":true,"khoang":"@c0502","text":"Dịch chuyển tới bình nguyên có khe rãnh, hắn há mồm hút các chủ hồn âm hồn (gồm một đầu lân) dung nhập Tôn Hồn Phiên, rồi dùng thuật đám bụi khí hóa hàn quang truy diệt Thiên quỷ phản chủ của La Vân đang suy yếu trốn trong khe, phủ đầy tro bụi lên thân nó."},{"chuong":"@c0503","importance":"normal","tieuDe":"Thu Phục Thiên Quỷ","text":"Vương Lâm dụ Thiên quỷ ra khỏi khe rãnh, dùng Côn Cực Tiên chuyên đánh nguyên thần quất cho suy yếu. Theo trí nhớ La Vân, hắn biết Thiên quỷ sau phản bội cần bốn chín ngày tu dưỡng nên quyết bắt sống lúc nó yếu nhất. Khi Thiên quỷ phun Bản mạng chi hỏa định hủy roi, Côn Cực Tiên lóe một đạo kim quang chụp tắt lửa khiến Thiên quỷ suýt tiêu tan; hắn vội thu roi, dùng hồn phiên cuộn Thiên quỷ vào giữ lại."},{"bridge":true,"khoang":"@c0503","text":"Ba ngày sau hắn về sơn cốc tộc Âu Dương Hoa qua trận pháp đã dung hợp cấm phiên, vào cấm địa tọa định. Hắn tính ở lại giáo hóa cư dân, truyền thuật hồn phiên để gây dựng lực lượng riêng trước khi tới thành Cổ Yêu, nhắm khôi phục Tôn hồn phiên và đoạt Cổ yêu chi linh. Hắn lưu khẩu quyết Luyện Hồn, Trừu Phách cùng cách chế tác hồn phiên vào hai ngọc giản, cố ý cài một sơ hở trí mạng chỉ mình biết để có thể trực tiếp khống chế hồn phiên của đệ tử."},{"chuong":"@c0504","importance":"normal","tieuDe":"Truyền Luyện Hồn thuật cho cốc yêu linh","text":"Vương Lâm chế tác yêu giản chứa khẩu quyết luyện hồn, cưỡng ép song chỉ đả thông một kinh mạch giúp trưởng lão Âu Dương Hoa đột phá nhị tinh, rồi tuyên bố truyền thụ thuật luyện hồn cho toàn bộ cư dân sơn cốc — thứ cực hiếm nơi vùng đất yêu linh."},{"bridge":true,"khoang":"@c0504","text":"Suốt ba tháng hắn nghiên cứu yêu tinh, dung hợp hai khối thành ‘Ba giáp yêu tinh’ ẩn yêu lực vô biên; nuốt thử khiến thân hóa yêu dị (đồng tử dựng đứng) nhưng vận chuyển toàn bộ chỉ đạt Trúc Cơ kỳ vì lượng yêu lực chưa đủ, sau đó rút yêu lực về và trở lại trạng thái siêu phàm."},{"chuong":"@c0505","importance":"normal","tieuDe":"Cài sơ hở khống chế hồn thú","text":"Tại sơn cốc ở Thiên Vận Tinh, Vương Lâm chế hồn phiên thay thế từ cươn thụ chi mộc, da dã thú và thủ ấn để bù tài liệu thiếu khuyết, rồi cải biến Luyện Hồn Thuật cài backdoor khiến mọi hồn thú do người học thuật phong ấn đều bị hắn hoàn toàn điều khiển và chấn nhiếp."},{"chuong":"@c0505","importance":"normal","tieuDe":"Chấn nhiếp sư tử cánh dài phản phệ","text":"Khi hồn phách sư tử cánh dài quay đầu phản phệ Thập Tam, Vương Lâm chỉ một tiếng hừ “Nghiệt súc, ngươi dám!” đã khiến nó tan nát rồi nằm bẹp thuần phục; hắn lướt mấy trăm trượng hiện thân, khiến cả sơn cốc kinh hãi sùng kính."},{"bridge":true,"khoang":"@c0505–@c0505","text":"Vương Lâm coi trọng ngộ tính của Thập Tam, trao ngọc giản phương pháp chế hồn phiên mới, mặc Âu Dương Hoa định kế tấn công bộ tộc cách ngàn dặm v��i một câu “Tùy ngươi!”."},{"chuong":"@c0506","importance":"normal","tieuDe":"Lập kế Tán Hồn Dưỡng Phách","text":"Đóng vai ‘thượng tiên’ ẩn ở sơn cốc, Vương Lâm thao túng bộ lạc tu Luyện Hồn Thuật để gom hồn phách và yêu tinh. Hắn để tộc nhân phong ấn hồn phách vào Hồn Phiên, chỉ cần khởi ý là thu về — kế sách ‘tán hồn dưỡng phách’ nhằm hồi phục thập ức tôn Hồn Phiên."},{"bridge":true,"khoang":"@c0506–@c0506","text":"Thu phục con sư tử yêu thú làm chủ hồn cho Hồn Phiên của Thập Tam, cảnh cáo về rủi ro chủ hồn cắn trả; ban khẩu quyết Luyện Hồn Thuật theo công lao; nuốt nhị giáp yêu tinh Âu Dương Hoa dâng, dung hợp thành ngũ giáp yêu tinh trong đan điền."}],"tuViMoc":[{"chuong":"@c0459","canhGioi":"Anh Biến kỳ","text":"Đặt mục tiêu tu luyện đột phá tới Anh Biến trung kỳ để có đủ lực phá vỡ trận pháp khốn địa; chuyên tâm hấp thu tiên ngọc, tiên lực trong cơ thể đạt bão hòa dung nhập thân thể làm lực lượng dự phòng.","importance":"minor"},{"chuong":"@c0461","canhGioi":"Anh Biến trung kỳ","text":"Nhờ lượng lớn tiên ngọc trợ giúp đột phá khi còn bị vây trong thạch lâm, Vương Lâm tiến lên Anh Biến trung kỳ, uy lực Hóa Ma Chỉ nhờ đó tăng mấy lần.","importance":"minor"},{"chuong":"@c0462","canhGioi":"Anh Biến Trung Kỳ","text":"Khi tái xuất phá vây, Vương Lâm đã đột phá lên Anh Biến Trung Kỳ, khiến Triệu Tinh Sát kinh hãi vì hắn vừa thoát vây vừa tăng cảnh giới.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Anh Biến trung kỳ","text":"Lĩnh ngộ Vấn Tâm chỉ cảnh tại Toái Tiên chi địa: khi tâm lạnh lẽo hơn cả vạn vật băng hàn, ý chí bất khuất vờn quanh thân, thần thức từ nguyên thần quét lui hàn khí xâm nhập kinh mạch. Đồng thời lĩnh ngộ Luân hồi đạo chính là đại Vô tình đạo, sau lưng hiện ra Luân hồi Hoạ trục chỉ hai màu đen trắng. Thuộc hệ tu tâm — không phải tu vi chính.","importance":"major"},{"chuong":"@c0473","canhGioi":"Anh Biến kỳ","importance":"major","text":"Ý cảnh nhập thể: trên nền hai mươi bước, Vương Lâm dung một tia cảm ngộ vào tâm cảnh, bước thêm năm bước đạt cực hạn hai mươi bảy bước, mở ra con đường lên Vấn Đỉnh. Sinh Tử Luân Hồi đạo của hắn là loại lĩnh ngộ cực hiếm khó thực chất hóa nhất; nhờ kết hợp Vấn Tâm chi đạo tại Toái Tiên chi địa mới khai thông. Bước thứ hai mươi tám nếu bước ra sẽ khiến tu vi sụp đổ, nguyên thần tiêu tan."},{"chuong":"@c0483","canhGioi":"Anh Biến","text":"Tu vi xác nhận đã đạt Anh Biến trung kỳ; nhờ vậy không còn ngại đối kháng trực tiếp nguyên thần ly thể dung trong bản mạng pháp khí như thuở chưa có Côn Cực tiên.","importance":"minor"},{"chuong":"@c0498","canhGioi":"Anh Biến trung kỳ","text":"Được La mỗ xác nhận tu vi mới Anh Biến trung kỳ; dù vậy hắn từng đấu mười một trận với tu sĩ Vấn Đỉnh, lực công hùng mạnh khiến nhiều thế lực chú ý.","importance":"minor"},{"chuong":"@c0500","canhGioi":"Anh Biến trung kỳ","text":"Đang ở Anh Biến trung kỳ, kém đối thủ Anh Biến hậu kỳ đại viên mãn một bậc, nhưng nhờ Thiên Quỷ hấp thu tiên lực của địch và thủ đoạn áp chế mà giành thế thượng phong.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Trương Hướng Phàm","tag":"dong-minh","quanHe":"Đệ tử mở khóa trận pháp Phẩm Linh Các, cung kính dẫn Vương Lâm vào lấy tiên ngọc","ghiChu":"@c0458"},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ hai Lam tông, tham gia vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng được người nhờ vả nên ra tay vây kích","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"doi-thu","quanHe":"Sư huynh ẩn mình nửa bước vấn đỉnh, coi Vương Lâm không xứng ra tay","ghiChu":"@c0458"},{"ten":"Thủy tổ đại nhân (Thiên Vận Tông)","tag":"su-mon","quanHe":"Thủy tổ tông môn, từng dặn chỉ cần không phạm môn quy thì khỏi quản Vương Lâm","ghiChu":"@c0458"},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"su-mon","quanHe":"Sư tỷ đồng môn","ghiChu":"Trực tiếp na di Vương Lâm tới khốn địa, hẹn ba năm thả ra; từng hứa truyền thần thông na di cho hắn sau khi mọi chuyện giải quyết."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn","ghiChu":"Người bố trí trận pháp thạch lâm vây khốn Vương Lâm."},{"ten":"Tào Nhất Đấu","tag":"dong-minh","quanHe":"Nguyên thần bị Vương Lâm thu nhận làm người dẫn đường","ghiChu":"Vương Lâm hứa cho một thân thể anh biến để đổi lấy việc dẫn đường về Thiên Vận Tông."},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đại sư huynh Tử hệ nhất mạch đứng sau việc na di vây khốn Vương Lâm","ghiChu":"Vương Lâm trở về quyết báo thù sự chèn ép của Triệu Tinh Sát và Tử hệ nhất mạch."},{"ten":"Hứa Lập Quốc","tag":"doi-thu","quanHe":"Kẻ thù bị Vương Lâm truy sát giữa thọ yến, đánh trọng thương nguyên thần","ghiChu":"Nhị sư huynh Tử hệ Thiên Vận Tông"},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Cản Vương Lâm bằng Đại tự tại thiên địa quyết nhưng bị ma hỏa tự bạo phá vỡ","ghiChu":""},{"ten":"Bạch Vi","tag":"khac","quanHe":"Đệ tử Tử hệ, mỉm cười kỳ dị khi thấy Vương Lâm trở lại nhưng không ra tay","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"doi-thu","quanHe":"Đối thủ tranh danh hiệu Thiên Vận Thất Tử","ghiChu":"Bị Vương Lâm uy hiếp, đáp trả bằng thuật triệu Cổ Yêu nhưng bị phản phệ."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc trong Thiên Vận Tông","ghiChu":"Xuất hiện quát đuổi cổ yêu, vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối Thiên Vận Tông cùng tông, sư đệ của sư tôn","ghiChu":"Tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không tranh danh hiệu Thiên Vận Thất Tử."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Đệ tử hàng thứ ba Lam Tông cùng Thiên Vận Tông","ghiChu":"Anh Biến đại viên mãn, gần Vấn Đỉnh; được Vương Lâm nhận ra trong lễ giảng đạo."},{"ten":"Tôn trưởng lão","tag":"khac","quanHe":"Cao thủ tu chân liên minh giáng lâm thọ yến","ghiChu":"Tiểu điêu ba mắt của Tôn trưởng lão đậu vai dò xét riêng Vương Lâm; hắn thấy quen quen."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Đầu lĩnh Hoàng Hệ cùng dự thọ yến","ghiChu":"Được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Kiếm Tôn Đại La Kiếm Tông","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị hắn cướp ở Tiên giới năm xưa, gợi mở ân oán liên quan các thanh Vũ chi kiếm."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ đồng môn","ghiChu":"Khiêu chiến Vương Lâm trong cuộc tranh phong hiệu; mô phỏng Hoá Ma chỉ của hắn để sáng chế Tử Ma thủ."},{"ten":"Vận Đường","tag":"khac","quanHe":"Đại sư huynh Hoàng hệ đồng môn","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị: mắt Vận Đường co rút khi tinh thể vàng xuất hiện, ánh mắt thoáng sợ hãi rồi mỉm cười với hắn."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Tử hệ Lão Lục giành phong hiệu","ghiChu":"Trần Đào khinh thường Vương Lâm, hai bên giao chiến tranh phong hiệu Thiên Vận Thất tử."},{"ten":"Triệu Hân Mộng","tag":"doi-thu","quanHe":"Tứ sư tỷ Tử hệ","ghiChu":"Gài bẫy hấp thu ma lực thất bại, thừa nhận xem thường Vương Lâm rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào tự xưng sư huynh, Vương Lâm phủ nhận tư cách đó của hắn; hai người giao chiến."},{"ten":"Lão già mặt đỏ","tag":"khac","quanHe":"Khách chúc thọ nhận ra sát chiêu","ghiChu":"Lão già mặt đỏ thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp."},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Thắng Vương Lâm đoạt phong hiệu Thiên Vận Thất tử, hẹn tái chiến sau khi Vương Lâm đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Nhận Vương Lâm làm đệ tử chân chính, hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, sắp đặt khảo nghiệm Toái Tiên chi địa."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn quen biết qua đại thọ","ghiChu":"Có ước hẹn với Thiên Vận Tử về Đông Hải Yêu Linh chi môn ba tháng sau."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Nhân vật bí ẩn ‘hơn một người’ trong thế giới bảy màu, nắm Sát Lục Tiên quyết, mời truyền nhưng Vương Lâm từ chối; vẫn để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Thiếu Tông Huyền Uyên Phái chủ động ra đón và kết giao, đưa Vương Lâm tới Linh Nhạc quốc","ghiChu":"Cùng tu vi Anh Biến Trung kỳ"},{"ten":"Triệu Tứ","tag":"khac","quanHe":"Tu sĩ vận hành Truyền tống trận đưa Vương Lâm tới Địa Tinh, kính gọi hắn là Thất sư tổ"},{"ten":"Thiên Thai lão nhân","tag":"khac","quanHe":"Cao thủ đệ nhất Linh Nhạc quốc; từng đến Thông Thiên tháp thăm dò Vương Lâm rồi khiếp sợ, cuối chương Vương Lâm tìm đến tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Hứa Vân Sơn","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả, gọi là Vương huynh, hẹn ngày sau cùng uống rượu","ghiChu":"@c0477"},{"ten":"Thiên Thai lão nhân","tag":"dong-minh","quanHe":"Tu sĩ Anh Biến kỳ phục vụ, trao ngọc giản ba chỗ yêu thú","ghiChu":"Gọi Vương Lâm là Sứ giả đại nhân"},{"ten":"Văn thú","tag":"khac","quanHe":"Vật nuôi","ghiChu":"Yêu thú đến từ tinh không, Vương Lâm nuôi lớn bằng cách thả hấp thu yêu thú Hóa Thần trở lên; đang ở thời khắc sắp tiến hóa."},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Cùng hướng tới Diệu Kim quả","ghiChu":"Vương Lâm âm thầm theo dõi đoàn của nàng (bị Đại La Kiếm Tông ép dẫn đường)."},{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Đối thủ bị Vương Lâm đánh tan nguyên thần, nuốt thân xác và cuối cùng giết chết dù đã đoạt xá Quách Tà Dật.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Nữ tử tiểu bối quỳ cầu Vương Lâm giết Thạch Phương cùng Trưởng lão Đại La Kiếm Tông, nguyện làm trâu ngựa hầu hạ.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"an-nhan","quanHe":"Tặng Thiên Cầm sợi kim linh căn cuối cùng coi như đền bù cơ duyên đã chiếm.","ghiChu":"@c0484"},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Tù nhân khai bí mật rồi bị giết","ghiChu":"Bắt giam tra hỏi về Kiếm Tôn và Đông Hải Yêu Linh chi môn, sau đó xử tử bằng loan đao và khí xám Sát lục tiên quyết."},{"ten":"Kiếm Tôn","tag":"khac","quanHe":"Mục tiêu liên quan chuyến đi","ghiChu":"Kẻ phong ấn Chu Dật và 1/3 kiếm hồn trong Đông Hải Yêu Linh chi môn — nơi Vương Lâm sắp tới."},{"ten":"Tôn Vân Sơn","tag":"dong-minh","quanHe":"Bạn đồng hành cùng đi Đông Hải Yêu Linh","ghiChu":"Tôn Vân Sơn cố đợi để cùng đi cho có bạn"},{"ten":"Tôn Nhược Nam","tag":"khac","quanHe":"Muội của Tôn Vân Sơn, lén bám theo hắn","ghiChu":"Nhìn Vương Lâm thoáng lóe kinh ngạc"},{"ten":"Tham Lang","tag":"doi-thu","quanHe":"Kẻ truy tìm sợi tơ Thiên Kiếp và tìm Vương Lâm","ghiChu":"Xuất hiện ngay tại nơi Vương Lâm đang đến"},{"ten":"Trần Đào","tag":"doi-thu","quanHe":"Đồng môn Tử hệ Thiên Vận Tông","ghiChu":"Lão lục từng tranh phong hào Thiên Vận Thất Tử; nhìn Vương Lâm với ánh mắt kỳ dị khi hắn tới cửa Đông Hải."},{"ten":"Tôn Vân Sơn","tag":"dong-hanh","quanHe":"Đồng hành tới Đông Hải","ghiChu":"Tách ra trước cửa, nhờ Vương Lâm chiếu cố, hẹn gặp lại trong Đông Hải Yêu Linh."},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Người được phụ thân dặn theo dõi Vương Lâm","ghiChu":"Thấy ánh mắt yêu dị mang khí xám của hắn sau khi dùng thần thông liền chấn động, hiểu vì sao phụ thân bảo nàng phải chú ý đến hắn (@c0490)."},{"ten":"Tôn Vân Sơn","tag":"dong-minh","quanHe":"Người báo cho Vương Lâm rằng hành trình Đông Hải kéo dài năm trăm năm","ghiChu":"@c0491"},{"ten":"Người xích lõa vẽ nhựa cây (thợ săn)","tag":"khac","quanHe":"Người chủng tộc lạ Vương Lâm gặp đầu tiên trong sơn cốc","ghiChu":"Vương Lâm nhường con thú, sau đó giam giữ để tra hỏi nguồn gốc nơi này."},{"ten":"Âu Dương Hoa","tag":"doi-thu","quanHe":"Trưởng lão bộ tộc sơn cốc, đối đầu qua trận pháp","ghiChu":"Khuyên Vương Lâm rời đi tới Cổ yêu thành rồi điều khiển trận pháp phản kích."},{"ten":"Âu Dương Hoa","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Âu Dương Hoa vây Vương Lâm bằng trận pháp thượng cổ, chiêu hàng tàn nhẫn rồi cầu tha khi bị phá trận."},{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Trưởng lão tộc nhân sơn cốc thần phục, mời vào cốc và kể về Hoàng Long cùng đêm yêu linh","ghiChu":""},{"ten":"Hoàng Long","tag":"khac","quanHe":"Người trong bức tranh cổ khiến Vương Lâm chấn động nguyên thần","ghiChu":""},{"ten":"Hắc y nam tử","tag":"doi-thu","quanHe":"Tu sĩ Thiên Vận Tinh săn yêu linh, tuyên bố coi Vương Lâm là con mồi để lấy yêu tinh tiến vào Thiên Yêu Thành","ghiChu":"Gặp @c0497; đối thủ lầm tưởng Vương Lâm chỉ Ứng Biến trung kỳ."},{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Tu sĩ trông coi Hồ Lô Cốc, đổi yêu lực kết tinh và cầu Vương Lâm cứu mạng khi yêu linh tấn công","ghiChu":"@c0497"},{"ten":"La mỗ","tag":"doi-thu","quanHe":"Đối thủ chạm trán ngoài thung lũng yêu linh","ghiChu":"Ban đầu tưởng Vương Lâm là người Đại La Kiếm Tông, sau nhận ra hắn là đệ tử Thiên Vận Tử; lo khó giết vì Vương Lâm có pháp bảo bảo mệnh."},{"ten":"Tử hệ lão Lục","tag":"doi-thu","quanHe":"Sư huynh đồng môn Tử hệ","ghiChu":"Từng dùng tu vi Vấn Đỉnh đè ép, khiến Vương Lâm mất danh hiệu Thiên Vận Thất Tử."},{"ten":"La mỗ (Hắc y nhân)","tag":"doi-thu","quanHe":"Đối thủ giao chiến trong Yêu linh khí lãng","ghiChu":"Tu sĩ Anh Biến hậu kỳ đại viên mãn, tự xưng hành sự thay Tôn sư; bị Vương Lâm đả thương nguyên thần, đáp trả bằng Ma cấm triệu Quỷ ảnh."},{"ten":"Hắc y nam tử (mặt sẹo)","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Áp chế bằng Hóa ma chỉ và Xạ Thần Xa, buộc hắn bỏ thân xác chạy nguyên thần; trước đó từng dùng cùng sát chiêu đấu Tử hệ lão Tứ."},{"ten":"La Vân","tag":"doi-thu","quanHe":"Đối thủ bị Vương Lâm diệt thân, bắt sống nguyên thần và Sưu Hồn đoạt ký ức","ghiChu":"Tu sĩ Thiên Quỷ Đạo, bị giam vào hồn phiên để luyện chủ hồn (@c0501)"},{"ten":"Quỷ Chân Nhân","tag":"doi-thu","quanHe":"Sư tôn của La Vân, bị La Vân dọa sẽ báo thù Vương Lâm","ghiChu":"Mầm xung đột tương lai với Thiên Quỷ Đạo (@c0501)"},{"ten":"La Vân","tag":"doi-thu","quanHe":"Tu sĩ Thiên Quỷ Đạo bị Vương Lâm hấp thu ký ức","ghiChu":"Vương Lâm nắm trọn ký ức về vùng đất yêu linh từ La Vân; hiểu La Vân muốn giết mình để đoạt giáp yêu lực còn thiếu."},{"ten":"Âu Dương Hoa","tag":"su-mon","quanHe":"Đệ tử quy phục","ghiChu":"Được Vương Lâm đả thông kinh mạch đột phá nhị tinh và truyền thụ thuật luyện hồn; đ���i xưng hô thành vãn bối, hành lễ như đệ tử."},{"ten":"Thập Tam","tag":"khac","quanHe":"Thuộc hạ được coi trọng","ghiChu":"Thanh niên Vương Lâm âm thầm theo dõi, có ngộ tính trời sinh với Luyện Hồn Thuật; Vương Lâm trao phương pháp mới và cứu hắn khi bị sư tử phản phệ."},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Tộc nhân chủ lực được Vương Lâm dạy Luyện Hồn Thuật và ban chủ hồn","ghiChu":""},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Người dẫn dắt bộ lạc, cung kính gọi Vương Lâm ‘thượng tiên’, dâng yêu tinh đổi khẩu quyết","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[{"ten":"Tiên ngọc","loai":"tài nguyên tu luyện","trangThai":"dang-co","moTa":"123.600 khối tiên ngọc lấy từ Phẩm Linh Các, dùng để hấp thu đột phá Anh Biến trung kỳ","nguon":"@c0458"}],"linhThao":[],"khac":[{"ten":"Lệnh bài Phẩm Linh Các","loai":"vật phẩm","trangThai":"da-dung","moTa":"Lệnh bài lấy tiên ngọc, ấn vào trận pháp ba đạo bạch ngân để mở cửa truyền tống lên tầng bảy và xác nhận thân phận lĩnh tiên ngọc","nguon":"@c0458"}]}},"nguon":["@c0458","@c0459","@c0460","@c0461","@c0462","@c0463","@c0464","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0471","@c0472","@c0473","@c0474","@c0476","@c0477","@c0478","@c0479","@c0480","@c0483","@c0484","@c0485","@c0487","@c0488","@c0489","@c0490","@c0491","@c0492","@c0493","@c0494","@c0495","@c0496","@c0497","@c0498","@c0499","@c0500","@c0501","@c0502","@c0503","@c0504","@c0505","@c0506"]},{"id":"truong-huong-pham","name":"Trương Hướng Phàm","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Mở khóa Phẩm Linh Các cho Thất sư tổ","text":"Trương Hướng Phàm ấn lệnh bài vào chỗ ba đạo bạch ngân giao nhau, kích hoạt trận pháp tạo cánh cửa truyền tống tại tầng thứ bảy Phẩm Linh Các, rồi cung kính mời Thất sư tổ Vương Lâm cầm lệnh bài tiến vào."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Cung kính dẫn Thất sư tổ Vương Lâm vào Phẩm Linh Các lấy tiên ngọc","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"trieu-tinh-sat","name":"Triệu Tinh Sát","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Góp mặt vây kích Vương Lâm","text":"Sắc mặt ôn hòa tiêu sái, Triệu Tinh Sát hiện ra từ gợn sóng bên cạnh Vương Lâm, là một trong năm người hợp vây tại Tử Lâm Các."},{"chuong":"@c0460","importance":"normal","tieuDe":"Độc thoại tranh đoạt thất tử","text":"Trong khi canh giữ tử vụ đại trận trước thọ yến, độc thoại điểm danh sáu vị tử còn lại (lão nhị bỏ cuộc, lão tam không để vào mắt, lão tứ nữ có cách giữ, lão ngũ bị phạt thiên ngục, lão lục xuất ngoại sinh tử chưa rõ), cảnh cáo lão thất chớ tranh đoạt với mình."},{"chuong":"@c0460","importance":"normal","tieuDe":"Nghênh đón Kim Ma tử","text":"Nhận ra Kim Ma tử trên chiến xa vàng, toát mồ hôi lạnh cung kính ra mắt rồi dẫn đường đưa chiến xa về Thiên Vận Tinh dự thọ yến."},{"chuong":"@c0461","importance":"normal","tieuDe":"Chủ tọa thọ yến Thiên Vận Tử","text":"Đại sư huynh Tử hệ nhất mạch ngồi chủ tọa tiệc thọ yến ngàn năm của sư tôn Thiên Vận Tử; vừa đứng dậy chúc rượu thì Vương Lâm — kẻ hắn từng mượn sức người ngoài na di vây khốn trong thạch lâm — xuất hiện thành cầu vồng tím từ chân trời đằng đông lao thẳng tới."},{"chuong":"@c0462","importance":"normal","tieuDe":"Cản Vương Lâm bất thành","text":"Sắc mặt cực xấu khi thấy Vương Lâm phá vây đạt Anh Biến Trung Kỳ, bóp nát chén rượu. Lão bước ra chắn trước nhị sư huynh, thi triển Đại tự tại thiên địa quyết tạo quầng sáng trắng bọc ma hỏa, nhưng bị ma hỏa tự bạo thiêu vỡ nên phải lui lại."},{"chuong":"@c0462","importance":"normal","tieuDe":"Đứng nhìn đồng môn bị giết","text":"Sau khi cản thất bại, Triệu Tinh Sát đứng nhìn Hứa Lập Quốc bị Vương Lâm truy sát mà cười lạnh, không hề ra tay cứu, hé lộ rạn nứt và toan tính trong nội bộ Tử hệ."},{"chuong":"@c0463","importance":"normal","tieuDe":"Triệu Cổ Yêu cấm thuật","text":"Bị Vương Lâm dồn ép và bị lão tứ từ chối trợ giúp, Triệu Tinh Sát dùng trước thuật triệu Cổ Yêu vốn định để dành cho dịp tranh danh hiệu Thiên Vận Thất Tử. Ký hiệu cổ quái lóe giữa lông mày gọi ra hư ảnh yêu vật trăm trượng, nhưng càng dùng thân thể hắn càng suy yếu."},{"chuong":"@c0463","importance":"normal","tieuDe":"Phản phệ và tham kiến Xích Liệt","text":"Cổ yêu bị tiếng hét của Xích Liệt buộc rút lui, Triệu Tinh Sát phun máu, cười u ám nhìn Vương Lâm. Hắn cung kính tham kiến Xích Liệt sư thúc, xác nhận mấy ngàn năm trước khi mới bái nhập Thiên Vận Tông từng gặp mặt một lần."},{"chuong":"@c0464","importance":"normal","tieuDe":"Bị Xích Liệt áp giải","text":"Sau khi gượng dùng yêu linh chưa kịp luyện hóa, Triệu Sát Tinh bị Xích Liệt túm mang đi để sư phụ trừng phạt, mất chức chủ yến hội về tay Vương Lâm."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia nhóm năm người vây kích Vương Lâm","ghiChu":"@c0458"},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"sư tôn","ghiChu":"Triệu Tinh Sát là đại sư huynh Tử hệ thuộc Thiên Vận Thất tử của Thiên Vận Tử."},{"ten":"Kim Ma tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Cung kính nghênh đón, dẫn đường về Thiên Vận Tinh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"đối thủ ngầm (nghi là lão thất)","ghiChu":"Triệu Tinh Sát cảnh cáo lão thất, đối tượng có thể chính là Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ bị hắn chèn ép, na di vây khốn","ghiChu":"Vương Lâm trở về quyết báo thù giữa thọ yến."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối đầu, cản bất thành rồi bị ma hỏa đánh lui","ghiChu":""},{"ten":"Hứa Lập Quốc","tag":"khac","quanHe":"Đồng môn Tử hệ mà Triệu Tinh Sát bỏ mặc không cứu","ghiChu":""},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ, bị hắn tố giết lão nhị","ghiChu":"Định dùng Cổ Yêu trừ Vương Lâm nhưng thất bại."},{"ten":"Tứ sư tỷ (Tử hệ)","tag":"khac","quanHe":"Cầu viện trợ nhưng bị từ chối","ghiChu":"Lão tứ viện cớ đã đền ân ba tháng trước và không tranh danh hiệu."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Sư thúc Thiên Vận Tông","ghiChu":"Tham kiến cung kính, từng gặp mấy ngàn năm trước."},{"ten":"Xích Liệt","tag":"su-mon","quanHe":"Tiền bối tông môn áp giải","ghiChu":"Bị Xích Liệt túm đi sau khi gượng dùng yêu linh."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0460","@c0461","@c0462","@c0463","@c0464"],"aliases":["Triệu Sát Tinh"]},{"id":"tu-ma-nhu-phong","name":"Tư Mã Như Phong","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Lam tông (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến kỳ","trangThai":"song","blurb":"Đệ tử đứng hàng thứ hai thuộc Lam tông của Thiên Vận Tông, y phục lam thêu ba con lam long, tươi cười ôn hòa nhưng tham gia vây kích Vương Lâm.","vaiTro":"Đệ tử Lam tông Thiên Vận Tông, một trong năm người vây kích Vương Lâm","tinhCach":[{"text":"Tươi cười ôn hòa nhưng ngầm hiểm, khéo quan sát đối thủ","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Y phục lam thêu ba con lam long, đứng hàng thứ hai trong đệ tử Lam tông","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Vây kích và giới thiệu sư huynh ẩn mình","text":"Tư Mã Như Phong tươi cười hiện thân trong nhóm vây kích Vương Lâm tại Tử Lâm Các, đoán Vương Lâm đã Anh Biến hậu kỳ đại viên mãn, rồi giới thiệu một vị sư huynh ẩn mình mạnh hơn hẳn."}],"tuViMoc":[],"tuVi":"Đệ tử Anh Biến kỳ đứng hàng thứ hai thuộc Lam tông Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích, đoán định tu vi Vương Lâm","ghiChu":"@c0458"},{"ten":"Người y phục xanh (như tượng băng)","tag":"dong-minh","quanHe":"Giới thiệu vị sư huynh ẩn mình nửa bước vấn đỉnh","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"tu-su-ty-tu-he","name":"Tứ sư tỷ (Tử hệ)","cn":"","aliases":["Tứ sư tỷ","Tứ sư tỷ (Tử hệ)"],"gioiTinh":"nu","theLuc":[{"ten":"Tử hệ (Thiên Vận Tông)","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ","trangThai":"song","blurb":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông; được người nhờ vả nên ra tay, thi triển Tử thuật - Na di trong cuộc vây kích Vương Lâm.","vaiTro":"Sư tỷ đồng hệ Tử của Vương Lâm, một trong năm người vây kích","tinhCach":[{"text":"Bất đắc dĩ ra tay vì chịu lời nhờ vả của người khác","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Anh Biến hậu kỳ, thuộc Tử hệ và sử dụng Tử thuật","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Thi triển Tử thuật - Na di khởi chiến","text":"Bất đắc dĩ thừa nhận được người nhờ vả, tứ sư tỷ bắt quyết điểm vào hư không, một tia sáng bạc lan ra bao trùm mười dặm, mở màn cuộc vây kích Vương Lâm tại Tử Lâm Các."},{"chuong":"@c0459","importance":"normal","tieuDe":"Na di vây khốn lão thất","text":"Tứ sư tỷ — nữ tử xinh đẹp như tiên tử đội mũ tơ tằm — dùng thần thông na di đưa Vương Lâm tới thạch lâm khốn địa, hứa sau ba năm sẽ tới thả ra và truyền thần thông na di cho hắn khi mọi chuyện giải quyết xong. Trước khi rời đi, nàng nói với đại sư huynh rằng nhân tình năm đó nay đã hồi báo, từ nay hai người không còn liên quan, rồi hóa ngân quang bay về Thiên Vận Tông."},{"chuong":"@c0463","importance":"normal","tieuDe":"Từ chối ra tay giúp Triệu Tinh Sát","text":"Khi Triệu Tinh Sát lớn tiếng cầu viện, lão tứ bình thản đáp ân tình ba tháng trước đã đền đáp và đã đồng ý không tranh đoạt danh hiệu Thiên Vận Thất Tử với hắn, đòi một lý do mới chịu ra tay. Triệu Tinh Sát cắn răng tức giận mất chỗ dựa."},{"chuong":"@c0464","importance":"normal","tieuDe":"Trao ngọc giản hai cấm pháp","text":"Đêm khuya yến tàn, tứ sư tỷ đưa Vương Lâm một ngọc giản chứa cấm pháp đại na di cùng một cấm pháp do sư tôn phỏng theo hạ phẩm tiên thuật sáng tạo, coi như xin lỗi việc tháng trước — lúc đó nàng dùng cấm pháp phong ấn nhưng chưa thực sự ra tay."},{"bridge":true,"khoang":"@c0465","text":"Trong thọ yến, Tứ sư tỷ truyền âm than thở với Vương Lâm rằng Tử Tông đang sa sút vì tranh đoạt nội bộ quá nhiều, danh hiệu Thiên Vận Thất Tử thay đổi thường xuyên, không còn uy phong như thời Tôn Vân sư đệ năm xưa."},{"bridge":true,"khoang":"@c0468","text":"Tứ sư tỷ thần thái như thường, bình tĩnh trụ vững khảo nghiệm áp lực cùng Vương Lâm; khi thấy hắn vượt trội nàng liếc một cái đầy thâm ý nhưng không nói gì."},{"chuong":"@c0469","importance":"normal","tieuDe":"Khiêu chiến Vương Lâm tranh phong hiệu","text":"Sau khi Bạch Vi bỏ cuộc, Triệu Hân Mộng nhíu mắt nhìn Vương Lâm, đòi giao chiến một trận để hắn không đạt phong hiệu quá đơn giản. Khi khai chiến nàng giật lui hơn mười trượng, vận Tử Ma thủ — thần thông tự sáng chế bằng cách mô phỏng Hoá Ma chỉ của Vương Lâm — đẩy tử quang gào rít lao tới."},{"chuong":"@c0470","importance":"normal","tieuDe":"Bẫy hấp thu ma lực bất thành","text":"Triệu Hân Mộng bắt chước Tử Ma thủ dụ Vương Lâm dùng Hoá Ma chỉ để cướp ma lực, định không tranh phong hiệu Thiên Vận Thất tử với hắn. Nàng dùng hạt châu trắng hút ma lực khiến nó hoá đen, nhưng Vương Lâm khiến ma lực hư ảo tự sụp, hạt châu vỡ vụn; nàng đe doạ nhưng bị từ chối."},{"chuong":"@c0470","importance":"normal","tieuDe":"Đấu Cửu chuyển luyện tiên rồi bỏ cuộc","text":"Nàng thi Cửu chuyển luyện tiên quyết tu ra kim sắc lốc xoáy năm vòng, nhưng kinh ngạc khi Vương Lâm chỉ vài ngày đã đạt ngũ chuyển lại rút chiến phủ và Xạ Thần xa. Triệu Hân Mộng thừa nhận đã xem thường hắn rồi rời đi, sau đó truyền âm cho Trần Đào về việc Tôn Vân."}],"tuViMoc":[],"tuVi":"Nữ tử Anh Biến hậu kỳ thuộc Tử hệ Thiên Vận Tông.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đồng hệ Tử nhưng ra tay vây kích theo lời nhờ vả","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ đồng môn (lão thất)","ghiChu":"Đích thân na di đưa hắn tới khốn địa, hẹn ba năm thả; hứa truyền thần thông na di."},{"ten":"Đại sư huynh (Thiên Vận Tông)","tag":"doi-thu","quanHe":"Sư huynh đồng môn, từng có nhân tình","ghiChu":"Tuyên bố nhân tình năm xưa đã hồi báo, cắt đứt quan hệ với đại sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Người từng chịu ân, nay cầu viện","ghiChu":"Lão tứ từ chối trợ giúp."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Sư đệ cùng Tử hệ","ghiChu":"Trao ngọc giản hai cấm pháp xin lỗi việc tháng trước."},{"ten":"Tôn Vân","tag":"su-mon","quanHe":"Sư đệ Tử Hệ thời còn uy phong, được nhắc lại khi than về sự sa sút","ghiChu":""},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Hai người duy nhất của Tử hệ trụ vững khảo nghiệm; Tứ sư tỷ liếc Vương Lâm đầy thâm ý trước biểu hiện vượt trội của hắn."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Lão Thất đồng môn","ghiChu":"Khiêu chiến và giao chiến với Vương Lâm; mô phỏng Hoá Ma chỉ của hắn thành Tử Ma thủ."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Thất sư đệ Tử hệ (giả danh)","ghiChu":"Gài bẫy hấp thu ma lực bất thành, đánh giá thấp rồi bỏ cuộc."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Truyền âm cho Trần Đào về việc Tôn Vân khiến hắn biến sắc."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Tử thuật - Na di","moTa":"Pháp thuật Tử hệ, bắt quyết điểm vào hư không phát tia sáng bạc bao trùm mười dặm","nguon":"@c0458"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458","@c0459","@c0463","@c0464","@c0465","@c0468","@c0469","@c0470"]},{"id":"nguoi-y-phuc-xanh-tuong-bang","name":"Người y phục xanh (như tượng băng)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước vấn đỉnh kỳ","trangThai":"song","blurb":"Vị sư huynh ẩn mình do Tư Mã Như Phong giới thiệu; lạnh lùng như chúa tể thiên hạ, tu vi đã bước nửa bước vào vấn đỉnh kỳ.","vaiTro":"Cường giả ẩn mình trong nhóm vây kích Vương Lâm","tinhCach":[{"text":"Lạnh lùng kiêu ngạo, đứng như tượng băng ngàn năm, coi đối thủ không xứng để ra tay","chuong":"@c0458"}],"tabs":{"diem":[{"text":"Tu vi nửa bước vấn đỉnh kỳ, ánh mắt đầy vẻ chúa tể thiên hạ","chuong":"@c0458"}],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lộ diện trong cuộc vây kích","text":"Một tiếng nói lạnh như băng vang lên, người y phục xanh xuất hiện sau lưng Vương Lâm vài chục trượng, đứng như tượng băng ngàn năm, liếc một cái rồi nhắm mắt dưỡng thần vì coi Vương Lâm không xứng để ra tay."}],"tuViMoc":[],"tuVi":"Tu vi đã bước nửa bước vào vấn đỉnh kỳ.","nhanMach":[{"ten":"Tư Mã Như Phong","tag":"dong-minh","quanHe":"Được Tư Mã Như Phong giới thiệu là sư huynh ẩn mình","ghiChu":"@c0458"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tham gia vây kích nhưng coi Vương Lâm không xứng để ra tay","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"thuy-to-thien-van-tong","name":"Thủy tổ đại nhân (Thiên Vận Tông)","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"khong-ro","blurb":"Thủy tổ của Thiên Vận Tông; từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản, và cạnh tranh nội bộ giữa đệ tử của ông cực kỳ khốc liệt.","vaiTro":"Thủy tổ tông môn Thiên Vận Tông, được nhắc tên","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0458","importance":"normal","tieuDe":"Lệnh không quản Vương Lâm","text":"Được ba chấp pháp trưởng lão nhắc tới: Thủy tổ từng dặn chỉ cần Vương Lâm không phạm môn quy thì khỏi quản; cạnh tranh nội bộ giữa các đệ tử của ông cực kỳ khốc liệt."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Thủy tổ tông môn, ra lệnh không quản chừng nào Vương Lâm chưa phạm môn quy","ghiChu":"@c0458"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0458"]},{"id":"dai-su-huynh-thien-van-tong","name":"Đại sư huynh (Thiên Vận Tông)","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0459","importance":"normal","tieuDe":"Bố trí trận pháp vây khốn","text":"Đại sư huynh là người bố trí trận pháp tại thạch lâm khốn địa để vây Vương Lâm — màn sáng bạc bao phủ mười dặm, triệt tiêu mọi kiếm quang pháp bảo phóng ra. Bị tứ sư tỷ tuyên bố cắt đứt nhân tình năm xưa khi nàng đưa Vương Lâm tới đây."}],"tuViMoc":[],"nhanMach":[{"ten":"Tứ sư tỷ (Tử hệ)","tag":"doi-thu","quanHe":"Sư muội đồng môn, từng có nhân tình","ghiChu":"Bị tứ sư tỷ tuyên bố nhân tình đã hồi báo, từ nay không còn liên quan."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư đệ đồng môn","ghiChu":"Bố trí trận pháp vây khốn Vương Lâm tại thạch lâm."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0459–@c0459","text":"Là khí linh trong tiên kiếm của Vương Lâm, được điều khiển cùng loan đao lao thử phá trận pháp khốn địa nhưng thất bại, kêu thảm rằng không phá nổi thứ này rồi bị thu về."},{"chuong":"@c0462","importance":"normal","tieuDe":"Nghênh chiến rồi bị trọng thương","text":"Là nhị sư huynh Tử hệ Thiên Vận Tông, hóa tử quang nghênh chiến Vương Lâm, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Cấm Phiên xé tan. Hắn dùng cấm thuật Tiên Ma thể hóa toàn thân thành sương mù đen để trốn, viện cớ hôm nay là đại thọ sư tôn, song bị tiên kiếm cùng loan đao chém tan, cuối cùng nguyên thần bị Côn Cực Tiên đánh trúng, trọng thương sắp tan."},{"chuong":"@c0483","importance":"normal","tieuDe":"Truy đuổi trong kiếm tiên","text":"Bị nhốt trong kiếm tiên của Vương Lâm, Hứa Lập Quốc lên tiếng kiêu ngạo và cùng thanh loan đao đuổi theo, giam giữ lão già thấp người Trưởng lão Đại La Kiếm Tông đang bỏ chạy."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ tử","ghiChu":"Gọi Vương Lâm là Chủ tử, được sai phá vây bất thành."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, đả thương nguyên thần giữa thọ yến","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đồng môn Tử hệ đứng nhìn không cứu khi hắn bị giết","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0459","@c0462","@c0483"],"aliases":["Lão nhị","Nhị sư huynh"]},{"id":"kim-ma-tu","name":"Kim Ma tử","gioiTinh":"nam","tabs":{"diem":[{"text":"Tôn giả độc chiếm một tiểu tinh, hoành hành ngang ngược, tính nóng nảy, giết người vô số.","chuong":"@c0460"},{"text":"Thân to như quả cầu thịt, da trong suốt như thủy tinh.","chuong":"@c0460"}],"kinhLich":[{"chuong":"@c0460","importance":"normal","tieuDe":"Tới chúc thọ Thiên Vận Tử","text":"Đáp chiến xa vàng cao hơn ngàn trượng do bốn yêu thú khổng lồ nâng đỡ, kèm mười tùy tùng trường sam bạc, tới Thiên Vận Tinh dự thọ yến; được Triệu Tinh Sát cung kính dẫn đường, thân phận chỉ đủ ngồi ở thọ tiệc do Xích tông tổ chức."}],"tuViMoc":[{"chuong":"@c0460","canhGioi":"Thông thiên (đồn đạt Hư Thật nhị ý)","text":"Tu vi loại thông thiên, có lời đồn đã chạm tới cảnh giới truyền thuyết Hư Thật nhị ý.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"khách chúc thọ","ghiChu":"Tự thân tới chúc đại thọ ngàn năm."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"người nghênh đón","ghiChu":"Được dẫn đường về Thiên Vận Tinh."}],"tuiDo":{"phapBao":[{"ten":"Chiến xa màu vàng của Kim Ma tử","trangThai":"dang-co","moTa":"Chiến xa khổng lồ cao hơn ngàn trượng đầy mũi nhọn, bốn yêu thú nâng đỡ; trên xe có ghế lớn và mười tùy tùng.","nguon":"@c0460"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"theLuc":[{"ten":"Thiên Vận Tông","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Thông thiên","trangThai":"song","vaiTro":"Tôn giả độc chiếm một tiểu tinh thuộc Thiên Vận Tông, khách chúc thọ Thiên Vận Tử.","blurb":"Tôn giả thân tròn như cầu thịt da trong như thủy tinh, hoành hành ngang ngược, tu vi thông thiên đồn đạt Hư Thật nhị ý.","nguon":["@c0460"]},{"id":"tao-nhat-dau","name":"Tào Nhất Đấu","gioiTinh":"nam","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0461","importance":"normal","tieuDe":"Dẫn đường về Thiên Vận Tông","text":"Được Vương Lâm phất hồn phiên thả nguyên thần ra, Tào Nhất Đấu nhận ra đây chính là Thiên Vận Tinh quê cũ, chỉ về hướng tây cách khoảng ba mươi vạn dặm là sơn môn Thiên Vận Tông; hắn tình nguyện dẫn đường vì được hứa cho một thân thể anh biến."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Người thu nhận nguyên thần của hắn ở Thi Âm tông","ghiChu":"Làm người dẫn đường để đổi lấy lời hứa một thân thể anh biến."}],"tuiDo":{}},"nguon":["@c0461"]},{"id":"thien-van-tu-su-ton","name":"Thiên Vận Tử","cn":"","aliases":["Sư tôn Tử tông"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Sư tôn của Tử tông trong Thiên Vận Tông, được tông môn mở thọ yến ngàn năm và sẽ giảng đạo sau bảy ngày.","vaiTro":"Sư tôn của Tử hệ nhất mạch, nhân vật cấp cao trên Thiên Vận Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Bậc sư tôn được cả Tử tông tổ chức thọ yến ngàn năm","chuong":"@c0461"}],"kinhLich":[{"chuong":"@c0461","importance":"normal","tieuDe":"Thọ yến ngàn năm","text":"Thiên Vận Tông mở thọ yến ngàn năm mừng sư tôn Thiên Vận Tử, bày tiệc tiên quả sơn tửu náo nhiệt; bảy ngày thọ yến xong sẽ là ngày Thiên Vận Tử giảng đạo, một tháng sau là kỳ Tử Hoàng nhị tông tranh đoạt danh hiệu Thiên Vận Thất tử."},{"chuong":"@c0465","importance":"normal","tieuDe":"Chủ trì đại thọ vạn năm, giảng Thiên Vận Chi Đạo","text":"Thiên Vận Tử xuất hiện trên quầng sáng bảy màu, được đệ tử đích hệ bảy tông và vô số tu sĩ tham bái. Ông mời lão bằng hữu Tôn trưởng lão từ tu chân liên minh xuất hiện, nhận phi kiếm trung phẩm tiên khí rồi tặng lại Côn Bằng Tử, sau đó khoanh chân ngồi giảng Thiên Vận Chi Đạo với cốt lõi ‘nghe theo mệnh trời’."},{"chuong":"@c0466","importance":"normal","tieuDe":"Giảng ba bước tu đạo","text":"Ngồi khoanh chân trên tường vân, Thiên Vận Tử giảng đạo cho đệ tử lục hệ và tu sĩ bốn phía: liệt kê bảy cảnh Ngưng Khí tới Vấn Đỉnh thuộc chữ ‘tu’ (bước một), bước hai là hư thực nhị ý và toái niết tam cảnh nơi hầu hết tu sĩ phải dừng chân, bước ba là chữ ‘đạo’ cầu thiên vận. Hắn phân biệt tu tiên, tu chân, tu đạo và thừa nhận chính mình bước một còn chưa hoàn thành."},{"chuong":"@c0466","importance":"normal","tieuDe":"Tiết lộ về ‘hắn’","text":"Đáp lời hoài nghi của Vương Lâm, Thiên Vận Tử than nhẹ lộ vẻ bồi hồi hiếm thấy, kể rằng ba ngàn năm trước hắn cũng không tin có bước thứ ba cho tới khi gặp được ‘hắn’ — một nhân vật bí ẩn cực mạnh."},{"chuong":"@c0467","importance":"normal","tieuDe":"Thi triển trung phẩm Dẫn Tiên thuật","text":"Kết thúc ba ngày giảng đạo nhân đại thọ vạn năm, trước truy hỏi của tu sĩ, Thiên Vận Tử tiết lộ về “hắn” — kẻ duy nhất lão biết đã đạt tới bước thứ ba và từng khiến Tu Chân Liên Minh nếm khổ một lần. Sau đó lão tuyên bố thi triển một trung phẩm Tiên thuật tên Dẫn Tiên thuật, lấy Lăng Thiên Hầu làm đối tượng, phóng xích mang lên trời hiện mảnh màu đỏ mây cuộn như rồng kèm thiên uy giáng xuống."},{"chuong":"@c0468","importance":"normal","tieuDe":"Thi triển Dẫn Tiên thuật cuốn đệ tử Đại La Kiếm Tông","text":"Trong đại thọ vạn năm tuổi, Thiên Vận Tử thi triển Dẫn Tiên thuật (Trung phẩm Tiên thuật), hô “Dẫn độ” cuốn hơn vạn đệ tử Đại La Kiếm Tông mê man bay lên hư không, triệu hư ảnh sứ giả Tiên giới ấn chưởng phong kín; làm nhục Kiếm Tôn Lăng Thiên Hầu và hứa ba ngày sau trả người."},{"chuong":"@c0468","importance":"normal","tieuDe":"Tuyên bố tranh đoạt phong hiệu Thiên Vận Thất tử","text":"Lão công bố trong bảy hệ đệ tử chỉ Hoàng hệ và Tử hệ chưa ai nắm phong hiệu Thiên Vận Thất tử, hôm nay sẽ xuất hiện người mang phong hiệu từ hai hệ này; nh��c lại lão Tam Hoàng hệ từng đạt phong hiệu rồi mất tích ở tinh không ba mươi năm trước."},{"chuong":"@c0469","importance":"normal","tieuDe":"Phân phong hiệu, khuyên Vương Lâm tranh đoạt","text":"Thiên Vận Tử chủ trì phân phong hiệu Thiên Vận Thất tử, trao tinh thể vàng cho Côn Bằng Tử của Hoàng hệ và nhấn mạnh phong hiệu là dấu hiệu thân phận của Thiên Vận Tông. Khi Vương Lâm định bỏ cuộc, lão ngẩn ra rồi đích thân khuyên giải, cho nửa nén hương suy xét, dặn đừng để người ngoài mê hoặc; lão liếc Vận Đường bằng ánh mắt âm trầm khiến lão này run sợ."},{"chuong":"@c0469","importance":"normal","tieuDe":"Độc thoại về bước thứ ba Thiên Vận đạo","text":"Lão hé lộ ba vạn năm trước từng gặp ‘hắn’, người để lại lời rằng chỉ khi tìm được kẻ phù hợp số phận mới tiến được bước thứ ba của Thiên Vận đạo. Suốt ba vạn năm lão thất bại vô số lần, tổn thất hơn nửa đệ tử, nay chăm chú nhìn ngón trỏ Vương Lâm để xét hắn có phải người đó, ánh mắt cuối cùng lộ một tia chán nản."},{"chuong":"@c0470","importance":"normal","tieuDe":"Phán định tranh phong hiệu","text":"Sắp đại thọ vạn năm, Thiên Vận Tử nhận đoá Thất thải lưu ly quang từ Trần Đào, phán chỉ Trần Đào và Vương Lâm đủ tư cách tranh phong hiệu Thiên Vận Thất tử nhưng chỉ một người đạt; hắn tán thưởng cả hai trong trận giao đấu."},{"chuong":"@c0472","importance":"normal","tieuDe":"Kết thúc đại thọ, thu nhận Vương Lâm","text":"Tuyên Trần Đào thắng và trao phong hiệu Thiên Vận Thất tử của Tử hệ; kết thúc đại thọ vạn năm tuổi khiến tu sĩ tản đi. Nhận Vương Lâm làm đệ tử chân chính, đưa về Tổng tông ba ngọn núi tại Thiên Vận Tinh, khảo Vương Lâm câu đố Chân huyễn pháp rồi sắp đặt khảo nghiệm leo Toái Tiên chi địa."},{"chuong":"@c0473","importance":"major","tieuDe":"Thu Vương Lâm làm đệ tử Tử hệ","text":"Thiên Vận Tử triệu Vương Lâm lên đỉnh, kể nguồn gốc Thiên Vận Tông: tổ tiên không phải tu sĩ mà là Thiên vận số, cả đời theo đuổi Thiên vận, tin hết thảy vận số là trời định. Lão vốn không định tới Chu Tước Tinh, vừa lúc gặp Vương Lâm đang cảm ngộ Hóa Thần tìm bản nguyên thiên đạo nên vì quý tài và vận số thầy trò mà thu làm đệ tử thứ bảy của Tử hệ. Lão xé không trung tỏa ánh sáng bảy màu Tối hỉ thất thải chiếu rọi gần nửa bầu trời Thiên Vận Tinh, rồi hỏi Vương Lâm chọn loại Cấm pháp thần thông nào."},{"chuong":"@c0474","importance":"normal","tieuDe":"Mở 3600 Cấm pháp thần thông cho đệ tử","text":"Thiên Vận Tử bình tĩnh để Vương Lâm tự chọn thần thông, từ chối yêu cầu ‘Sinh tồn pháp thuật’ (vi sư không có), rồi nâng tay phải điểm ánh sáng bảy màu, mở ra thế giới bảy màu chứa 3600 đạo Cấm pháp thần thông để đệ tử chọn theo cơ duyên. Lão sở hữu thần thông bảy màu (Tối hỷ khẩu thất thải) và từng có hứa hẹn với Thiên Vận Tử áo xám."},{"chuong":"@c0486","importance":"normal","tieuDe":"Ba lần thăm dò Đông Hải","text":"Ngày thành đạo từng mời bạn tốt (gồm Kiếm Tôn Lăng Thiên Hậu) lập nhóm đến Đông Hải thăm dò ba lần: hai lần đầu về tay không, lần thứ ba vào được bên trong nhưng ra chỉ còn nửa quân số; sau đó tách với Lăng Thiên Hậu, không ai nói ra chuyện đã xảy ra."},{"chuong":"@c0486","importance":"normal","tieuDe":"Tuyên bố Đông Hải thành cấm địa","text":"Tuyên bố trong Đông Hải có Cổ Yêu tồn tại, lập nơi này thành một trong những cấm địa — cửa Đông Hải Yêu Linh; cùng Lăng Thiên Hậu và các lão quái thống nhất không cho người ngoài tiến vào, khiến Tu Chân Liên Minh đành để mặc."},{"chuong":"@c0488","importance":"normal","tieuDe":"Dẫn chín đệ tử tới Đông Hải","text":"Thiên Vận Tử mặc áo trắng từ đám mây bảy màu bước ra, dẫn chín đệ tử Thiên Vận Tông tới cửa Đông Hải Yêu Linh và được nghênh đón long trọng nh��t. Lão cùng Trần Đào tìm kiếm Vương Lâm, khi hắn tới thì bảo đứng phía sau, nhắc xem trọng việc trọng đại và nhìn hắn đầy thâm ý."},{"bridge":true,"khoang":"@c0489","text":"Quan sát thủy triều Đông Hải Yêu Linh, ánh mắt bình tĩnh ngầm lấp lánh tia sáng bảy màu, băn khoăn không biết lần này vật gì sẽ bị hút đến."},{"bridge":true,"khoang":"@c0490","text":"Sắc mặt khẽ biến rồi vội xoay người khi con sóng hồng quang cuối ập tới; đại biến sắc khi khối lệnh bài kim quang lộ ra giữa thủy triều cửa Đông Hải Yêu Linh."},{"chuong":"@c0491","importance":"normal","tieuDe":"Ước định năm trăm năm tụ lại Đông Hải","text":"Điều mười đệ tử Thiên Vận Tông (gồm Vương Lâm) vào cánh cửa; xác nhận có tất cả ba cái lệnh bài liên quan đại bí mật Thiên Vận Tinh, ước định năm trăm năm sau theo chu kỳ thí luyện sẽ tụ tập tiến vào lần nữa, dặn mọi người chuẩn bị cẩn thận vì chuyện năm đó."},{"chuong":"@c0491","importance":"normal","tieuDe":"Bói vận may Vương Lâm","text":"Về bảo tháp bảy màu trong dãy núi tam sắc ở Thiên Vận Tinh, rải vài mẩu xương thú đen kịt tỏa khí tà dị quanh mình để quan sát, nhận xét Vương Lâm là kẻ may mắn nhưng ngầm hỏi vận may còn lại bao nhiêu, khóe miệng lộ nụ cười."}],"tuViMoc":[],"nhanMach":[{"ten":"Tôn trưởng lão","tag":"ban-be","quanHe":"Lão bằng hữu từ tu chân liên minh, được mời dự đại thọ","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái."},{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Đệ tử đầu lĩnh Hoàng Hệ, được tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Hắc y nhân (mặt sẹo)","tag":"khac","quanHe":"Tu sĩ hắc y mặt sẹo trầm giọng hỏi hắn về bước thứ ba của tu đạo giữa buổi giảng.","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"khách dự đại thọ kiêm đối tượng thi triển Tiên thuật","ghiChu":"Hai cao thủ đối thoại trêu chọc nhau; Lăng Thiên Hầu lạnh lùng đồng ý làm đối tượng để Thiên Vận Tử biểu diễn Dẫn Tiên thuật."},{"ten":"Lăng Thiên Hầu","tag":"doi-thu","quanHe":"Khách dự thọ bị làm nhục","ghiChu":"Thiên Vận Tử ra tay với đệ tử Đại La Kiếm Tông của Lăng Thiên Hầu, khiến lão âm trầm trách móc nhưng đành nhẫn nhịn chờ ba ngày."},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đệ tử lão đại Hoàng hệ","ghiChu":"Thiên Vận Tử nhìn Vận Đường bằng ánh mắt thâm thuý rồi âm trầm khi lão nhường phong hiệu và lộ biểu hiện quỷ dị."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử lâu năm","ghiChu":"Nhận kỳ bảo Trần Đào dâng, cho hắn tranh phong hiệu."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử chân chính mới thu nhận","ghiChu":"Hứa truyền Cấm pháp thần thông và pháp bảo bản mạng, cho đặc ân tự chọn."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đệ tử Tử hệ","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."},{"ten":"Lăng Thiên Hầu","tag":"khac","quanHe":"Kiếm Tôn có ước hẹn","ghiChu":"Ba tháng sau phải tuyển người tiến vào Đông Hải Yêu Linh chi môn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử thứ bảy của Tử hệ","ghiChu":"Thu nhận sau khi Vương Lâm đạt ý cảnh nhập thể hai mươi bảy bước."},{"ten":"Thiên Vận Tử áo xám","tag":"khac","quanHe":"Có hứa hẹn từ trước; nhờ đó người áo xám mới truyền Sát Lục Tiên quyết cho đệ tử của Thiên Vận Tử","ghiChu":"@c0474"},{"ten":"Lăng Thiên Hậu","tag":"ban-be","quanHe":"Bạn cũ cùng thăm dò Đông Hải","ghiChu":"Sau lần thứ ba thì tách ra, giữ kín bí mật."},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bị Huyết Tổ bảy lần khiêu chiến."}],"tuiDo":{}},"nguon":["@c0461","@c0465","@c0466","@c0467","@c0468","@c0469","@c0470","@c0472","@c0473","@c0474","@c0486","@c0488","@c0489","@c0490","@c0491"]},{"id":"bach-vi","name":"Bạch Vi","cn":"","gioiTinh":"nam","trangThai":"song","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0462","importance":"normal","tieuDe":"Thái độ khó lường giữa yến tiệc","text":"Khi Vương Lâm phá vây xông vào thọ yến, mắt Bạch Vi lộ tia kỳ dị, chỉ mỉm cười khó hiểu mà ung dung uống rượu, không hề ra tay, gợi ý còn ẩn tình giữa các đệ tử Tử hệ."},{"chuong":"@c0464","importance":"normal","tieuDe":"Lộ tâm tư báo thù đại sư huynh","text":"Trên đường về Tử Vi Các, Bạch Vi lộ vẻ ác độc, lẩm bẩm trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh — nếu yêu linh thức tỉnh, đại sư huynh khôi phục bản lãnh thì hắn vĩnh viễn không báo được thù; ngoài mặt vẫn chúc mừng Vương Lâm."},{"bridge":true,"khoang":"@c0468","text":"Trong khảo nghiệm áp lực phân loại đệ tử Tử hệ, Bạch Vi kiên trì thêm một lúc rồi than thầm, rơi xuống ngồi trên mặt đất."},{"bridge":true,"khoang":"@c0469","text":"Trong cuộc tranh phong hiệu, Bạch Vi cung kính tuyên bố bỏ cuộc."},{"chuong":"@c0470","importance":"minor","tieuDe":"Nhận ra Trần Đào","text":"Đệ tử Tử hệ Bạch Vi nhận ra Trần Đào khi hắn trở về, sắc mặt không tự nhiên và im lặng."}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng phe Tử hệ; quan sát Vương Lâm trở lại với nụ cười kỳ dị","ghiChu":""},{"ten":"Đại sư huynh (Tử hệ)","tag":"doi-thu","quanHe":"Đối tượng báo thù","ghiChu":"Lo yêu linh thức tỉnh sẽ khôi phục bản lãnh đại sư huynh, hắn không báo được thù."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"Trách sư tôn bất công đã cấy yêu linh vào thân đại sư huynh."},{"ten":"Trần Đào","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Nhận ra Trần Đào, sắc mặt không tự nhiên."}],"tuiDo":{},"tuViMoc":[]},"nguon":["@c0462","@c0464","@c0468","@c0469","@c0470"]},{"id":"xich-liet","name":"Xích Liệt","cn":"","aliases":["Xích Liệt sư thúc","Lão già mặt đỏ hồng bào"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ (cao thâm)","trangThai":"song","blurb":"Sư thúc trong Thiên Vận Tông, lão già hồng bào mặt đỏ đeo hồ lô rượu; chỉ một tiếng hét đã buộc cổ yêu rút lui.","vaiTro":"Sư thúc bậc trên trong Thiên Vận Tông","tinhCach":[{"text":"Phóng khoáng, ham rượu, tiếc chén rượu dở dang hơn cả việc đệ tử đánh nhau","chuong":"@c0463"},{"text":"Nể sợ tổ sư Thiên Vận Tử","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Hóa từ một đám mây đỏ, sặc mùi rượu, mắng đệ tử đánh nhau làm dở chén rượu","chuong":"@c0463"},{"text":"Uy nghiêm trấn yêu: chỉ một tiếng hét “Nghiệt súc! Cút đi cho ta!” đã khiến cổ yêu run rẩy buông mồi","chuong":"@c0463"}],"kinhLich":[{"chuong":"@c0463","importance":"normal","tieuDe":"Xuất hiện chấm dứt trận đấu","text":"Khi cổ yêu định nuốt Hồn Thú của Vương Lâm, từ tổng tông Thiên Vận Tông vang tiếng hét của Xích Liệt buộc cổ yêu thu nhỏ rút về. Một đám mây đỏ hóa thành lão già hồng bào mặt đỏ đeo hồ lô, mắng các đệ tử đánh nhau và lo Thiên Vận Tử trách."},{"chuong":"@c0464","importance":"normal","tieuDe":"Bắt Triệu Sát Tinh trị tội","text":"Xích Liệt khẳng định yêu linh trong Triệu Sát Tinh vừa hình thành đã gượng dùng, túm hắn để sư phụ trừng phạt; tiết lộ sư phụ kỳ vọng cao ở Vương Lâm và đại sư huynh sẽ không xuất hiện tranh danh hiệu Thiên Vận Thất Tử, rồi hóa mây đỏ mang Triệu Sát Tinh bay đi."},{"chuong":"@c0464","importance":"minor","tieuDe":"Báo lịch giảng đạo","text":"Trước khi rời đi, Xích Liệt ôm quyền xin lỗi các tu sĩ tông phái và thông báo hôm sau là ngày sư huynh Thiên Vận Tử giảng đạo."}],"tuVi":"Cảnh giới chưa nêu rõ, song uy thế đủ trấn áp cổ yêu chỉ bằng một tiếng hét.","nhanMach":[{"ten":"Triệu Tinh Sát","tag":"su-mon","quanHe":"Đệ tử bậc dưới trong tông","ghiChu":"Triệu Tinh Sát tham kiến, từng gặp mấy ngàn năm trước."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Đệ tử trong tông","ghiChu":"Tiếng hét của Xích Liệt vô tình cứu Hồn Thú của Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Tổ sư mà Xích Liệt nể sợ","ghiChu":"Sợ bị Thiên Vận Tử trách phạt."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"Báo lịch giảng đạo hôm sau của sư huynh."},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đệ tử cháu (lão đại Tử hệ) bị áp giải","ghiChu":"Túm đi sau khi hắn gượng dùng yêu linh chưa luyện hóa."}],"tuiDo":{"phapBao":[{"ten":"Hồ lô lớn","loai":"vật đựng rượu","moTa":"Hồ lô lớn đeo sau lưng, đựng rượu; Xích Liệt sặc mùi rượu khi xuất hiện.","nguon":"@c0463"}]},"tuViMoc":[]},"nguon":["@c0463","@c0464"]},{"id":"khuong-thien-ton","name":"Khương Thiên Tôn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thủy Vân Môn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh Hậu Kỳ","trangThai":"song","blurb":"Trưởng lão Vấn Đỉnh Hậu Kỳ của Thủy Vân Môn; người nhận ra hư ảnh là cổ yêu trong truyền thuyết thượng cổ và gọi tên Yêu lực.","vaiTro":"Trưởng lão Thủy Vân Môn, kiến thức uyên bác về thượng cổ","tinhCach":[{"text":"Trầm tĩnh, ngồi im suốt bảy ngày quan sát","chuong":"@c0463"}],"tabs":{"diem":[{"text":"Suốt bảy ngày ngồi im, chỉ nhẹ giọng khi nhận ra cổ yêu truyền thuyết","chuong":"@c0463"}],"kinhLich":[{"chuong":"@c0463","importance":"normal","tieuDe":"Nhận ra Cổ Yêu và Yêu lực","text":"Khi hư ảnh yêu vật xuất hiện, Khương Thiên Tôn nghi đó là cổ yêu trong truyền thuyết thượng cổ và xác nhận “Rất giống”. Lúc khí tức cổ yêu vượt xa linh lực, sánh ngang tiên lực và ma hỏa của Vương Lâm, ông gọi đó là “Yêu lực”."}],"tuViMoc":[{"chuong":"@c0463","canhGioi":"Vấn Đỉnh Hậu Kỳ","text":"Ra mặt với cảnh giới Vấn Đỉnh Hậu Kỳ, một trong các Vấn Đỉnh trưởng lão hiện diện.","importance":"major"}],"nhanMach":[],"tuiDo":{}},"nguon":["@c0463"]},{"id":"nam-tu-ho-vuong-thanh-tong","name":"Nam tử họ Vương (Thanh Tông)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thanh Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Nửa bước Vấn Đỉnh","trangThai":"song","blurb":"Đệ tử Thanh Tông của Thiên Vận Tông, mặt lạnh như băng, đã bước nửa bước vào Vấn Đỉnh — vượt cả Tư Mã Như Phong.","vaiTro":"Đệ tử mạnh của Thanh Tông trong lễ giảng đạo Thiên Vận Tử","tinhCach":[{"text":"Mặt lạnh như băng, ít biểu lộ","chuong":"@c0464"}],"tabs":{"diem":[{"text":"Nửa bước Vấn Đỉnh, vượt Tư Mã Như Phong","chuong":"@c0464"}],"kinhLich":[{"chuong":"@c0464","importance":"normal","tieuDe":"Lộ diện trong lễ giảng đạo","text":"Theo đoàn Thanh Tông kính bái tổng tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm quét mắt nhận ra hắn đã bước nửa bước vào Vấn Đỉnh, vượt Tư Mã Như Phong."}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Nửa bước Vấn Đỉnh","text":"Tu vi đã bước nửa bước vào Vấn Đỉnh, vượt cả Tư Mã Như Phong Anh Biến đại viên mãn.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Cùng dự lễ giảng đạo Thiên Vận Tử","ghiChu":"Bị Vương Lâm nhận ra tu vi nửa bước Vấn Đỉnh."},{"ten":"Tư Mã Như Phong","tag":"doi-thu","quanHe":"Cùng sáu tông Thiên Vận Tông","ghiChu":"Tu vi vượt Tư Mã Như Phong."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"nguoi-trung-nien-cam-tong","name":"Người trung niên Cam Tông","cn":"","aliases":["Người đàn ông trung niên (Cam Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Cam Tông","trangThai":"gan-bo"},{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Hậu Kỳ","trangThai":"song","blurb":"Đệ tử vị trí thứ tư Cam Tông (Chanh Tông) của Thiên Vận Tông; năm xưa ở tiên giới từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ.","vaiTro":"Cao thủ Cam Tông Vương Lâm nhận ra trong lễ giảng đạo","tinhCach":[],"tabs":{"diem":[{"text":"Năm xưa đánh Sất Hổ ở tiên giới bằng Sát Khí Huyết Tinh","chuong":"@c0464"}],"kinhLich":[{"chuong":"@c0464","importance":"normal","tieuDe":"Tái xuất trong lễ giảng đạo","text":"Đứng vị trí thứ tư đoàn Cam Tông trong lễ giảng đạo Thiên Vận Tử; Vương Lâm nhận ra hắn chính là người năm xưa đánh nhau với Sất Hổ ở tiên giới, khi đó chưa tới Anh Biến nay đã đạt Anh Biến Hậu Kỳ."}],"tuViMoc":[{"chuong":"@c0464","canhGioi":"Anh Biến Hậu Kỳ","text":"Năm xưa ở tiên giới chưa tới Anh Biến, nay đã Anh Biến Hậu Kỳ.","importance":"major"}],"nhanMach":[{"ten":"Sất Hổ","tag":"doi-thu","quanHe":"Đối thủ trận đánh năm xưa ở tiên giới","ghiChu":"Từng dùng Sát Khí Huyết Tinh đánh nhau với Sất Hổ."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cùng dự lễ giảng đạo, bị nhận ra","ghiChu":"Vương Lâm nhận ra qua ký ức tiên giới."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Sát Khí Huyết Tinh","trangThai":"dang-co","moTa":"Thần thông/pháp thuật từng dùng đánh Sất Hổ ở tiên giới năm xưa.","nguon":"@c0464"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0464"]},{"id":"ton-truong-lao","name":"Tôn trưởng lão","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tu chân liên minh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (cao thủ tột bậc tiên giới)","trangThai":"song","blurb":"Cao thủ uy áp tột bậc từ tu chân liên minh, được Thiên Vận Tử mời tới dự đại thọ vạn năm với danh nghĩa lão bằng hữu.","vaiTro":"Lão bằng hữu khách quý của Thiên Vận Tử, cao thủ tu chân liên minh","tinhCach":[{"text":"Hào sảng, thân thiết suồng sã với Thiên Vận Tử, gọi đối phương là Thiên Vận lão quái và đùa cợt thoải mái.","chuong":"@c0465"},{"text":"Uy áp khủng khiếp, chỉ một ánh mắt khiến các cao thủ phải cúi đầu.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Giáng lâm bằng đạo kim quang vạn trượng ngưng tụ thành trận pháp khổng lồ, khiến mặt trời mất màu, trời đất ảm đạm.","chuong":"@c0465"},{"text":"Dáng vẻ khoảng bốn mươi tuổi, thân hình cường tráng như pho tượng chiến tiên, mặt cương nghị, mắt như có tia chớp, mặc trường bào màu tím.","chuong":"@c0465"},{"text":"Nuôi một con tiểu điêu ba mắt đậu trên vai, tốc độ nhanh hơn tia chớp vô số lần.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Giáng lâm thọ yến Thiên Vận Tử","text":"Được Thiên Vận Tử mời từ hư không, Tôn trưởng lão hiện thân giữa đại thọ vạn năm, uy áp khiến cao thủ phải cúi đầu. Hắn tặng một thanh phi kiếm trung phẩm tiên khí ngưng luyện vạn năm làm hậu lễ, rồi ngồi một bên nghe Thiên Vận Tử giảng đạo."},{"bridge":true,"khoang":"@c0466–@c0466","text":"Trưởng lão đến từ liên minh tu chân dự buổi giảng đạo; tử điêu đậu lên vai lão nhai nuốt tiên ngọc, lão mỉm cười gật đầu với Vương Lâm. Khi Thiên Vận Tử nhắc tới ‘hắn’, sắc mặt lão lập tức khó coi, hồi tưởng mang theo nhiều vẻ sợ hãi vì rõ ràng biết đó là ai."},{"bridge":true,"khoang":"@c0467","text":"Dự lễ đại thọ vạn năm, Tôn trưởng lão sắc mặt khó coi và muốn ngăn Thiên Vận Tử nhắc về “hắn” nhưng đành để lão nói; vốn quen biết Lăng Thiên Hầu nên có lời chào hỏi khi vị Kiếm Tôn xuất hiện."},{"chuong":"@c0470","importance":"minor","tieuDe":"Thẩm định kỳ bảo","text":"Tôn trưởng lão xác nhận đoá hoa Trần Đào dâng là Thất thải lưu ly quang, nhận xét hoả hậu còn kém cánh thứ bảy."}],"tuViMoc":[],"tuVi":"Cao thủ tột bậc của tu chân liên minh; thực lực không rõ cảnh giới nhưng uy áp khiến các cao thủ Thiên Vận Tông phải cúi đầu.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"ban-be","quanHe":"Lão bằng hữu, được mời dự đại thọ vạn năm","ghiChu":"Xưng hô thân mật, gọi nhau là lão quái / Thiên Vận lão quái."},{"ten":"Côn Bằng Tử","tag":"khac","quanHe":"Người được Thiên Vận Tử chuyển tặng phi kiếm của ông","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử Hệ bị tiểu điêu ba mắt của ông dò xét riêng","ghiChu":""},{"ten":"Lăng Thiên Hầu","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Lăng Thiên Hầu chào hỏi Tôn trưởng lão như người quen khi tới dự đại thọ."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"da-dung","moTa":"Trung phẩm tiên khí do Tôn trưởng lão tự ngưng luyện vạn năm, đem tặng Thiên Vận Tử làm hậu lễ thọ yến (sau đó được tặng lại Côn Bằng Tử).","nguon":"@c0465"}],"linhThu":[{"ten":"Tiểu điêu ba mắt","moTa":"Con chim toàn thân màu tím, ba mắt phát tia sáng âm u, đậu trên vai Tôn trưởng lão; tốc độ nhanh hơn tia chớp vô số lần. Trong thọ yến nó bay tới đậu vai Vương Lâm dò xét.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0466","@c0467","@c0470"]},{"id":"con-bang-tu","name":"Côn Bằng Tử","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Hoàng Hệ (Thiên Vận Tông)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Người đứng đầu Hoàng Hệ của Thiên Vận Tông, được Thiên Vận Tử tặng lại phi kiếm trung phẩm tiên khí trong thọ yến.","vaiTro":"Đầu lĩnh Hoàng Hệ Thiên Vận Tông","tinhCach":[{"text":"Trung thành, dễ xúc động trước ân điển của sư tôn; run rẩy tạ ơn khi nhận bảo vật.","chuong":"@c0465"}],"tabs":{"diem":[{"text":"Đứng đầu Hoàng Hệ, được Thiên Vận Tử ban tặng phi kiếm trung phẩm tiên khí ngay tại thọ yến.","chuong":"@c0465"}],"kinhLich":[{"chuong":"@c0465","importance":"normal","tieuDe":"Nhận phi kiếm trung phẩm tiên khí","text":"Tại đại thọ vạn năm, Thiên Vận Tử nhận thanh phi kiếm trung phẩm tiên khí của Tôn trưởng lão rồi ném tặng lại cho Côn Bằng Tử; hắn run lên xúc động, cung kính tạ ơn sư tôn."},{"chuong":"@c0469","importance":"normal","tieuDe":"Nhận phong hiệu Thiên Vận Thất tử Hoàng hệ","text":"Sau khi Vận Đường nhường ngôi và đề cử, Côn Bằng Tử (Nhị sư đệ Hoàng hệ) được Thiên Vận Tử trao tinh thể vàng — dấu hiệu phong hiệu Thiên Vận Thất tử của Hoàng hệ, hứa truyền một bản Hạ phẩm Tiên thuật đầy đủ nếu giữ phong hiệu ngàn năm và một bảo mệnh pháp bảo khi xuất quan. Hắn kích động quỳ bái nhận lời rồi vào bế quan cảm thụ tinh thể vàng."}],"tuViMoc":[],"tuVi":"Không rõ cảnh giới; là đầu lĩnh Hoàng Hệ Thiên Vận Tông.","nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư tôn / thủy tổ Thiên Vận Tông, ban tặng phi kiếm tiên khí","ghiChu":""},{"ten":"Tôn trưởng lão","tag":"an-nhan","quanHe":"Người ngưng luyện thanh phi kiếm mà hắn được nhận","ghiChu":""},{"ten":"Vận Đường","tag":"su-mon","quanHe":"Đại sư huynh Hoàng hệ","ghiChu":"Vận Đường chủ động bỏ cuộc, đề cử Côn Bằng Tử là người thích hợp nhất với phong hiệu."}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm màu vàng (trung phẩm tiên khí)","loai":"phi-kiem","trangThai":"dang-co","moTa":"Trung phẩm tiên khí do Tôn trưởng lão ngưng luyện vạn năm, được Thiên Vận Tử chuyển tặng tại thọ yến.","nguon":"@c0465"}]}},"nguon":["@c0465","@c0469"]},{"id":"hac-y-nhan-mat-seo","name":"Hắc y nhân (mặt sẹo)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Tu sĩ mặc hắc y tỏa hung khí, mặt có vết sẹo hung ác chạy từ mặt xuống cổ, hỏi Thiên Vận Tử về bước thứ ba của tu đạo.","vaiTro":"Tu sĩ bí ẩn dự buổi giảng đạo của Thiên Vận Tử.","tinhCach":[{"text":"Trầm tĩnh nhưng ẩn chứa hung khí dày đặc, khiến trong vòng mười trượng quanh thân không tu sĩ nào dám lại gần.","chuong":"@c0466"}],"tabs":{"diem":[{"text":"Quanh thân mười trượng không ai dám lại gần, hung khí cuộn trào, mặt có vết sẹo hung ác từ mặt xuống cổ.","chuong":"@c0466"}],"kinhLich":[{"chuong":"@c0466","importance":"normal","tieuDe":"Hỏi về bước thứ ba","text":"Giữa buổi giảng đạo trên tường vân, hắc y nhân trầm giọng hỏi Thiên Vận Tử về bước thứ ba của tu đạo, dẫn tới phần giải thích chữ ‘đạo’ và thiên vận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Hỏi Thiên Vận Tử về bước thứ ba của tu đạo trong buổi giảng.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466"]},{"id":"han-bi-an","name":"Hắn (nhân vật bí ẩn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Nhân vật bí ẩn Thiên Vận Tử gặp ba ngàn năm trước, khiến hắn tin có bước thứ ba của tu đạo; Tôn trưởng lão biết và lộ vẻ sợ hãi khi nhớ lại.","vaiTro":"Nhân vật cực mạnh được nhắc tới, chưa lộ diện.","tinhCach":[],"tabs":{"diem":[{"text":"Sự tồn tại đủ khiến cả Thiên Vận Tử thay đổi nhận thức về bước thứ ba và khiến Tôn trưởng lão sợ hãi.","chuong":"@c0466"}],"kinhLich":[{"chuong":"@c0466","importance":"normal","tieuDe":"Được nhắc tới","text":"Thiên Vận Tử kể rằng ba ngàn năm trước nhờ gặp ‘hắn’ mới tin có bước thứ ba của tu đạo; Tôn trưởng lão hiển nhiên biết ‘hắn’ là ai và lộ vẻ sợ hãi."},{"bridge":true,"khoang":"@c0467","text":"Được Thiên Vận Tử tiết lộ là kẻ duy nhất lão từng biết đã đạt tới bước thứ ba, từng khiến Tu Chân Liên Minh nếm đau khổ một lần duy nhất; như đoá phù dung sớm nở tối tàn, nay đã biệt tích không tung tích, danh tính bỏ ngỏ."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Người Thiên Vận Tử gặp ba ngàn năm trước, làm hắn tin có bước thứ ba.","ghiChu":""}],"tuiDo":{}},"nguon":["@c0466","@c0467"]},{"id":"lang-thien-hau","name":"Lăng Thiên Hầu","aliases":["Kiếm Tôn Lăng Thiên Hầu","Lăng Thiên Hậu","Kiếm Tôn"],"gioiTinh":"nam","tabs":{"kinhLich":[{"chuong":"@c0467","importance":"normal","tieuDe":"Kiếm Tôn cưỡi biển phi kiếm dự đại thọ","text":"Kiếm Tôn Lăng Thiên Hầu, Tông chủ Đại La Kiếm Tông trên Thiên Vận Tinh, xuất hiện cùng sấm sét và vô số kiếm quang: một lão già áo xanh râu trắng gầy gò mang khí tức thiên uy, sau lưng có bốn bóng kiếm hư ảo, dưới chân là xà hình bảo kiếm đầy máu tanh. Hắn dẫn hơn vạn đệ tử áo đen đeo kiếm cổ tới chúc thọ, chào hỏi Tôn trưởng lão và lạnh lùng đồng ý làm đối tượng cho Thiên Vận Tử thi triển Tiên thuật."},{"chuong":"@c0468","importance":"normal","tieuDe":"Đối đầu Thiên Vận Tử tại đại thọ","text":"Kiếm Tôn Lăng Thiên Hầu dẫn hơn vạn đệ tử Đại La Kiếm Tông tới chúc thọ; khi Thiên Vận Tử thi triển Dẫn Tiên thuật cuốn đệ tử đi, lão thúc xà hình phi kiếm lao lên rồi triệu Kỳ Lân thú từ mi tâm phản kích, nhưng cuối cùng nhẫn nhịn gọi kiếm tiên về, chờ ba ngày đệ tử trở về."},{"bridge":true,"khoang":"@c0469","text":"Khi Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử cho Côn Bằng Tử, Kiếm Tôn Lăng Thiên Hầu lộ một tia khinh thường."},{"chuong":"@c0470","importance":"minor","tieuDe":"Kinh ngạc trước Hồn thú","text":"Là quan khách mừng thọ, Kiếm Tôn Lăng Thiên Hầu lộ vẻ kinh ngạc khi thấy Hồn thú khổng lồ Vương Lâm triệu ra từ Xạ Thần xa."},{"chuong":"@c0472","importance":"normal","tieuDe":"Nhắc ước hẹn Đông Hải Yêu Linh chi môn","text":"Rời đại thọ sớm bằng kiếm quang; trước khi đi nhắc lại ước hẹn với Thiên Vận Tử rằng ba tháng sau lão phải tuyển người tiến vào Đông Hải Yêu Linh chi môn."},{"chuong":"@c0486","importance":"normal","tieuDe":"Cùng thăm dò Đông Hải lần ba","text":"Là người chưa bao giờ nể mặt Thiên Vận Tử nhưng vẫn cùng lập nhóm thăm dò Đông Hải; lần thứ ba vào được bên trong rồi ra chỉ còn nửa quân số, sau đó tách với Thiên Vận Tử và giữ kín chuyện đã xảy ra."},{"chuong":"@c0488","importance":"normal","tieuDe":"Ra điều kiện với Tham Lang","text":"Kiếm Tôn Lăng Thiên Hậu dò hỏi Tham Lang về hạt châu, hoãn việc đến sau Đông Hải Yêu Linh, đổi lại yêu cầu Tham Lang vào trong bảo vệ mười hai đệ tử của lão hoàn thành nhiệm vụ bí mật. Lão vạch trần tâm cơ Tham Lang đang bị người giữ hạt châu bức bách, hứa sẽ mở cửa Yêu Linh cho hắn vào."},{"bridge":true,"khoang":"@c0489","text":"Là tu sĩ kỳ cựu từng chứng kiến Đông Hải Yêu Linh, khi thủy triều khởi động hắn ánh mắt lộ tia sáng kỳ dị, lẩm bẩm “Bắt đầu rồi!”."},{"bridge":true,"khoang":"@c0490","text":"Hai mắt tuôn tinh quang khó tưởng tượng, nhìn chằm chằm vào con sóng hồng quang cuối; phải biến sắc trước sự quỷ dị của thủy triều bảo vật cửa Đông Hải Yêu Linh."},{"chuong":"@c0491","importance":"normal","tieuDe":"Mở cánh cửa Đông Hải yêu linh","text":"Chỉ tay về Đông Hải, bốn kiếm ảnh hư ảo sau lưng hóa bốn đạo cầu vồng đánh vào khối nước khổng lồ lơ lửng, mở ra lối vào hỗn độn xanh đỏ dẫn tới một thế giới khác, hô gọi chúng tu sĩ tiến vào rồi thu kiếm đóng cửa."},{"chuong":"@c0491","importance":"normal","tieuDe":"Về Đại La tinh bế quan luyện yêu kiếm","text":"Tiết lộ Đại La kiếm tông đặt ở Đại La tinh do hắn đưa từ tinh không tới; phá cương phong vào đông bộ bế quan, quyết trong hai trăm năm lấy chín chín yêu linh quy nhất luyện Tiên kiếm thành yêu kiếm để chắc tay thu lệnh bài Đông Hải."}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"đồng cấp/đối thủ thực lực","ghiChu":"Tu vi và thực lực môn phái của hai bên gần tương đương; Lăng Thiên Hầu đồng ý làm đối tượng cho Thiên Vận Tử thi triển Dẫn Tiên thuật."},{"ten":"Tôn trưởng lão","tag":"dong-minh","quanHe":"quen biết","ghiChu":"Chào hỏi Tôn trưởng lão khi tới dự đại thọ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"ân oán tiềm ẩn","ghiChu":"Vương Lâm nhận ra thanh xà hình bảo kiếm của Lăng Thiên Hầu là Vũ chi đệ nhị kiếm bị cướp ở Tiên giới năm xưa."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Chủ nhân đại thọ làm nhục mình","ghiChu":"Thiên Vận Tử cuốn đi đệ tử Đại La Kiếm Tông của lão; Lăng Thiên Hầu trách móc nhưng biết thân phận đối phương nên đành chờ ba ngày."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Đệ tử Tử hệ trong đám đông","ghiChu":"Kỳ Lân thú của Lăng Thiên Hầu cộng hưởng tiếng gầm với Tôn Hồn Phiên trong người Vương Lâm."},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Đại lão có ước hẹn","ghiChu":"Ước hẹn Đông Hải Yêu Linh chi môn."},{"ten":"Thiên Vận Tử","tag":"ban-be","quanHe":"Bạn cũ cùng thăm dò Đông Hải","ghiChu":"Sau lần thứ ba thì tách ra."},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Cố nhân tới cầu nhờ","ghiChu":"Tham Lang chạy đường xa đến Thiên Vận Tinh tìm lão; Lăng Thiên Hậu ra điều kiện đổi lấy việc giúp hắn."}],"tuiDo":{"phapBao":[{"ten":"Vũ chi đệ nhị kiếm","tenCu":"Xà hình bảo kiếm","trangThai":"dang-co","moTa":"Bảo kiếm hình con rắn đầy máu tanh dưới chân Lăng Thiên Hầu, tế luyện bằng phương pháp khiến người nhìn tâm thần đại chấn; chính là Vũ chi đệ nhị kiếm hắn cướp ở Tiên giới năm đó.","nguon":"@c0467"}]},"tuViMoc":[]},"nguon":["@c0467","@c0468","@c0469","@c0470","@c0472","@c0486","@c0488","@c0489","@c0490","@c0491"]},{"id":"lao-tam-hoang-he-thien-van","name":"Lão Tam (Hoàng hệ)","gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"trangThai":"mat-tich","blurb":"Đệ tử Hoàng hệ của Thiên Vận Tử, ba mươi năm trước từng đạt phong hiệu Thiên Vận Thất tử rồi mất tích thần bí khi ra tinh không.","vaiTro":"Nhân vật được nhắc tên","tabs":{"diem":[{"text":"Từng mang phong hiệu Thiên Vận Thất tử nhưng một lần ra tinh không thì bặt vô âm tín cho tới nay","chuong":"@c0468"}],"kinhLich":[{"chuong":"@c0468","importance":"minor","tieuDe":"Mất tích ở tinh không","text":"Ba mươi năm trước, lão Tam Hoàng hệ đạt phong hiệu Thiên Vận Thất tử, nhưng trong một lần ra tinh không thì mất tích thần bí, đến nay vẫn bặt tin."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Thiên Vận Tử nhắc tới lão Tam khi tuyên bố tranh đoạt phong hiệu Thiên Vận Thất tử cho Hoàng hệ và Tử hệ."}],"tuiDo":{}},"nguon":["@c0468"]},{"id":"van-duong","name":"Vận Đường","aliases":["Đại sư huynh Hoàng hệ","Lão đại Hoàng hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Hoàng hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không rõ","trangThai":"song","blurb":"Lão đại Hoàng hệ, dung mạo xấu xí nhiều nếp nhăn; từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt, tính nhàn nhã không tranh đoạt nhưng ẩn giấu điều quỷ dị.","vaiTro":"Đại sư huynh Hoàng hệ, người chủ động nhường phong hiệu nhưng để lộ biểu hiện bí ẩn khiến Vương Lâm và Thiên Vận Tử để ý.","tinhCach":[{"text":"Nhàn nhã, không có tâm tranh đoạt, chỉ thích tu luyện thong dong","chuong":"@c0469"},{"text":"Ẩn giấu điều quỷ dị — mắt co rút và lộ vẻ sợ hãi khi tinh thể vàng xuất hiện","chuong":"@c0469"}],"tabs":{"diem":[{"text":"Từng làm Thiên Vận Thất tử hơn 800 năm rồi bị lão Tam đoạt mất","chuong":"@c0469"},{"text":"Theo Thiên Vận Tử trước cả Côn Bằng Tử (hơn 2000 năm), tính tình quái gỡ không tiếp xúc người khác","chuong":"@c0469"}],"kinhLich":[{"chuong":"@c0469","importance":"normal","tieuDe":"Nhường phong hiệu, đề cử Côn Bằng Tử","text":"Trong cuộc tranh phong hiệu Hoàng hệ, Vận Đường — chỉ còn lại cùng Côn Bằng Tử — cung kính xin bỏ cuộc, tự nhận không có tâm tranh đoạt và đề cử Nhị sư đệ Côn Bằng Tử là người thích hợp nhất với phong hiệu. Khi tinh thể vàng từ mi tâm Thiên Vận Tử bay ra, hai mắt lão co rút rồi lập tức bình tĩnh; bị Vương Lâm nhìn lâu, lão ngẩng đầu quét mắt rồi khoé miệng mỉm cười, sau lại run sợ trước ánh mắt âm trầm của Thiên Vận Tử."}],"tuViMoc":[],"tuVi":"Tu vi chưa rõ; che giấu rất giỏi, từng đủ sức làm Thiên Vận Thất tử Hoàng hệ hơn 800 năm.","nhanMach":[{"ten":"Côn Bằng Tử","tag":"su-mon","quanHe":"Nhị sư đệ Hoàng hệ","ghiChu":"Vận Đường nhường phong hiệu, đề cử Côn Bằng Tử."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Bị Thiên Vận Tử nhìn bằng ánh mắt âm trầm khiến run lòng cúi đầu."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Sư đệ đồng môn (Lão Thất)","ghiChu":"Vương Lâm phát hiện biểu hiện quỷ dị của lão; ánh mắt sợ hãi của lão khiến Vương Lâm do dự bỏ cuộc."}],"tuiDo":{}},"nguon":["@c0469"]},{"id":"tran-dao","name":"Trần Đào","aliases":["Tử hệ Lão Lục","Lão Lục"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"},{"ten":"Tử hệ","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh kỳ","trangThai":"song","blurb":"Tử hệ Lão Lục, đệ tử lâu năm của Thiên Vận Tử, từng đạt phong hiệu Thiên Vận Thất tử trước thời Tôn Vân; trở về đòi tranh lại phong hiệu.","vaiTro":"Đệ tử kỳ cựu Tử hệ trở về tranh phong hiệu, đối thủ mới của Vương Lâm trong tiệc đại thọ.","tinhCach":[{"text":"Kiêu ngạo, khinh thường Vương Lâm, chỉ thừa nhận Tôn Vân mới là Thất sư đệ thật.","chuong":"@c0470"},{"text":"Hiếu chiến, hứng thú trước cường địch — xé áo lộ nửa thân, rút trường thằng nghênh chiến.","chuong":"@c0470"}],"tabs":{"diem":[{"text":"Từng đạt phong hiệu Thiên Vận Thất tử trước Tôn Vân, năm xưa thua Tôn Vân rồi rời tông ra tinh ngoại rèn luyện.","chuong":"@c0470"}],"kinhLich":[{"chuong":"@c0470","importance":"normal","tieuDe":"Trở về dâng kỳ bảo đòi phong hiệu","text":"Một đạo tử khí xông tới hiện ra Trần Đào, dâng cho Thiên Vận Tử đoá Thất thải lưu ly quang cướp được ở Hắc Mặc Tinh — thiên địa kỳ bảo xếp thứ 93 Tu Chân Liên Minh. Hắn đòi lại phong hiệu Thiên Vận Thất tử; khi Triệu Hân Mộng truyền âm về Tôn Vân, hắn biến sắc."},{"chuong":"@c0470","importance":"normal","tieuDe":"Giao chiến Vương Lâm","text":"Trần Đào (Vấn Đỉnh) đánh ấn quyết chấn nhiếp nhưng chỉ đẩy lùi Vương Lâm mười trượng nên kinh ngạc; hắn đẩy ngũ chuyển kim tiên lực của Vương Lâm lên cửu chuyển phản công, rồi nổ tan đòn nuốt của Hồn thú khiến quần áo rách bươm. Hứng thú trước cường địch, hắn xé áo lộ nửa thân, rút ra trường thằng đen như sợi gân sinh vật toả khí tức hoang dã (trận chưa dứt)."},{"chuong":"@c0471","importance":"normal","tieuDe":"Khốn Hồn thú bằng Long cân","text":"Trần Đào khoe Long cân rút từ xác một con yêu long ở Yêu Tinh, vung từ góc độ khó tin buộc lấy cổ Hồn thú của Vương Lâm rồi đứng trên đầu nó siết chặt khống chế."},{"chuong":"@c0471","importance":"normal","tieuDe":"Khẩu chiến và tấn công Vương Lâm","text":"Sau khi Vương Lâm mở phong ấn Xạ Thần xa khiến Hồn thú phản công, Trần Đào dựng tử sắc quang cầu phòng ngự nhưng vẫn bị tổn thương; hắn mỉa mai Vương Lâm “có tư cách làm sư đệ”, bị phản bác, rồi hóa tàn ảnh lao tới tấn công."},{"chuong":"@c0472","importance":"normal","tieuDe":"Thắng Vương Lâm đoạt phong hiệu","text":"Đỡ được hai đạo Hoàng tuyền chỉ của Vương Lâm nhờ trước khi trở về có kỳ ngộ đạt Vấn Đỉnh trung kỳ, thừa nhận một chỉ này vượt ngoài dự liệu. Thắng trận nên được Thiên Vận Tử trao phong hiệu Thiên Vận Thất tử của Tử hệ; lão điểm mi tâm đưa cảm ngộ phong hiệu vào người hắn."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Lão lục Trần Đào, đệ tử Tử hệ mặc áo tím uy áp như kiếm sắc, sốt ruột chờ Vương Lâm tới cửa Đông Hải; khi thấy thân ảnh tử sắc thì mừng thầm gọi “Lão Thất”, rồi nhìn Vương Lâm bằng ánh mắt kỳ dị."}],"tuViMoc":[{"chuong":"@c0470","canhGioi":"Vấn Đỉnh kỳ","text":"Trần Đào tu vi Vấn Đỉnh, đủ sức đẩy kim tiên lực lên cửu chuyển.","importance":"minor"},{"chuong":"@c0472","canhGioi":"Vấn Đỉnh trung kỳ","text":"Trước khi trở về tham dự đại thọ, nhờ một kỳ ngộ mà đạt tới Vấn Đỉnh trung kỳ, đủ sức đỡ Hoàng tuyền chỉ của Vương Lâm.","importance":"major"}],"nhanMach":[{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Sư phụ","ghiChu":"Đệ tử lâu năm, dâng kỳ bảo mừng đại thọ vạn năm của sư phụ."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Tranh phong hiệu Thiên Vận Thất tử","ghiChu":"Khinh thường rồi giao chiến với Vương Lâm."},{"ten":"Tôn Vân","tag":"doi-thu","quanHe":"Người từng đoạt phong hiệu của hắn","ghiChu":"Năm xưa thua Tôn Vân; thừa nhận Tôn Vân mới là Thất sư đệ thật."},{"ten":"Triệu Hân Mộng","tag":"su-mon","quanHe":"Đồng môn Tử hệ","ghiChu":"Triệu Hân Mộng truyền âm về Tôn Vân khiến hắn biến sắc."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ tại lễ chúc thọ","ghiChu":"Trần Đào (Vấn Đỉnh kỳ) tự xưng sư huynh, giao chiến với Vương Lâm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư huynh đệ Tử hệ kiêm đối thủ","ghiChu":"Hẹn tái chiến với Vương Lâm sau khi đối phương đạt Vấn Đỉnh."},{"ten":"Thiên Vận Tử","tag":"su-mon","quanHe":"Trưởng bối Thiên Vận Tông","ghiChu":"Trao phong hiệu Thiên Vận Thất tử."}],"tuiDo":{"phapBao":[{"ten":"Trường thằng đen","trangThai":"dang-co","moTa":"Sợi dây như gân sinh vật rút ra từ thân, toả khí tức hoang dã, dùng đối phó Hồn thú.","nguon":"@c0470"}],"khac":[{"ten":"Thất thải lưu ly quang","moTa":"Đoá hoa kỳ bảo cướp ở Hắc Mặc Tinh, dâng cho Thiên Vận Tử.","trangThai":"da-dung","nguon":"@c0470"}]}},"nguon":["@c0470","@c0471","@c0472","@c0488"]},{"id":"lao-gia-mat-do-ho-lo-do","name":"Lão già mặt đỏ (mang hồ lô đỏ)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"khong-ro","trangThai":"song","blurb":"Vị khách lạ mặt đỏ mang hồ lô đỏ lớn đến lễ chúc thọ, vừa uống rượu vừa nhận ra Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của một “người điên” lão từng gặp.","vaiTro":"Nhân vật bí ẩn quan khán tại lễ chúc thọ","tinhCach":[{"text":"Phóng khoáng, mê rượu","chuong":"@c0471"}],"tabs":{"diem":[{"text":"Nhận ra mối liên hệ giữa sát chiêu Hoàng tuyền chỉ và một “lão quái / người điên” lão từng gặp thuở mới đến nơi này","chuong":"@c0471"}],"kinhLich":[{"chuong":"@c0471","importance":"normal","tieuDe":"Khách chúc thọ nhận ra sát chiêu","text":"Lão già mặt đỏ mang hồ lô đỏ đến chúc thọ, vừa uống rượu vừa ngạc nhiên khi thấy Hoàng tuyền chỉ của Vương Lâm giống hệt sát chiêu của “người điên kia” mà lão từng gặp khi mới tới nơi này; danh tính lão chưa lộ."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Quan khán nhận ra sát chiêu","ghiChu":"Thấy Hoàng tuyền chỉ của Vương Lâm giống sát chiêu một nhân vật bí ẩn lão từng gặp."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0471"]},{"id":"thien-van-tu-ao-xam","name":"Thiên Vận Tử áo xám","aliases":["Người áo xám","Hơn một người"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Không rõ (siêu việt Vấn Đỉnh)","trangThai":"khong-ro","blurb":"Một Thiên Vận Tử mặc áo bào màu tro, mắt xám, trẻ tuổi hơn các Thiên Vận Tử khác — là người ‘hơn một người’ (thứ 3601) trong thế giới bảy màu, nắm giữ Sát Lục Tiên quyết.","vaiTro":"Nhân vật bí ẩn xuất hiện trong tâm thần Thiên Vận Tử, mời truyền Sát Lục Tiên quyết cho Vương Lâm.","tinhCach":[{"text":"Lạnh lùng, sát khí cực mạnh — chỉ một chữ làm sụp phong ấn của 3600 Thiên Vận Tử","chuong":"@c0474"},{"text":"Kỳ dị, kiêng kỵ con số bảy","chuong":"@c0474"}],"tabs":{"diem":[{"text":"Là ‘hơn một người’ — thực thể thứ 3601 trong thế giới bảy màu, không có tiên lực dao động, mọi công kích xuyên qua như ảo ảnh","chuong":"@c0474"},{"text":"Sát khí mạnh nhất Vương Lâm từng gặp; một chữ ‘Cút!’ đẩy lui 3600 Thiên Vận Tử mấy vạn dặm","chuong":"@c0474"},{"text":"Nắm giữ Sát Lục Tiên quyết, thân được hàng tỷ Sinh chi lạc ấn thủ hộ","chuong":"@c0474"}],"kinhLich":[{"chuong":"@c0474","importance":"normal","tieuDe":"Lộ diện ‘hơn một người’ trong thế giới bảy màu","text":"Khi Vương Lâm vào thế giới bảy màu chọn thần thông, người áo xám ngồi thổ nạp bất động giữa 3600 Thiên Vận Tử. Sát khí của lão khiến cả 3600 Thiên Vận Tử hô ‘Phong!’ phong ấn, nhưng một chữ ‘Cút!’ làm phong ấn sụp đổ, để lộ tổng số 3601 — hơn một người."},{"chuong":"@c0474","importance":"normal","tieuDe":"Mời truyền Sát Lục Tiên quyết","text":"Sau sáu lần chạm mặt, người áo xám hỏi Vương Lâm có phải đệ tử Thiên Vận Tử, tiết lộ lão được đưa tới vì Sát Lục Tiên quyết, ra điều kiện ‘không lưu người sống’. Khi Vương Lâm từ chối, lão không đáp câu hỏi về quan hệ với sư phụ, hoá một ngọc giản từ bụi khí để lại rồi biến mất."}],"tuVi":"Cảnh giới chưa nói rõ nhưng siêu việt Vấn Đỉnh; thân được hàng tỷ Sinh chi lạc ấn thủ hộ, dù Thiên Vận Tinh sụp đổ cũng bình yên vô sự.","nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Người thứ sáu được đưa tới; được mời truyền Sát Lục Tiên quyết nhưng từ chối, vẫn được để lại ngọc giản","ghiChu":"@c0474"},{"ten":"Thiên Vận Tử","tag":"khac","quanHe":"Có hứa hẹn từ trước nên mới chịu truyền cho đệ tử của Thiên Vận Tử; quan hệ cụ thể chưa tiết lộ","ghiChu":"@c0474"}],"tuiDo":{"congPhap":[{"ten":"Sát Lục Tiên quyết","trangThai":"dang-co","moTa":"Tiên quyết bắt chước từ một loại Tiên thuật vô danh, dựa vào giết chóc đoạt sinh lực ngưng kết Sinh chi lạc ấn phòng thủ.","nguon":"@c0474"}]}},"nguon":["@c0474"]},{"id":"hua-van-son","name":"Hứa Vân Sơn","cn":"","aliases":["Thiếu Tông Huyền Uyên Phái"],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến Trung kỳ","trangThai":"song","blurb":"Thiếu Tông của Huyền Uyên Phái trên Địa Tinh, chủ động ra đón và kết giao với Vương Lâm.","vaiTro":"Thiếu Tông Huyền Uyên Phái, người dẫn dắt Vương Lâm khi tới Địa Tinh và đưa hắn nhậm chức sứ giả Linh Nhạc quốc.","tinhCach":[{"text":"Tinh ý, biết nhìn xa, chủ động kết giao với người có tiềm lực lớn","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Cầm bảo phiến ngọc bích, phong thái ung dung của một Thiếu Tông","chuong":"@c0476"},{"text":"Khi biết sứ giả mới là Tử hệ Lão Thất Vương Lâm thì rung động muốn kết giao sớm","chuong":"@c0476"}],"kinhLich":[{"chuong":"@c0476","importance":"normal","tieuDe":"Nghênh đón sứ giả Tử hệ","text":"Ba ngày trước biết tin từ một bằng hữu Thiên Vận Tông rằng có người Tử hệ sẽ tới Địa Tinh làm sứ giả Linh Nhạc quốc; khi biết đó là Vương Lâm — đệ tử mới của Thiên Vận Tử — hắn cầm bảo phiến ngọc bích cùng mấy Trưởng lão tóc bạc ra Truyền tống trận chờ đón, ôm quyền xưng Thiếu tông và mời với tư cách chủ nhà."},{"bridge":true,"khoang":"@c0476–@c0476","text":"Sau hai ngày quan hệ đã hoà hợp, Hứa Vân Sơn đưa Vương Lâm tới Linh Nhạc quốc nhận chức sứ giả."},{"bridge":true,"khoang":"@c0477","text":"Cùng Vương Lâm bay tới Linh Nhạc quốc đưa hắn nhậm chức Sứ giả, cười cáo từ gọi Vương Lâm là Vương huynh, hẹn ngày sau uống rượu rồi hóa sét bay đi."}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Anh Biến Trung kỳ","text":"Tu vi ngang hàng Vương Lâm khi gặp mặt.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ động ra đón và kết giao, làm chủ nhà dẫn Vương Lâm tới Linh Nhạc quốc"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Đưa Vương Lâm đến nhậm chức Sứ giả Huyền Uyên Phái, xưng hô thân thiết","ghiChu":"@c0477"}],"tuiDo":{"phapBao":[{"ten":"Bảo phiến ngọc bích","moTa":"Cây quạt gấp màu ngọc bích Hứa Vân Sơn cầm khi ra đón Vương Lâm.","nguon":"@c0476"}]}},"nguon":["@c0476","@c0477"]},{"id":"trieu-tu","name":"Triệu Tứ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Hoá Thần (hướng tới hậu kỳ)","trangThai":"song","blurb":"Tu sĩ Huyền Uyên Phái vận hành Truyền tống trận, người tiễn Vương Lâm tới Địa Tinh.","vaiTro":"Tu sĩ trông coi và kích hoạt Truyền tống trận của Huyền Uyên Phái.","tinhCach":[{"text":"Hâm mộ kẻ mạnh, chuyên tâm tu luyện","chuong":"@c0476"}],"tabs":{"diem":[{"text":"Kính gọi Vương Lâm là “Tử hệ Thất sư tổ”, hâm mộ nhìn theo sau khi tiễn","chuong":"@c0476"}],"kinhLich":[{"chuong":"@c0476","importance":"normal","tieuDe":"Kích hoạt Truyền tống trận tiễn Vương Lâm","text":"Triệu Tứ kết quyết đánh một đạo thanh quang vào Truyền tống trận mười dặm, khiến toàn trận chấn động và truyền Vương Lâm rời đi; sau đó hắn lẩm bẩm không biết Thất sư tổ tới Địa Tinh làm gì rồi khoanh chân thổ nạp, quyết sớm đạt Hoá Thần hậu kỳ."}],"tuViMoc":[{"chuong":"@c0476","canhGioi":"Hoá Thần","text":"Đang tu luyện hướng tới Hoá Thần hậu kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Vận hành Truyền tống trận tiễn Vương Lâm tới Địa Tinh, kính gọi là Thất sư tổ"}]},"nguon":["@c0476"]},{"id":"lao-to-huyen-minh","name":"Lão Tổ Huyền Minh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vượt Vấn Đỉnh","trangThai":"song","blurb":"Lão Tổ đứng đầu Huyền Uyên Phái trên Địa Tinh, tu vi vượt quá Vấn Đỉnh.","vaiTro":"Người đứng đầu Huyền Uyên Phái, thế lực tu chân mạnh nhất Địa Tinh.","tinhCach":[],"tabs":{"diem":[{"text":"Tu vi vượt quá Vấn Đỉnh, là chỗ dựa của Huyền Uyên Phái","chuong":"@c0476"}],"kinhLich":[{"bridge":true,"khoang":"@c0476–@c0476","text":"Được nhắc tới là Lão Tổ đứng đầu Huyền Uyên Phái — Lục cấp tu chân quốc duy nhất trên Địa Tinh, tu vi vượt quá Vấn Đỉnh."}],"nhanMach":[]},"nguon":["@c0476"]},{"id":"thien-thai-lao-nhan","name":"Thiên Thai lão nhân","cn":"","aliases":["Lão nhân tóc bạc trắng","Cao thủ đệ nhất Linh Nhạc quốc"],"gioiTinh":"nam","theLuc":[{"ten":"Linh Nhạc quốc","trangThai":"gan-bo"},{"ten":"Ngũ Linh Sơn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến hậu kỳ đại viên mãn (một chân vào Vấn Đỉnh)","trangThai":"song","blurb":"Cao thủ đệ nhất Linh Nhạc quốc, lão nhân tóc bạc ở Ngũ Linh Sơn, tu vi gần chạm cảnh giới Vấn Đỉnh.","vaiTro":"Tu sĩ mạnh nhất Linh Nhạc quốc; sau khi thăm dò Vương Lâm và thấy Khuất thú thì khiếp sợ, hạ lệnh lập cấm địa quanh Thông Thiên tháp.","tinhCach":[{"text":"Điềm tĩnh, thận trọng, biết tiến thoái","chuong":"@c0477"}],"tabs":{"diem":[{"text":"Tu vi cao nhất Linh Nhạc quốc, đã đặt một chân vào cảnh giới Vấn Đỉnh","chuong":"@c0477"},{"text":"Hấp thu thái âm lực thổ nạp trên đỉnh Ngũ Linh Sơn","chuong":"@c0477"}],"kinhLich":[{"chuong":"@c0477","importance":"normal","tieuDe":"Thăm dò Vương Lâm, lập cấm địa","text":"Là cao thủ đệ nhất Linh Nhạc quốc, lão nhân đến Thông Thiên tháp thăm dò vị tân Sứ giả. Ba ngày sau trở về với sắc mặt cực kỳ khó coi, mắt hiện vẻ khiếp sợ vì tận mắt thấy Khuất thú; các tông phái liền truyền lệnh cấm đệ tử bước vào phạm vi ngàn dặm quanh tháp."},{"chuong":"@c0477","importance":"normal","tieuDe":"Ra mắt Sứ giả tại Ngũ Linh Sơn","text":"Lão đang ngồi khoanh chân trên đỉnh Ngũ Linh Sơn hấp thu thái âm lực thì Vương Lâm tìm đến. Lão mở mắt bình tĩnh nói ra mắt Sứ giả đại nhân, Vương Lâm ôm quyền đáp lời."},{"bridge":true,"khoang":"@c0478","text":"Tự trách vì để lão đạo phá quy củ tiến vào phạm vi ngàn dặm quanh Thông Thiên Tháp, kinh động Khuất thú khiến Vương Lâm không thu phục được; cung kính trao Vương Lâm ngọc giản ghi ba chỗ yêu thú tụ tập, nhận ra giữa mi tâm hắn ẩn sát khí và đoán hắn đi vì giết chóc."}],"tuViMoc":[{"chuong":"@c0477","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tu vi cao nhất Linh Nhạc quốc, gần như đặt một chân vào cảnh giới Vấn Đỉnh.","importance":"major"}],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tân Sứ giả Huyền Uyên Phái mà lão thăm dò rồi khiếp sợ; cuối chương Vương Lâm tìm đến lão tại Ngũ Linh Sơn","ghiChu":"@c0477"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Tôn xưng Sứ giả đại nhân, phục vụ và trao ngọc giản","ghiChu":""}],"tuiDo":{}},"nguon":["@c0477","@c0478"]},{"id":"quach-ta-dat","name":"Quách Tà Dật","aliases":["Quách đại sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Lục đại đệ tử Đại La Kiếm Tông, đại sư huynh của nhóm năm người tới Địa Ma Bắc Giới.","vaiTro":"Đệ tử kiếm tu Đại La Kiếm Tông","tinhCach":[{"text":"Khéo léo, dùng thủ đoạn mượn danh sư môn để chiếm lợi","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Mượn danh Đại La Kiếm Tông và lời mời trợ trận để chiếm Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Dẫn nhóm tới Địa Ma Bắc Giới","text":"Trung tuần mặc trường sam trắng xanh đeo trường kiếm cổ, làm đại sư huynh nhóm năm người, bảo chờ Sư bá rồi mới tiến vào; mâu thuẫn với Thiên Cầm cô nương về Diệu Kim quả, rồi cung kính tham kiến lão sư thúc Hoá Thần hậu kỳ và quỳ một gối ra mắt hai Kiếm Các Trưởng lão."},{"chuong":"@c0479","importance":"normal","tieuDe":"Khai báo việc phát hiện Diệu Kim quả","text":"Là tu sĩ Đại La Kiếm Tông, Quách Tà Dật khai với hai Trưởng lão về việc sư môn Thiên Cầm phát hiện Diệu Kim quả, chỉ về phía nàng và cầu xin cho nàng một quả sau khi thu được. Sau đó hắn ân cần bắt chuyện muốn hàn gắn với Thiên Cầm."},{"chuong":"@c0481","importance":"normal","tieuDe":"Dựng cục hại sư huynh Thiên Cầm","text":"Là kẻ dựng nên việc đẩy sư huynh Thiên Cầm vào sơn cốc Cửu Lê trùng; nắm chặt bảo kiếm trong tay áo, lóe sát khí về phía Thiên Cầm và thừa nhận hai bên đã kết thù."},{"chuong":"@c0483","importance":"normal","tieuDe":"Bị Thạch Phương đoạt xá","text":"Nguyên thần ly thể Thạch Phương lao tới, xuyên liễu diệp phi kiếm qua mi tâm Quách Tà Dật mà đoạt xá siêu tốc, chiếm lấy thân thể hắn; sau đó thân xác cùng chung số phận nổ tung khi Vương Lâm giết Thạch Phương."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan trở lên","text":"Đại đệ tử dẫn đầu nhóm, tu vi cao hơn các sư đệ sư muội Kết Đan","importance":"minor"}],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Được nàng mời trợ trận nhưng chiếm Diệu Kim quả, bị nàng căm hận","ghiChu":""},{"ten":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","tag":"su-mon","quanHe":"Sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""},{"ten":"Thiên Cầm cô nương","tag":"khac","quanHe":"Người hắn khai ra rồi muốn hàn gắn","ghiChu":"Hắn khiến nàng bị ép dẫn đường rồi xin cho nàng một quả, sau ân cần bắt chuyện."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Tra hỏi hắn và đồng ý cho Thiên Cầm một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"su-mon","quanHe":"Trưởng lão tông môn","ghiChu":"Hỏi hắn số lượng Diệu Kim quả."},{"ten":"Thiên Cầm","tag":"doi-thu","quanHe":"Kết thù sau khi hại chết sư huynh nàng","ghiChu":"@c0481"},{"ten":"Lữ Tùng Nghĩa","tag":"su-mon","quanHe":"Sư thúc, lão già Hóa Thần kỳ đi cùng","ghiChu":"@c0481"},{"ten":"Nữ tử (sư muội Quách Tà Dật)","tag":"su-mon","quanHe":"Sư muội đi cùng, gọi hắn là sư huynh","ghiChu":"@c0481"},{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Bị trưởng lão Thạch Phương đoạt xá, mất thân xác.","ghiChu":"@c0483"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0481","@c0483"]},{"id":"thien-cam-co-nuong","name":"Thiên Cầm cô nương","gioiTinh":"nu","theLuc":[],"trangThai":"song","blurb":"Nữ tử xinh đẹp mời Quách Tà Dật trợ trận nhưng bị hắn mượn danh sư môn chiếm Diệu Kim quả.","vaiTro":"Nữ tu tranh chấp Diệu Kim quả","tinhCach":[{"text":"Đầy thù hận, thẳng thắn mắng kẻ dùng thủ đoạn đê tiện","chuong":"@c0478"}],"tabs":{"diem":[{"text":"Căm hận Quách Tà Dật vì bị chiếm đoạt Diệu Kim quả","chuong":"@c0478"}],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Tranh chấp Diệu Kim quả","text":"Mặc quần lụa trắng thắt nơ bướm tơ tằm, mắng Quách Tà Dật mượn danh Đại La Kiếm Tông dùng thủ đoạn đê tiện; được hắn hứa để lại một quả Diệu Kim quả mang về sư môn."},{"chuong":"@c0479","importance":"normal","tieuDe":"Bị ép dẫn đường vào Địa Ma Bắc Giới","text":"Bị Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả, Thiên Cầm bị hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông ép dẫn đường vào Địa Ma Bắc Giới. Nội tâm chua xót hận Quách Tà Dật phản bội, nhưng vì khí tức hai Trưởng lão vượt xa sư môn nhỏ bé của nàng, nàng đành cắn răng cam chịu, chỉ mong đạt được một Diệu Kim quả."},{"bridge":true,"khoang":"@c0480","text":"Dẫn đường cho đoàn Đại La Kiếm Tông tới sơn cốc nơi sư môn vãn bối phát hiện Diệu Kim quả hai tháng trước, rồi lui về sau; bị lão già Hoá Thần kỳ liếc nhìn thân thể với quang mang kỳ lạ."},{"chuong":"@c0481","importance":"normal","tieuDe":"Mất sư huynh trong sơn cốc","text":"Chứng kiến sư huynh áo trắng bị Cửu Lê trùng chui vào cơ thể ăn thịt đến chết, nàng chấn động gặng hỏi tiền bối vì sao, nở nụ cười thê thảm rồi chuyển sang bình tĩnh đáng sợ."},{"chuong":"@c0483","importance":"normal","tieuDe":"Quỳ cầu Vương Lâm","text":"Thiên Cầm run rẩy quỳ xin Vương Lâm giết Thạch Phương và Trưởng lão Đại La Kiếm Tông đang bỏ chạy, nguyện làm trâu ngựa hầu hạ. Vẫn là xử nữ nên từng bị Thạch Phương định mượn thân để chữa thương; than rằng sư môn tốn công biết sơn cốc có Diệu Kim quả nhưng cục diện đã đổi khác khi Vương Lâm xuất hiện."},{"chuong":"@c0484","importance":"normal","tieuDe":"Chứng kiến luyện kim linh căn","text":"Quan khán Vương Lâm hành sự, ban đầu ngỡ hắn bố trí trận pháp, sau đau lòng như rỉ máu khi thấy Diệu Kim quả héo rũ. Cuối cùng nàng vỡ lẽ giá trị thật của Diệu Kim quả nằm ở gốc rễ, theo bản năng tiếp lấy sợi kim linh căn Vương Lâm tặng rồi về bên đồng môn, hoá cầu vồng rời đi."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Mời trợ trận nhưng bị chiếm Diệu Kim quả, sinh thù hận","ghiChu":""},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Từng tin tưởng, nay hận vì bị phản bội","ghiChu":"Quách Tà Dật khai ra việc sư môn nàng phát hiện Diệu Kim quả khiến nàng bị ép dẫn đường; sau đó hắn ân cần muốn hàn gắn nhưng nàng càng chua xót."},{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Kẻ ép nàng dẫn đường","ghiChu":"Đồng ý cho nàng một quả sau khi thu được, ra lệnh dẫn đường."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Đồng môn tức giận thay nàng nhưng bị nàng quát im."},{"ten":"Nam tử áo trắng (đồng môn Thiên Cầm)","tag":"su-mon","quanHe":"Sư huynh, bị hại chết trong sơn cốc","ghiChu":"@c0481"},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Kẻ dựng cục đẩy sư huynh nàng vào cốc, kết thù","ghiChu":"@c0481"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Quỳ cầu Vương Lâm cứu mạng, nguyện làm trâu ngựa hầu hạ.","ghiChu":"@c0483"},{"ten":"Thạch Phương","tag":"su-mon","quanHe":"Trưởng lão sư môn định mượn thân xử nữ của nàng để chữa thương.","ghiChu":"@c0483"},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Được Vương Lâm tặng một sợi kim linh căn coi như đền lại cơ duyên Diệu Kim quả đã bị chiếm.","ghiChu":"@c0484"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0479","@c0480","@c0481","@c0483","@c0484"]},{"id":"lao-gia-hoa-than-su-thuc-quach-ta-dat","name":"Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong ba lão tóc bạc hắc y đeo bảo kiếm cổ, tu vi Hoá Thần hậu kỳ, sư thúc của Quách Tà Dật.","vaiTro":"Trưởng bối Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Giáng lâm Địa Ma Bắc Giới","text":"Cùng hai Kiếm Các Trưởng lão lao tới bằng trường hồng, khí lãng thổi bay những người khác lui hơn mười trượng; dẫn Quách Tà Dật ra mắt hai Trưởng lão."},{"bridge":true,"khoang":"@c0480","text":"Trong đoàn tiến vào Địa Ma Bắc Giới, thỉnh thoảng liếc nhìn thân thể yêu kiều của Thiên Cầm với quang mang kỳ lạ, lộ ý đồ; không nhận ra sự kinh hoàng của hai Trưởng lão trước áp lực quỷ dị."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Hoá Thần hậu kỳ","text":"Tu vi Hoá Thần hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Là sư thúc, dẫn ra mắt hai Trưởng lão","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0480"],"aliases":["Lão già Hoá Thần hậu kỳ (sư thúc Quách Tà Dật)"]},{"id":"hai-kiem-cac-truong-lao","name":"Hai Kiếm Các Trưởng lão","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hai lão già hắc y tu vi Anh Biến sơ kỳ đeo bảo kiếm cổ, Trưởng lão Kiếm Các của Đại La Kiếm Tông.","vaiTro":"Trưởng lão Kiếm Các Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0478","importance":"normal","tieuDe":"Ra mắt tại Địa Ma Bắc Giới","text":"Lao tới cùng lão Hoá Thần hậu kỳ, được Quách Tà Dật quỳ một gối tham kiến."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Anh Biến sơ kỳ","text":"Cả hai tu vi Anh Biến sơ kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Được Quách Tà Dật quỳ tham kiến","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"thieu-nu-ket-dan-dai-la-kiem-tong","name":"Thiếu nữ Kết Đan hậu kỳ (Đại La Kiếm Tông)","gioiTinh":"nu","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một trong hai nữ tử nhóm Quách Tà Dật, tu vi Kết Đan hậu kỳ, báo có người tiến vào Địa Ma Bắc Giới.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Mặc quần lụa miệng xinh, báo với nhóm thấy có người vừa tiến vào Địa Ma Bắc Giới."}],"tuViMoc":[{"chuong":"@c0478","canhGioi":"Kết Đan hậu kỳ","text":"Tu vi Kết Đan hậu kỳ","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh dẫn đầu nhóm","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478"]},{"id":"nam-tu-ao-lam-dai-la-kiem-tong","name":"Nam tử áo lam (Đại La Kiếm Tông)","gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Đệ tử trẻ chừng hai mươi bảy tám tuổi nịnh hót, đề cao Đại La Kiếm Tông và Quách Tà Dật.","vaiTro":"Đệ tử Đại La Kiếm Tông","tinhCach":[{"text":"Nịnh hót, tâng bốc đại sư huynh và sư môn","chuong":"@c0478"}],"tabs":{"diem":[],"kinhLich":[{"bridge":true,"khoang":"@c0478","text":"Khen Đại La Kiếm Tông là môn phái số một số hai Thiên Vận Tinh và đề cao Quách Tà Dật."},{"chuong":"@c0481","importance":"minor","tieuDe":"Say mê cảnh tàn khốc","text":"Kẻ được Quách Tà Dật nịnh hót; trong khi mọi người kinh sợ, hắn lại thầm say mê cảnh tượng nam tử áo trắng bị Cửu Lê trùng ăn thịt."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Đại sư huynh được hắn tâng bốc","ghiChu":""},{"ten":"Quách Tà Dật","tag":"khac","quanHe":"Được Quách Tà Dật nịnh hót","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0478","@c0481"]},{"id":"lao-gia-cao-nguoi-dai-la-kiem-tong","name":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão cao người Đại La Kiếm Tông","Lão già cao người (Trưởng lão Đại La Kiếm Tông)","Lão già cao họ Thạch","Thạch Phương Trưởng lão"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông tham gia chuyến tìm Diệu Kim quả.","vaiTro":"Trưởng lão tra hỏi và ép dẫn đường","tinhCach":[{"text":"Hống hách nhưng còn giữ lời, đồng ý cho Thiên Cầm một quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Ép Thiên Cầm dẫn đường tìm Diệu Kim quả","text":"Cùng lão già thấp người tra hỏi Quách Tà Dật về Diệu Kim quả, đồng ý cho Thiên Cầm một quả sau khi thu được rồi ra lệnh cho nàng dẫn đoàn vào Địa Ma Bắc Giới."},{"chuong":"@c0480","importance":"normal","tieuDe":"Mở thông đạo vào sơn cốc Diệu Kim quả","text":"Trưởng lão Anh Biến sơ kỳ Thạch Phương cảm nhận áp lực quỷ dị như vạn sơn áp đỉnh trong Địa Ma Bắc Giới — cảm giác chưa từng gặp từ khi Hoá Thần — song vẫn quyết đi nhanh hơn. Tới sơn cốc, lão bấm quyết ngưng tụ một chiếc côn nồng đậm tiên lực hoá tiên phong thổi tan cây cối, mở thông đạo lộ ra phiến Diệu Kim quả, rồi nhận ra ổ Cửu Lê trùng ẩn dưới lá khô gần đó."},{"chuong":"@c0481","importance":"normal","tieuDe":"Phong ấn Cửu Lê trùng, đối đầu bụi khí","text":"Xưng danh Trưởng lão Đại La Kiếm Tông, dùng cấm thuật Kiếm phong chi cấm qua ngọc giản đỏ phong ấn nam tử áo trắng cùng đàn Cửu Lê trùng. Khi kẻ mạnh trong bụi khí xuất hiện, bấm quyết hóa bóng kiếm hư ảo hơn mười trượng chém xuống, nhưng kiếm bị đợt bụi khí phá tan."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Tu sĩ cùng tông bị tra hỏi","ghiChu":"Tra hỏi hắn về Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị ép dẫn đường","ghiChu":"Ra lệnh nàng dẫn đường, hứa cho một quả."},{"ten":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Cùng là Trưởng lão Đại La Kiếm Tông, phối hợp ăn ý","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá tan kiếm của hắn","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lao-gia-thap-nguoi-dai-la-kiem-tong","name":"Lão già thấp người (Trưởng lão Đại La Kiếm Tông)","cn":"","aliases":["Trưởng lão thấp người Đại La Kiếm Tông","Lão già thấp người (Trưởng lão Đại La Kiếm Tông)"],"gioiTinh":"nam","theLuc":[{"ten":"Đại La Kiếm Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Anh Biến sơ kỳ","trangThai":"song","blurb":"Một trong hai Trưởng lão Anh Biến sơ kỳ của Đại La Kiếm Tông, mắt bừng tinh quang khi nghe Diệu Kim quả có khoảng trăm quả.","vaiTro":"Trưởng lão tham lam Diệu Kim quả","tinhCach":[{"text":"Tham lam, mắt bừng tinh quang khi nghe số lượng Diệu Kim quả.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Hỏi số lượng Diệu Kim quả","text":"Hỏi Thiên Cầm số lượng Diệu Kim quả; nghe đáp ước chừng trăm quả thì mắt bừng tinh quang, lộ rõ tham vọng."},{"chuong":"@c0480","importance":"normal","tieuDe":"Ném đồng môn thử Cửu Lê trùng","text":"Trưởng lão Anh Biến sơ kỳ cảm giác kích động muốn giết người khi gặp Khổ Ảnh thú, từng đề nghị rời đi. Tới sơn cốc, lão chỉ ra cần dược dẫn đối phó Cửu Lê trùng rồi bất ngờ dùng lực vô hình chụp lấy gã đồng môn áo trắng bên người Thiên Cầm, ném thẳng vào sơn cốc làm mồi, lộ nụ cười tàn nhẫn."},{"chuong":"@c0481","importance":"normal","tieuDe":"Dọn trùng, sai hái Diệu Kim quả","text":"Tiến vào sơn cốc trước, bắn kiếm khí diệt sạch Cửu Lê trùng còn sót, ra lệnh cho Lữ Tùng Nghĩa đi hái Diệu Kim quả. Khi bụi khí áp tới, ném ra gương đồng một mặt tỏa thanh quang chống đỡ, nhưng gương bị giọng lạnh lẽo phá vỡ răng rắc."},{"chuong":"@c0483","importance":"normal","tieuDe":"Bị truy sát và giam giữ","text":"Sau khi Vương Lâm phá Huyết Thủ ấn và diệt Thiên Quỷ đầu, lão già thấp người liều mạng bỏ chạy nhưng bị thanh loan đao cùng kiếm tiên (nhốt Hứa Lập Quốc) đuổi theo giam giữ, chờ Vương Lâm tra hỏi."},{"chuong":"@c0484","importance":"normal","tieuDe":"Bị loan đao và kiếm tiên uy hiếp","text":"Ở chỗ sâu Địa Ma Bắc giới, lão mặt tái nhợt khoanh chân ngồi trên đại thụ không dám cử động: cách mi tâm một tấc có thanh loan đao lơ lửng bất động, cách thiên linh cái một tấc là một kiếm tiên với kiếm quang nồng đậm không tiêu tán đang đe doạ."},{"chuong":"@c0485","importance":"normal","tieuDe":"Khai Bí Mật Rồi Bị Diệt","text":"Tu sĩ Đại La Kiếm Tông, từng đến Địa Tinh cùng Thạch Phương và trêu chọc phải Vương Lâm. Bị phi kiếm cực cứng và loan đao quỷ dị của Vương Lâm khống chế đến không dám chạy, lão đành đứng chờ và cam đoan khai thật: chuyện Kiếm Tôn trở về bị kiếm hồn truy kích, phong ấn 1/3 kiếm hồn trong Đông Hải Yêu Linh chi môn, cùng bí mật ba đại cấm địa và phần thưởng Yêu Linh quán đính. Khai xong bị loan đao xuyên đầu, lão tu Tam phân thần thức thuật tái sinh lần cuối, thề về Đại La Kiếm Tông báo thù, nhưng vừa bay đi liền bị hai làn khí xám của Vương Lâm xuyên thân hút sạch sức sống mà chết thật."}],"tuViMoc":[],"nhanMach":[{"ten":"Lão già cao người (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Đồng liêu cùng tông","ghiChu":"Hai Trưởng lão cùng tham gia chuyến tìm Diệu Kim quả."},{"ten":"Thiên Cầm cô nương","tag":"doi-thu","quanHe":"Người bị tra hỏi số lượng quả","ghiChu":"Hỏi nàng số lượng Diệu Kim quả."},{"ten":"Lữ Tùng Nghĩa","tag":"dong-minh","quanHe":"Sai đi hái Diệu Kim quả","ghiChu":"@c0481"},{"ten":"Người trong bụi khí (giọng lạnh lẽo)","tag":"doi-thu","quanHe":"Kẻ mạnh phá vỡ gương đồng của lão","ghiChu":"@c0481"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, giam giữ chờ thẩm vấn.","ghiChu":"@c0483"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Kẻ bắt giam và xử tử","ghiChu":"Ép khai bí mật Đông Hải Yêu Linh chi môn rồi giết cả hai lần."},{"ten":"Thạch Phương","tag":"dong-hanh","quanHe":"Bạn đồng hành đến Địa Tinh","ghiChu":"Cùng đến Địa Tinh; lời khai của lão bị Vương Lâm lấy lời Thạch Phương làm chuẩn đối chiếu."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481","@c0483","@c0484","@c0485"]},{"id":"nam-tu-ao-trang-dong-mon-thien-cam","name":"Nam tử áo trắng (đồng môn Thiên Cầm)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Sư môn của Thiên Cầm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"không-ro","trangThai":"song","blurb":"Tu sĩ cùng sư môn với Thiên Cầm, tức giận trách Đại La Kiếm Tông nhưng bị Thiên Cầm quát im.","vaiTro":"Đồng môn bất bình của Thiên Cầm","tinhCach":[{"text":"Nóng nảy, bất bình thay sư môn nhưng phải nhẫn nhịn.","chuong":"@c0479"}],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0479","importance":"normal","tieuDe":"Bất bình trách Đại La Kiếm Tông","text":"Tức giận trách Đại La Kiếm Tông về việc sư môn phải hy sinh nhiều trưởng bối mới tìm được Diệu Kim quả, nhưng bị Thiên Cầm quát ‘Câm mồm!’ buộc phải im lặng nhẫn nhịn."},{"bridge":true,"khoang":"@c0480","text":"Bị lão già thấp người dùng lực vô hình chụp lấy và ném thẳng vào sơn cốc làm dược dẫn thử Cửu Lê trùng; vừa tiến vào liền bị vô số điểm đỏ Cửu Lê trùng lao tới."},{"chuong":"@c0481","importance":"normal","tieuDe":"Bị Cửu Lê trùng ăn thịt đến chết","text":"Bị ném vào giữa sơn cốc, vô số Cửu Lê trùng phá quần áo chui vào da thịt; chưa đến ba tức toàn thân lộ huyết sắc, hắn tự cào cấu da thịt lộ cả xương cốt, dãy dụa thảm thiết rồi tắt tiếng, hai mắt ảm đạm tuyệt vọng oán hận."}],"tuViMoc":[],"nhanMach":[{"ten":"Thiên Cầm cô nương","tag":"su-mon","quanHe":"Cùng sư môn","ghiChu":"Bị nàng quát im khi tức giận trách Đại La Kiếm Tông."},{"ten":"Thiên Cầm","tag":"su-mon","quanHe":"Sư muội chứng kiến hắn chết","ghiChu":"@c0481"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0479","@c0480","@c0481"]},{"id":"lu-tung-nghia","name":"Lữ Tùng Nghĩa","gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Hóa Thần kỳ","trangThai":"song","blurb":"Lão già Hóa Thần kỳ, sư thúc của Quách Tà Dật, được sai vào sơn cốc Địa Ma Bắc giới hái Diệu Kim quả.","vaiTro":"Trợ thủ trong nhóm Quách Tà Dật và hai Trưởng lão Đại La Kiếm Tông, đảm nhận việc hái Diệu Kim quả.","tinhCach":[{"text":"Tuân lệnh, hành động dứt khoát, lao như điện về phía Diệu Kim quả khi được sai.","chuong":"@c0481"}],"tabs":{"diem":[{"text":"Lão già Hóa Thần kỳ, vai vế sư thúc của Quách Tà Dật.","chuong":"@c0481"}],"kinhLich":[{"chuong":"@c0481","importance":"normal","tieuDe":"Vào cốc hái Diệu Kim quả","text":"Vào sơn cốc thứ ba sau hai Trưởng lão, được lão già lùn ra lệnh đi hái Diệu Kim quả. Khi biến cố bụi khí nổ ra, lão lao như điện tới được bên cạnh đóa hoa trên tảng đá vàng."}],"tuViMoc":[{"chuong":"@c0481","canhGioi":"Hóa Thần kỳ","text":"Xuất hiện với cảnh giới Hóa Thần kỳ.","importance":"minor"}],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Cháu (sư điệt)","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"dong-minh","quanHe":"Nhận lệnh hái Diệu Kim quả","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nu-tu-su-muoi-quach-ta-dat","name":"Nữ tử (sư muội Quách Tà Dật)","gioiTinh":"nu","trangThai":"song","blurb":"Nữ tử gọi Quách Tà Dật là sư huynh; tái nhợt run rẩy trước cảnh tàn khốc trong sơn cốc.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0481","importance":"minor","tieuDe":"Kinh sợ trước cảnh tàn khốc","text":"Đi cùng nhóm Quách Tà Dật, sắc mặt tái nhợt và run rẩy vì kinh sợ khi chứng kiến nam tử áo trắng bị Cửu Lê trùng ăn thịt."}],"tuViMoc":[],"nhanMach":[{"ten":"Quách Tà Dật","tag":"su-mon","quanHe":"Sư huynh","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"nguoi-trong-bui-khi-giong-lanh-leo","name":"Người trong bụi khí (giọng lạnh lẽo)","gioiTinh":"khong-ro","trangThai":"khong-ro","blurb":"Kẻ mạnh ẩn trong đoàn bụi khí nồng đậm, thực lực áp đảo hai Trưởng lão Đại La Kiếm Tông; danh tính chưa rõ.","tabs":{"diem":[{"text":"Ẩn trong bụi khí, chỉ một câu nói và một đợt bụi khí đã phá vỡ gương đồng và kiếm của hai Trưởng lão.","chuong":"@c0481"}],"kinhLich":[{"chuong":"@c0481","importance":"normal","tieuDe":"Áp đảo hai Trưởng lão Đại La Kiếm Tông","text":"Xuất hiện sau cơn gió mát khiến hai Trưởng lão đại biến sắc mặt. Đoàn bụi khí nồng đậm bùng lên như vạn mã, phá tan thanh quang gương đồng và kiếm khí Thạch Phương; từ trong bụi khí truyền ra giọng lạnh lẽo: “Ánh sáng của đom đóm há có thể so sánh với ánh trăng!”"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Phương","tag":"doi-thu","quanHe":"Phá tan kiếm của Thạch Phương","ghiChu":"@c0481"},{"ten":"Lão già lùn (Trưởng lão Đại La Kiếm Tông)","tag":"doi-thu","quanHe":"Phá vỡ gương đồng của lão","ghiChu":"@c0481"}],"tuiDo":{}},"nguon":["@c0481"]},{"id":"thach-phuong","name":"Thạch Phương","gioiTinh":"nam","aliases":[],"theLuc":[{"ten":"Sư môn của Thiên Cầm","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"tu-vong","blurb":"Trưởng lão của nhóm tiểu bối (đồng môn Thiên Cầm, Quách Tà Dật), tinh thông đoạt xá siêu tốc; bị Vương Lâm tiêu diệt tại sơn cốc.","vaiTro":"Phản diện một chương — trưởng lão kiếm tu nguyên thần ly thể đối đầu Vương Lâm.","tinhCach":[{"text":"Gian xảo, tham sống sợ chết: đoạt xá vật chủ, cầu xin và sẵn sàng giết môn hạ để mua mạng.","chuong":"@c0483"}],"tabs":{"diem":[{"text":"Nắm phương pháp đoạt xá siêu tốc, gần như khôi phục thần trí tức thì sau khi chiếm thân.","chuong":"@c0483"}],"kinhLich":[{"chuong":"@c0483","importance":"normal","tieuDe":"Bại trận và đoạt xá Quách Tà Dật","text":"Kiếm quang cùng nguyên thần ly thể của Thạch Phương xông tới mi tâm Vương Lâm nhưng bị Tứ chuyển hàm tiên lực vỗ tan, tiên ảnh đánh trọng thương nguyên thần, Văn thú nuốt sạch thân xác. Hắn vội đoạt xá tiểu bối Quách Tà Dật theo lối siêu tốc, cầu xin tha mạng, giết hai tiểu bối để chứng minh thành ý và hiến ngọc giản đoạt xá."},{"chuong":"@c0483","importance":"normal","tieuDe":"Bị khí xám nổ tung","text":"Sau khi ghi ngọc giản, Thạch Phương tranh thủ bỏ chạy khỏi sơn cốc nhưng thân vừa đoạt xá quá suy yếu; hai đạo khí xám của Vương Lâm chui vào kinh mạch khiến thân hắn nổ tung, để lại một khối cầu xám."}],"tuViMoc":[],"tuVi":"Tu sĩ có nguyên thần ly thể dung trong bản mạng phi kiếm; cảnh giới cụ thể không nêu rõ.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm đánh tan nguyên thần, nuốt thân xác và cuối cùng giết chết.","ghiChu":"@c0483"},{"ten":"Quách Tà Dật","tag":"doi-thu","quanHe":"Tiểu bối bị Thạch Phương đoạt xá làm vật chủ.","ghiChu":"@c0483"},{"ten":"Thiên Cầm cô nương","tag":"su-mon","quanHe":"Trưởng lão của nhóm tiểu bối có Thiên Cầm; định mượn thân xử nữ Thiên Cầm để chữa thương.","ghiChu":"@c0483"}],"tuiDo":{"phapBao":[{"ten":"Liễu diệp phi kiếm","loai":"bản mạng pháp khí","trangThai":"mat","moTa":"Phi kiếm hình lá liễu dung nguyên thần ly thể, bị tiên ảnh đánh chấn động hào quang ảm đạm.","nguon":"@c0483"}]}},"nguon":["@c0483"]},{"id":"kiem-ton","name":"Kiếm Tôn","gioiTinh":"nam","theLuc":[],"trangThai":"khong-ro","blurb":"Cường giả từ tiên giới trở về, bị một đạo kiếm hồn đáng sợ truy kích; sau mấy ngày giao chiến đã phong ấn hơn 1/3 kiếm hồn cùng Chu Dật tại chỗ sâu trong Đông Hải Yêu Linh chi môn.","vaiTro":"Nhân vật được nhắc tới, liên quan trực tiếp đến mục tiêu chuyến đi của Vương Lâm.","tabs":{"diem":[{"text":"Từ tiên giới trở về, đủ sức phong ấn một đạo kiếm hồn cường đại trong cấm địa.","chuong":"@c0485"}],"kinhLich":[{"chuong":"@c0485","importance":"minor","text":"Theo lời khai của lão già Đại La Kiếm Tông: lúc Kiếm Tôn từ tiên giới trở về có một đạo kiếm hồn đáng sợ từ chân trời truy kích, đánh nhau mấy ngày, cuối cùng kiếm hồn tan vỡ; hơn 1/3 bị Kiếm Tôn phong ấn tại chỗ sâu trong Đông Hải Yêu Linh chi môn, cùng nơi đó phong ấn Chu Dật."},{"chuong":"@c0487","importance":"normal","tieuDe":"Đích thân tới cửa Đông Hải","text":"Hóa thanh kiếm cổ mang thiên uy phóng tới cửa Đông Hải Yêu Linh, ngồi khoanh chân trên Hùng Lân thú với bốn đạo kiếm quang hư ảnh sau lưng, dẫn theo Kiếm Tiếu Thập Nhị Tử của Đại La Kiếm Tông; tạo khoảng trống trăm dặm khiến tu sĩ vội tránh né."},{"chuong":"@c0487","importance":"normal","tieuDe":"Mục đích nhốt kiếm hồn","text":"Tiết lộ ý đồ mượn hiện tượng thủy triều năm nghìn năm một lần để hút đạo kiếm hồn của một nữ quân tiên giới chìm sâu vĩnh viễn vào Đông Hải, quyết không để vật ấy rơi vào tay Thiên Vận lão tặc; ngay sau đó lão hữu cũ Tham Lang phá hư không xông tới tìm hắn."}],"tuViMoc":[],"tuVi":"Chưa rõ cảnh giới cụ thể; đủ sức phong ấn kiếm hồn cường đại.","nhanMach":[{"ten":"Chu Dật","tag":"doi-thu","quanHe":"Người bị phong ấn","ghiChu":"Bị Kiếm Tôn phong ấn trong Đông Hải Yêu Linh chi môn."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Kình địch cả đời, hai người đối lập kéo dài nhiều năm"},{"ten":"Tham Lang","tag":"dong-minh","quanHe":"Lão hữu cũ tới nhờ vả, muốn tặng hắn một cơ duyên cực lớn"},{"ten":"Diêu Tích Tuyết","tag":"khac","quanHe":"Lão quái phải kiêng nể hắn ở cửa Đông Hải"}],"tuiDo":{}},"nguon":["@c0485","@c0487"],"aliases":["Kiếm Tôn","Lăng Thiên Hậu","Lăng Thiên lão hữu"]},{"id":"dieu-tich-tuyet","name":"Diêu Tích Tuyết","cn":"","aliases":["Con gái Huyết Tổ"],"gioiTinh":"nu","theLuc":[],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Con gái duy nhất của Huyết Tổ Diêu Tinh Hải, được cha truyền toàn bộ công pháp huyết hệ; xuất hiện ngồi trên huyết ngọc khổng lồ bay tới ngoài Đông Hải Yêu Linh.","vaiTro":"Cường giả huyết hệ trẻ tuổi đến chờ cửa Đông Hải Yêu Linh mở.","tinhCach":[{"text":"Lạnh lùng, kín tiếng — đến nơi không nói lời nào, nhắm mắt khoanh chân ngồi chờ.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Mắt phượng mi cong, da trắng bóng như thủy tinh, ánh mắt ẩn thâm thúy u hàn khiến người nhìn vào như vạn kiếp bất phục.","chuong":"@c0486"}],"kinhLich":[{"chuong":"@c0486","importance":"normal","tieuDe":"Cưỡi huyết ngọc đến Đông Hải","text":"Giữa hồng quang che trời và mùi máu tanh nồng đậm, nàng ngồi trên bức tượng huyết ngọc khổng lồ bay tới ngoài cửa Đông Hải Yêu Linh, dừng ở chỗ trống rồi nhắm chặt mắt khoanh chân ngồi, không nói lời nào."},{"bridge":true,"khoang":"@c0487","text":"Là con gái Huyết Tổ, có uy thế lớn nên trong phạm vi trăm trượng quanh nàng không ai dám tới; khi Kiếm Tôn Lăng Thiên Hậu xuất hiện ở cửa Đông Hải Yêu Linh nàng cũng phải kinh hãi than “Kiếm Tôn!”."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Diêu Tích Tuyết ngồi trên khối huyết sắc ngọc thạch, theo lời dặn của phụ thân quan sát Vương Lâm; kinh ngạc vì một đệ tử tu vi tầm thường vừa gia nhập Thiên Vận Tử đã được chỉ đích danh vào Đông Hải."},{"chuong":"@c0490","importance":"normal","tieuDe":"Chấn động vì ánh mắt Vương Lâm","text":"Đang ngồi trên khối huyết ngọc ở phương xa quan sát thủy triều hồng quang, nàng vô ý đảo mắt nhìn qua chỗ Vương Lâm. Vừa thấy ánh mắt hắn dày đặc tơ máu lẫn khí xám yêu dị sau khi vận thần thông, nàng chấn động không tự chủ, mặt tái nhợt vội cúi đầu, trong lòng dậy sóng và hiểu ra vì sao phụ thân dặn nàng phải chú ý đến người này."},{"chuong":"@c0491","importance":"normal","tieuDe":"Vào cửa Đông Hải","text":"Đứng trên huyết ngọc lộ vẻ suy tư, cắn răng hóa thành đạo huyết quang bay vào lối vào cánh cửa Đông Hải yêu linh."}],"tuViMoc":[],"tuVi":"Được Huyết Tổ truyền toàn bộ công pháp huyết hệ; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Cha ruột","ghiChu":"Được cha coi như ngọc quý, truyền toàn bộ công pháp."},{"ten":"Huyết Tổ Diêu Tinh Hải","tag":"cha-me","quanHe":"Phụ thân"},{"ten":"Kiếm Tôn","tag":"khac","quanHe":"Đại lão khiến nàng phải kiêng nể"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng được phụ thân dặn chú ý","ghiChu":"Bị ánh mắt mang khí xám của Vương Lâm làm chấn động (@c0490)."}],"tuiDo":{"phapBao":[{"ten":"Huyết ngọc (tượng huyết sắc)","trangThai":"dang-co","moTa":"Bức tượng huyết sắc khổng lồ bằng ngọc thạch, tỏa hồng quang và mùi máu tanh, dùng làm phương tiện bay trong tinh không.","nguon":"@c0486"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487","@c0488","@c0490","@c0491"]},{"id":"huyet-to-dieu-tinh-hai","name":"Huyết Tổ Diêu Tinh Hải","cn":"","aliases":["Huyết Tổ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Thông Thiên","trangThai":"song","blurb":"Lão quái tu vi thông thiên của Thiên Vận Tinh, từng bảy lần khiêu chiến Thiên Vận Tử; độc chiếm Huyết Tinh khai hoang nạp huyết tu luyện ma công, cha của Diêu Tích Tuyết.","vaiTro":"Cường giả huyết hệ ẩn cư, được nhắc tới trong chương (chưa ra mặt).","tinhCach":[{"text":"Cô độc, cường ngạnh — cả đời không thu đồ đệ, chỉ dồn tâm huyết cho con gái.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Bảy lần khiêu chiến Thiên Vận Tử đều thất bại nhưng tu vi càng lúc càng cao, lần thứ bảy thi triển Huyết Công kinh người.","chuong":"@c0486"}],"kinhLich":[{"chuong":"@c0486","importance":"normal","tieuDe":"Bảy lần khiêu chiến Thiên Vận Tử","text":"Bảy lần khiêu chiến chủ nhân Thiên Vận Tinh là Thiên Vận Tử, tuy đều thất bại nhưng tu vi mỗi lần một mạnh; lần thứ bảy thi triển Huyết Công khiến người kinh sợ."},{"chuong":"@c0486","importance":"normal","tieuDe":"Độc chiếm Huyết Tinh tu ma công","text":"Độc chiếm một tinh cầu bên ngoài Thiên Vận Tinh (Huyết Tinh), khai hoang nạp huyết tu luyện ma công; cả đời không thu đồ đệ, đem toàn bộ công pháp truyền cho con gái rồi nghịch thiên cải mệnh."}],"tuViMoc":[],"tuVi":"Tu vi thông thiên, sở trường công pháp huyết hệ.","nhanMach":[{"ten":"Diêu Tích Tuyết","tag":"cha-me","quanHe":"Con gái ruột","ghiChu":"Coi như ngọc quý, truyền toàn bộ công pháp."},{"ten":"Thiên Vận Tử","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Bảy lần khiêu chiến."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[{"ten":"Huyết Công","moTa":"Ma công huyết hệ sở trường, thi triển trong lần thứ bảy khiêu chiến Thiên Vận Tử.","nguon":"@c0486"}],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486"]},{"id":"ton-van-son","name":"Tôn Vân Sơn","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Thiếu tông chủ Huyền Uyên phái, hay cầm quạt thúy ngọc; ngăn em gái lên Đông Hải Yêu Linh và long trọng chờ đón Vương huynh đến qua truyền tống trận.","vaiTro":"Người chủ trì truyền tống trận của Huyền Uyên phái, đón Vương Lâm.","tinhCach":[{"text":"Điềm tĩnh, có uy — quát mắng em gái nhưng vẫn giữ phong thái thong dong.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Thường cầm quạt thúy ngọc đập nhẹ vào lòng bàn tay, chốc chốc nhìn về phương xa chờ khách.","chuong":"@c0486"}],"kinhLich":[{"chuong":"@c0486","importance":"normal","tieuDe":"Ngăn em gái lên Đông Hải","text":"Trước truyền tống trận khổng lồ của Huyền Uyên phái, ngăn em gái áo hồng đòi lên Đông Hải Yêu Linh, viện cớ tu vi nàng không đủ và phụ thân đã bế quan ra lệnh cấm, sai lão Huyền Nhất bắt nàng mang về tông phái."},{"chuong":"@c0486","importance":"normal","tieuDe":"Chờ đón Vương huynh","text":"Phát hiện có người đến qua truyền tống trận liền mỉm cười nhìn về chân trời, nói “Vương huynh! Tôn mỗ chờ huynh đã lâu!”."},{"bridge":true,"khoang":"@c0487","text":"Cố đợi Vương Lâm để cùng đi Đông Hải Yêu Linh; than do gia phụ bắt buộc phải đi dù nguy hiểm; dẫn theo ba trưởng lão Huyền Uyên phái hộ vệ và ra lệnh mở trận pháp tinh không, nhưng từ chối cho muội Tôn Nhược Nam đi theo."},{"bridge":true,"khoang":"@c0488–@c0488","text":"Tôn Vân Sơn đồng hành cùng Vương Lâm tới cửa Đông Hải, âm trầm vì phải vội lên đường mới kịp ngày cuối; tách khỏi Vương Lâm, nhờ chiếu cố và hẹn gặp lại trong Đông Hải Yêu Linh."}],"tuViMoc":[],"tuVi":"Thiếu tông chủ Huyền Uyên phái; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Em gái Tôn Vân Sơn","tag":"ho-hang","quanHe":"Em gái","ghiChu":"Ngăn nàng lên Đông Hải."},{"ten":"Huyền Nhất","tag":"cap-tren","quanHe":"Lão già cao thủ dưới trướng","ghiChu":"Sai bắt em gái mang về."},{"ten":"Vương Lâm","tag":"ban-be","quanHe":"Vương huynh","ghiChu":"Long trọng chờ đón qua truyền tống trận."},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Bạn đồng hành cùng đi Đông Hải Yêu Linh"},{"ten":"Tôn Nhược Nam","tag":"ho-hang","quanHe":"Xá muội, bị hắn từ chối cho đi theo"},{"ten":"Huyền Nhất","tag":"su-mon","quanHe":"Trưởng lão Huyền Uyên phái phụ trách an toàn cho hắn"}],"tuiDo":{"phapBao":[{"ten":"Quạt thúy ngọc","trangThai":"dang-co","moTa":"Chiếc quạt ngọc thường cầm, hay đập thân quạt vào lòng bàn tay.","nguon":"@c0486"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487","@c0488"]},{"id":"huyen-nhat","name":"Huyền Nhất","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Một trong ba lão già đầu tóc trắng khí tức kinh người theo Tôn Vân Sơn, cao thủ Huyền Uyên phái; được lệnh bắt tiểu thư mang về tông phái.","vaiTro":"Cao thủ hộ vệ của Huyền Uyên phái.","tinhCach":[],"tabs":{"diem":[{"text":"Đầu tóc trắng xóa, khí tức kinh người, đứng sau lưng thiếu tông chủ.","chuong":"@c0486"}],"kinhLich":[{"chuong":"@c0486","importance":"normal","tieuDe":"Được lệnh bắt tiểu thư","text":"Được Tôn Vân Sơn sai đi bắt em gái áo hồng đang đòi lên Đông Hải Yêu Linh mang về tông phái."},{"bridge":true,"khoang":"@c0487","text":"Là một trong ba lão già trưởng lão Huyền Uyên phái phụ trách an toàn cho Tôn Vân Sơn; được lệnh cùng hai lão già quay vào trận pháp tinh không để hộ tống chuyến đi Đông Hải Yêu Linh."}],"tuViMoc":[],"tuVi":"Cao thủ Huyền Uyên phái; tu vi cụ thể chưa rõ.","nhanMach":[{"ten":"Tôn Vân Sơn","tag":"su-mon","quanHe":"Thiếu tông chủ chủ quản","ghiChu":"Nhận lệnh hành sự."},{"ten":"Tôn Vân Sơn","tag":"su-mon","quanHe":"Người được hắn hộ vệ"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487"]},{"id":"em-gai-ton-van-son","name":"Em gái Tôn Vân Sơn","cn":"","aliases":["Em gái Tôn Vân Sơn","Xá muội Tôn Vân Sơn"],"gioiTinh":"nu","theLuc":[{"ten":"Huyền Uyên Phái","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ","trangThai":"song","blurb":"Cô gái trẻ khoảng hai mươi tuổi mặc áo hồng nhạt, da trong suốt như thủy tinh, tỏa hương như cây Bách Linh; đòi anh trai cho lên Đông Hải Yêu Linh.","vaiTro":"Tiểu thư Huyền Uyên phái muốn vào Đông Hải Yêu Linh.","tinhCach":[{"text":"Bướng bỉnh, ngang ngạnh — đòi đi cho bằng được, viện cớ mẹ đã đồng ý.","chuong":"@c0486"}],"tabs":{"diem":[{"text":"Hóa từ một đám mây hồng, da trong suốt như thủy tinh, tỏa mùi thơm như cây Bách Linh.","chuong":"@c0486"}],"kinhLich":[{"chuong":"@c0486","importance":"normal","tieuDe":"Đòi lên Đông Hải Yêu Linh","text":"Đòi anh trai Tôn Vân Sơn cho lên Đông Hải Yêu Linh, ra điều kiện nếu vượt qua được thì phải để nàng đi; khi bị từ chối liền viện cớ “Mẹ đã đồng ý rồi!”."},{"chuong":"@c0487","importance":"normal","tieuDe":"Lén bám theo tới Đông Hải","text":"Bị huynh Tôn Vân Sơn từ chối cho đi Đông Hải Yêu Linh, nàng đắc ý lấy ra miếng truyền tống ngọc giản lén trộm của cha, hóa thành sợi tơ trắng phóng vào cầu vồng truyền tống để lén đi theo, hy vọng tìm được bảo vật ở Đông Hải."}],"tuViMoc":[],"tuVi":"Tu vi chưa đủ để vào Đông Hải theo lời Tôn Vân Sơn.","nhanMach":[{"ten":"Tôn Vân Sơn","tag":"ho-hang","quanHe":"Anh trai","ghiChu":"Bị anh ngăn không cho lên Đông Hải."},{"ten":"Tôn Vân Sơn","tag":"ho-hang","quanHe":"Huynh trưởng, người từ chối cho nàng đi theo"},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người nàng lén bám theo, gọi “Vương đại ca”"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0486","@c0487"]},{"id":"tham-lang","name":"Tham Lang","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tán tu","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Người đàn ông trung niên bao phủ tử khí, cưỡi đống xương khô khổng lồ; chủ hung từng muốn cướp Hạt Châu Thiên Nghịch của Tư Đồ Nam, nay thân mang thương nặng tìm tới lão hữu Kiếm Tôn.","vaiTro":"Cường địch tiềm tàng truy tìm Vương Lâm","tinhCach":[{"text":"Tham lam, thủ đoạn — muốn thôn phệ thượng cổ tu sĩ để khôi phục tu vi","chuong":"@c0487"},{"text":"Khôn khéo, biết tránh kẻ mạnh hơn (Tư Đồ Nam) và mượn lực lão hữu","chuong":"@c0487"}],"tabs":{"diem":[{"text":"Bao phủ tử khí, cưỡi mấy nghìn bộ xương khô khổng lồ trong đó có một bộ cực lớn của mãnh thú thượng cổ","chuong":"@c0487"}],"kinhLich":[{"chuong":"@c0487","importance":"normal","tieuDe":"Tới Đông Hải nhờ vả Kiếm Tôn","text":"Vì thân mang thương nặng và muốn tránh Tư Đồ Nam, hắn rời Chu Tước Tinh đến Đại La Kiếm Tông tìm Kiếm Tôn không gặp nên đuổi theo tới cửa Đông Hải; phá toái hư không xông vào phạm vi trăm dặm, chào “Lăng Thiên lão hữu” và đề nghị tặng Kiếm Tôn một cơ duyên cực lớn để đè đầu Thiên Vận Tử dễ như trở bàn tay."},{"chuong":"@c0488","importance":"normal","tieuDe":"Tiết lộ cơ duyên hạt châu","text":"Tham Lang kể với Lăng Thiên Hậu chuyện mấy vạn năm trước Tu Chân Liên Minh treo thưởng một bộ thượng phẩm tiên thuật hoàn chỉnh để tìm một hạt châu; thừa nhận vết thương của hắn liên quan đến hạt châu đó và đang bị người giữ nó bức bách. Hắn nhận lời giúp Lăng Thiên Hậu, hóa thành bóng ma ẩn sau lưng lão, cảm thấy Vương Lâm quen thuộc như cố nhân năm xưa."},{"chuong":"@c0491","importance":"normal","tieuDe":"Trà trộn vào cửa Đông Hải","text":"Đã sớm biến mất sau lưng Lăng Thiên Hậu, hóa thành đạo kiếm khí bảo mệnh được ban cho đệ tử cuối cùng của Kiếm Tiếu Thập Nhị Tử, theo Đại La kiếm tông tiến vào cánh cửa yêu linh."}],"tuViMoc":[],"nhanMach":[{"ten":"Kiếm Tôn","tag":"dong-minh","quanHe":"Lão hữu cũ mà hắn tới nhờ vả"},{"ten":"Tư Đồ Nam","tag":"doi-thu","quanHe":"Người sở hữu Hạt Châu Thiên Nghịch mà hắn từng muốn cướp, nay phải tránh mặt"},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người hắn truy tìm cùng sợi tơ Thiên Kiếp"},{"ten":"Lăng Thiên Hậu","tag":"dong-minh","quanHe":"Người được cầu nhờ","ghiChu":"Tham Lang tìm tới nhờ xuất thủ chuyện hạt châu, đổi lại bảo vệ mười hai đệ tử của lão trong Đông Hải."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cảm giác quen thuộc","ghiChu":"Tham Lang cảm thấy trên người Vương Lâm sinh ra cảm giác như cố nhân năm xưa rồi thu hồi ánh mắt."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0487","@c0488","@c0491"]},{"id":"chu-vu-thai","name":"Chu Vũ Thái","tabs":{"kinhLich":[{"bridge":true,"khoang":"@c0489","text":"Đang khoanh chân tĩnh tọa trên Chu Tước Tinh xa xôi, đột nhiên mở hai mắt khi thấy bầu trời đỏ rực bởi hồng quang thủy triều Đông Hải Yêu Linh lan tới."}]},"nguon":["@c0489"]},{"id":"nguoi-xich-loa-tho-san-son-coc","name":"Người xích lõa vẽ nhựa cây (thợ săn)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Cư dân sơn cốc Đông Hải yêu linh","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (không có linh lực)","trangThai":"song","blurb":"Người nửa thân xích lõa sống trong sơn cốc vùng Đông Hải yêu linh, không có chút linh lực nào nhưng linh tính kinh người, săn dã thú bằng vũ khí u quang.","vaiTro":"Cư dân chủng người lạ trong sơn cốc trận pháp thượng cổ.","tinhCach":[{"text":"Cảnh giác, hoang dã, đề phòng người lạ — giành giữ con thú săn được.","chuong":"@c0492"}],"tabs":{"diem":[{"text":"Không có linh lực nhưng linh tính kinh người, ẩn thân cực giỏi bằng nhựa cây xanh.","chuong":"@c0492"},{"text":"Săn dã thú bằng gậy đen gắn lưỡi dao u quang; máu con thú lộ u quang.","chuong":"@c0492"}],"kinhLich":[{"chuong":"@c0492","importance":"normal","tieuDe":"Săn thú và đối mặt Vương Lâm","text":"Nằm ẩn thân trong rừng, bất ngờ bật dậy đâm chết con dã thú lớn không linh lực, nhảy lên lưng thú cắt cổ. Khi Vương Lâm hiện thân, hắn cảnh giác cầm dao thốt giọng khàn “Thú, ta!” để giành con thú; được Vương Lâm nhường, hắn kéo xác thú lui về sơn cốc."}],"tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","tag":"khac","quanHe":"Tu sĩ lạ gặp ở rừng núi, nhường con thú rồi sau giam giữ tra hỏi"}],"tuiDo":{"khac":[{"ten":"Gậy dài màu đen gắn lưỡi dao u quang","loai":"vũ khí","moTa":"Đầu gậy gắn lưỡi dao nhỏ phát u quang; gậy gãy vụn khi đâm thú nhưng lưỡi dao giết được dã thú.","nguon":"@c0492"}]}},"nguon":["@c0492"]},{"id":"au-duong-hoa","name":"Âu Dương Hoa","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Bộ tộc sơn cốc","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão giả tóc bạc tự xưng trưởng lão sơn cốc, sống ở vùng đất này từ khi có ký ức, thuở nhỏ từng học ở Cổ yêu thành nên có tuổi thọ cao.","vaiTro":"Trưởng lão bộ tộc thân trâu mình người trong sơn cốc, đối đầu Vương Lâm bằng thượng cổ trận pháp.","tinhCach":[{"text":"Vẻ ngoài tang thương, lời lẽ ôn hòa nhưng quyết liệt bảo vệ tộc nhân","chuong":"@c0493"}],"tabs":{"diem":[{"text":"Chỉ hiện thân bằng thế thân hư ảo, bản thể thật ẩn sâu trong cốc","chuong":"@c0493"},{"text":"Thờ yêu linh, định lấy hồn phách người ngoài làm tế phẩm","chuong":"@c0493"}],"kinhLich":[{"chuong":"@c0493","importance":"normal","tieuDe":"Ra mặt chỉ điểm Cổ yêu thành","text":"Sau ba ngày yên tĩnh, Âu Dương Hoa cầm quải trượng đen cùng mười một sinh vật thân trâu mình người bước ra khỏi cốc, xin thả tộc nhân để đối thoại. Lão tiết lộ về Cổ yêu thành ngoài ba ngàn dặm, khuyên Vương Lâm tới đó tìm vật cần và nói người ngoài cứ bốn trăm năm lại tới một lần."},{"chuong":"@c0493","importance":"normal","tieuDe":"Điều khiển trận pháp phản kích","text":"Khi Vương Lâm phá trận, Âu Dương Hoa lộ ra chỉ là thế thân hư ảo; bản thể trong cốc lệnh trận pháp hút kéo vạn vật ngưng thành hư ảnh người màu xanh cao mấy trượng để giết Vương Lâm, lấy hồn phách tế yêu linh."},{"chuong":"@c0494","importance":"normal","tieuDe":"Chiêu hàng bất thành, cầu tha","text":"Dựa vào trận pháp thượng cổ trong sơn cốc, Âu Dương Hoa cười lạnh đòi Vương Lâm tự cắt một tay một chân để hắn hấp thu ba phần nguyên thần, dọa biến đối phương thành yêu ảnh thứ hai; khi trận bị tám mươi ba tổ hợp cấm chế đánh tan thì hoảng sợ cầu xin tha mạng."},{"chuong":"@c0495","importance":"normal","tieuDe":"Thần phục Vương Lâm","text":"Dẫn mười tộc nhân ra cốc cung kính xưng Vương Lâm là thượng tiên, xin đừng phá trận pháp kẻo cả tộc thành thức ăn của yêu linh. Cắn ngón tay vẩy giọt máu mở thông đạo mời Vương Lâm vào sơn cốc, kể về Hoàng Long và trận pháp cổ, cảnh báo đêm yêu linh và mời về nhà mình."},{"chuong":"@c0496","importance":"normal","tieuDe":"Tiết lộ cơ cấu Thiên Yêu quận","text":"Kể cho Vương Lâm về nơi yêu linh có chín quận, bộ tộc đang ở thuộc Thiên Yêu quận với yêu đế Tai Hư, bát đại yêu soái, thiên vạn yêu binh, hơn trăm thành trì; nhắc đêm trăng tròn là đêm yêu linh đi săn mồi, và quy luật cứ năm trăm năm có người bên ngoài tiến vào. Sau khi thấy đan dược của Vương Lâm, hạ quyết tâm dẫn hắn tới đáy sơn cốc hình hồ lô xem ngọc yêu linh."},{"chuong":"@c0497","importance":"normal","tieuDe":"Đổi yêu lực kết tinh cầu cứu","text":"Âu Dương Hoa run rẩy nhận hơn mười bình ngọc của Vương Lâm, đem yêu lực kết tinh duy nhất của thung lũng đổi lấy; hé lộ rằng vì trận pháp Hồ Lô Cốc đã suy yếu nặng, không chắc chống được đêm Yêu linh săn mồi, nên cắn răng mời thượng tiên ở lại và tiết lộ bí mật để mong được trợ giúp."},{"bridge":true,"khoang":"@c0497","text":"Đêm xuống, Âu Dương Hoa cùng đàn ông trong cốc cầm vũ khí tập trung ở cửa, niệm chú duy trì trận pháp; khi trận bị sóng yêu khí công phá sắp vỡ, hắn mừng rỡ gọi Vương Lâm là thượng tiên đến cứu mạng."},{"bridge":true,"khoang":"@c0503","text":"Cung kính cung đón Vương Lâm là thượng tiên khi hắn trở về thung lũng, đoán người đi cùng hắn trước đó đã bị giết. Theo lệnh, hắn ra lệnh cấm mọi người vào sâu thung lũng (cấm địa), ai trái lệnh bị đuổi, đồng thời tuyên bố sơn cốc quá nhỏ cần mở rộng địa bàn — tuyên chiến với tộc khác, khiến cư dân phấn khích."},{"chuong":"@c0504","importance":"normal","tieuDe":"Được đả thông kinh mạch, đột phá nhị tinh","text":"Trưởng lão sơn cốc, thuở nhỏ từng học ở thành cổ yêu nhưng bị đuổi vì bị phát hiện có tinh lực. Được Vương Lâm dùng song chỉ điểm từ bụng lên mi tâm cưỡng ép đả thông kinh mạch, đau thấu xương rồi ngất, mấy canh giờ sau tỉnh dậy đạt nhị tinh, tự thấy như được hồi sinh, quỳ tạ thượng tiên."},{"bridge":true,"khoang":"@c0504","text":"Nhận yêu giản, nhìn thấu khẩu quyết luyện hồn, được giao truyền dạy lại cho toàn cốc; ba tháng chuyên tâm tu luyện thuật luyện hồn tiến bộ cực nhanh, cảm kích thề khắc cốt ân điển."},{"chuong":"@c0505","importance":"normal","tieuDe":"Nhường cơ hội, định kế tấn công bộ tộc","text":"Âu Dương Hoa đã tới giai đoạn ba và chế xong hồn phiên trước Thập Tam mấy ngày nhưng cố ý nhường cơ hội cho hắn, nhận ra tương lai sơn cốc thuộc về Thập Tam; lão trình Vương Lâm kế hoạch một tháng sau phát động người trong cốc đánh một bộ tộc vài chục người cách ngàn dặm."},{"chuong":"@c0506","importance":"normal","tieuDe":"Dâng yêu tinh nhận khẩu quyết giai đoạn bốn","text":"Cung kính cầu kiến ‘thượng tiên’, dâng khối đá đen chứa nhị giáp yêu tinh và nhận ngọc giản khẩu quyết Luyện Hồn Thuật giai đoạn thứ tư — hiện là người duy nhất đạt mức này. Vốn phản đối nữ tu, bị Vương Lâm khiển trách liền đổi sang cổ vũ nữ tử tu hành."},{"bridge":true,"khoang":"@c0506–@c0506","text":"Cùng Thập Tam làm chủ công đánh hạ bộ tộc trong động, luyện hóa hồn phách người vừa chết; chỉ huy đồng hóa người ngoại tộc bằng yêu thang và đẩy bộ lạc chuyển sang xâm lược."}],"tuViMoc":[{"chuong":"@c0504","canhGioi":"Nhị tinh","text":"Được Vương Lâm cưỡng ép đả thông kinh mạch, đột phá lên trình độ nhị tinh — đường tắt nâng tu vi nhưng để lại di chứng.","importance":"minor"},{"chuong":"@c0505","canhGioi":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","text":"Được Vương Lâm cho phép, Âu Dương Hoa tu luyện Luyện Hồn Yêu Thuật tới giai đoạn ba. Đây là thành tựu thuộc hệ Luyện Hồn Thuật, không phải tu vi chính.","importance":"minor"}],"tuVi":"Tu vi không rõ; thân thể yếu ớt, có tuổi thọ rất cao nhờ từng học ở Cổ yêu thành.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người ngoài xâm nhập sơn cốc, đối đầu qua trận pháp","ghiChu":"Bị Vương Lâm phá trận và nhận ra chỉ là thế thân hư ảo."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ","ghiChu":"Vây Vương Lâm bằng trận pháp nhưng bị hắn phá trận, áp sát buộc phải cầu tha."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Tôn xưng Vương Lâm là thượng tiên, mời vào sơn cốc và tiếp đãi","ghiChu":""},{"ten":"Hoàng Long","tag":"khac","quanHe":"Thượng tiên dẫn tổ tiên tộc Âu Dương Hoa đến định cư, được tôn thờ qua bức tranh","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Người bên ngoài mà Âu Dương Hoa dẫn đi đổi đan dược lấy ngọc yêu linh","ghiChu":"Lo sợ tộc nhân chết nhưng vẫn dẫn đi vì đan dược là trọng bảo."},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Thượng tiên được Âu Dương Hoa mời ở lại và đổi yêu lực kết tinh, cầu cứu khi yêu linh tấn công","ghiChu":"@c0497"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Tôn làm thượng tiên, phụng mệnh thi hành cấm địa và tuyên chiến mở rộng địa bàn","ghiChu":""},{"ten":"Vương Lâm","tag":"an-nhan","quanHe":"Ân nhân / sư tôn","ghiChu":"Đả thông kinh mạch cho đột phá nhị tinh và truyền thụ thuật luyện hồn; Âu Dương Hoa tôn kính xưng vãn bối, hành lễ như đệ tử."},{"ten":"Thập Tam","tag":"khac","quanHe":"Hậu bối được nhường đường","ghiChu":"Âu Dương Hoa nhường cơ hội chế hồn phiên cho Thập Tam và dùng tiểu phiên triệu chim sẻ cứu hắn khi sư tử phản phệ."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"Cung kính tôn là ‘thượng tiên’, dâng yêu tinh đổi khẩu quyết","ghiChu":""},{"ten":"Thập Tam","tag":"dong-minh","quanHe":"Cùng làm chủ công các trận chinh phạt","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Quải trượng màu đen","moTa":"Cây gậy đen Âu Dương Hoa cầm khi bước ra khỏi cốc.","nguon":"@c0493"}]}},"nguon":["@c0493","@c0494","@c0495","@c0496","@c0497","@c0503","@c0504","@c0505","@c0506"]},{"id":"hoang-long-thuong-tien","name":"Hoàng Long","cn":"","aliases":["Hoàng Long thượng tiên"],"gioiTinh":"nam","theLuc":[],"trangThai":"khong-ro","blurb":"Nam tử trung niên trong bức tranh cổ ố vàng nhà Âu Dương Hoa, được tộc nhân tôn là Hoàng Long thượng tiên đã dẫn tổ tiên họ đến định cư sơn cốc.","vaiTro":"Nhân vật được nhắc qua truyền miệng và bức tranh; cái tên khiến Vương Lâm chấn động nguyên thần.","tinhCach":[],"tabs":{"diem":[{"text":"Được tộc Âu Dương Hoa tôn là thượng tiên qua lời kể tổ tiên","chuong":"@c0495"}],"kinhLich":[{"chuong":"@c0495","importance":"normal","tieuDe":"Hoàng Long trong bức tranh cổ","text":"Vô số năm trước dẫn tộc nhân tổ tiên Âu Dương Hoa đến định cư sơn cốc, nơi trận pháp cổ đã tồn tại qua vô số năm. Hình ảnh lưu trong bức tranh ố vàng nứt nẻ: nam tử trung niên mặc trang phục kỳ dị, tay phải tạo ấn ký cổ quái trước ngực, nhìn về một hư ảnh ẩn hiện trong màn sương đen. Cái tên khiến Vương Lâm chấn động nguyên thần."}],"tuViMoc":[],"nhanMach":[{"ten":"Âu Dương Hoa","tag":"khac","quanHe":"Trưởng lão tộc nhân lưu giữ bức tranh và tôn thờ Hoàng Long","ghiChu":""},{"ten":"Vương Lâm","tag":"khac","quanHe":"Cái tên Hoàng Long khiến Vương Lâm chấn động nguyên thần","ghiChu":""}],"tuiDo":{}},"nguon":["@c0495"]},{"id":"tai-hu","name":"Tai Hư","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Yêu quận","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Yêu đế của Thiên Yêu quận nơi yêu linh, thống lĩnh bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì.","vaiTro":"Yêu đế","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0496","importance":"normal","tieuDe":"Yêu đế Thiên Yêu quận","text":"Được Âu Dương Hoa nhắc tới là yêu đế của Thiên Yêu quận, nắm giữ một phương với bát đại yêu soái, thiên vạn yêu binh và hơn trăm thành trì."}],"tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0496"]},{"id":"hac-y-nam-tu-thien-van-tinh","name":"Hắc y nam tử (Thiên Vận Tinh)","cn":"","aliases":["Hắc y nam tử"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Yêu Thành","trangThai":"danh-nghia"}],"canhGioiCaoNhat":"Ứng Biến hậu kỳ đại viên mãn","trangThai":"song","blurb":"Tu sĩ áo đen mặt lạnh cầm kiếm mỏng màu đen, săn yêu linh ở Thiên Vận Tinh để lấy yêu tinh đủ tư cách tiến vào Thiên Yêu Thành; coi Vương Lâm là con mồi.","vaiTro":"Đối thủ của Vương Lâm tại Thiên Vận Tinh","tinhCach":[{"text":"Lạnh lùng, khinh miệt và tự tin, thích dồn con mồi vào thế bất ngờ","chuong":"@c0497"}],"tabs":{"diem":[{"text":"Tu vi Ứng Biến hậu kỳ đại viên mãn, hấp thu yêu lực điên cuồng qua thất khiếu","chuong":"@c0497"},{"text":"Săn yêu linh để lấy yêu tinh đủ tư cách tiến vào Thiên Yêu Thành","chuong":"@c0497"}],"kinhLich":[{"chuong":"@c0497","importance":"normal","tieuDe":"Tuyên bố săn Vương Lâm","text":"Thần thức Vương Lâm phát hiện Hắc y nam tử đang múa kiếm thu hút lượng lớn yêu lực; hắn ngẩng đầu cười lạnh, khen tu vi Vương Lâm không tồi nhưng tuyên bố Vương Lâm là con mồi của mình, dù giao nộp yêu linh cũng vô dụng. Hắn lầm tưởng Vương Lâm chỉ Ứng Biến trung kỳ, cho rằng thu được yêu tinh của đối phương thì đủ tư cách tiến vào Thiên Yêu Thành."},{"bridge":true,"khoang":"@c0497","text":"Hắc y nam tử chém một con vật kỳ dị một sừng làm đôi để hút yêu lực, rồi vung kiếm hóa điện quang phi kiếm lao thẳng tới thung lũng, vang thanh âm lạnh như băng: Săn bắn, bắt đầu!"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Coi Vương Lâm là con mồi để lấy yêu tinh tiến vào Thiên Yêu Thành; lầm tưởng đối phương chỉ Ứng Biến trung kỳ","ghiChu":"@c0497"}],"tuiDo":{"phapBao":[{"ten":"Kiếm mỏng màu đen","trangThai":"dang-co","moTa":"Trường kiếm mỏng màu đen dùng thu hút yêu lực và hóa thành điện quang phi kiếm tấn công từ xa.","nguon":"@c0497"}],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0497"]},{"id":"la-mo-hac-y-nam-tu","name":"La mỗ (Hắc y nam tử)","cn":"","aliases":["Hắc y nam tử","La mỗ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Vấn Đỉnh (nguyên thần)","trangThai":"song","blurb":"Tu sĩ hắc y đạp phi kiếm ngông cuồng, chạm trán Vương Lâm giữa sóng yêu linh; sở trường hỏa hệ với Địa diệt chi hỏa và cấm thuật Kiếm toái.","vaiTro":"Đối thủ thoáng qua của Vương Lâm tại Thiên Yêu quận.","tinhCach":[{"text":"Ngông cuồng, lạnh lùng, song thận trọng — sợ giết nhầm người quen nên dò hỏi môn phái trước.","chuong":"@c0498"}],"tabs":{"diem":[{"text":"Nguyên thần cao thâm, sở trường hỏa hệ; tự xưng La mỗ.","chuong":"@c0498"},{"text":"Am hiểu danh tiếng các thế lực, nhận ra ngay thân phận Vương Lâm qua ngọc giản tướng mạo.","chuong":"@c0498"}],"kinhLich":[{"chuong":"@c0498","importance":"normal","tieuDe":"Đụng độ Vương Lâm bên thung lũng yêu linh","text":"Đạp phi kiếm chặn Vương Lâm, ban đầu tưởng hắn là người Đại La Kiếm Tông. Khi giao đấu, bị loan đao đả thương ngực tuôn huyết quang, phải nuốt đan dược khôi phục. Y tung Kiếm toái cùng Địa diệt chi hỏa hóa sáu rồng lửa nhưng Vương Lâm dùng Sinh Chi Lạc Ấn hóa giải, suýt bị điểm trúng. Cuối cùng y nhận ra đối phương là đệ tử Thiên Vận Tử, Tử hệ lão thất Vương Lâm."},{"chuong":"@c0499","importance":"normal","tieuDe":"Thi triển Ma cấm triệu Quỷ ảnh","text":"Tu sĩ Anh Biến hậu kỳ đại viên mãn tự xưng hành sự thay Tôn sư, giao chiến với Vương Lâm trong Yêu linh khí lãng. Dùng huyết sắc ngũ sát phong ấn Côn Cực Tiên nhưng lần đầu thất bại, bị roi tiên đả thương nguyên thần; sau khi phun độc khí rút lui bất thành, hắn hút khói đen vào ngực chịu đau tột độ, thi triển Ma cấm biến tay trái thành mười Quỷ ảnh thiên quỷ đệ tứ tôn lao vào Vương Lâm."},{"chuong":"@c0501","importance":"normal","tieuDe":"Bị diệt thân, lộ thân phận La Vân","text":"Hồn thú của Vương Lâm thiêu rụi thân thể chỉ còn nguyên thần thoát ra; La Vân dùng Tổn Thần thuật hao tổn tinh hoa nguyên thần để bỏ chạy nhưng bị Côn Cực Tiên quấn bắt. Hắn xưng tên La Vân, người Thiên Quỷ Đạo, có quỷ linh bảo vệ, sư tôn là Quỷ Chân Nhân, dọa sẽ báo thù."},{"chuong":"@c0501","importance":"normal","tieuDe":"Bị Sưu Hồn, giam vào hồn phiên","text":"Vương Lâm lập cấm chế ngăn tự bạo rồi thi triển Sưu Hồn Thuật; La Vân kêu la khoảng một nén nhang rồi bất động, nguyên thần gần như trong suốt. Kết tinh trong đan điền và toàn bộ ký ức bị đoạt, nguyên thần bị giam để luyện thành chủ hồn."}],"tuViMoc":[{"chuong":"@c0501","canhGioi":"Nguyên thần Anh Biến hậu kỳ đại viên mãn","text":"Tu vi sắp bước vào Vấn Đỉnh, nhờ vậy chống được phần nào quỷ phong của hồn thú.","importance":"minor"}],"tuVi":"Nguyên thần cao hơn Vương Lâm nhiều; sở hữu phi kiếm và thủ đoạn hỏa hệ mạnh.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ chạm trán","ghiChu":"Nhận ra Vương Lâm là đệ tử Thiên Vận Tử dùng Tịch Diệt Chỉ; lo khó hạ sát vì hắn có pháp bảo bảo mệnh."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ giao chiến","ghiChu":"Bị Côn Cực Tiên của Vương Lâm đả thương nguyên thần; đáp trả bằng Ma cấm."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm diệt thân, bắt sống nguyên thần và Sưu Hồn đoạt ký ức","ghiChu":"@c0501"},{"ten":"Quỷ Chân Nhân","tag":"su-mon","quanHe":"Sư tôn","ghiChu":"La Vân dọa sư tôn sẽ báo thù (@c0501)"}],"tuiDo":{"phapBao":[{"ten":"Phi kiếm (tế kiếm)","trangThai":"hong","moTa":"Phi kiếm y đạp di chuyển, bị kiếm tiên Vương Lâm làm rạn rồi dùng làm Kiếm toái nổ vỡ.","nguon":"@c0498"}],"danDuoc":[{"ten":"Đan dược hồi thương","moTa":"Lấy từ túi trữ vật nuốt nhanh để khôi phục thương thế ngực.","nguon":"@c0498"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0498","@c0499","@c0501"]},{"id":"tu-he-lao-luc","name":"Tử hệ lão Lục","cn":"","aliases":["Lão Lục Tử hệ"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Vận Tông","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Vấn Đỉnh","trangThai":"song","blurb":"Sư huynh đồng môn Tử hệ của Vương Lâm; từng dùng tu vi Vấn Đỉnh đè ép khiến Vương Lâm mất danh hiệu Thiên Vận Thất Tử.","vaiTro":"Nhân vật được nhắc tên — ân oán tiềm tàng trong Tử hệ.","tinhCach":[],"tabs":{"diem":[{"text":"Tu vi Vấn Đỉnh, vị trí lão Lục trong Tử hệ Thiên Vận Tử.","chuong":"@c0498"}],"kinhLich":[{"chuong":"@c0498","importance":"normal","tieuDe":"Đè ép Vương Lâm giành danh hiệu Thất Tử","text":"Được nhắc lại: từng dùng tu vi Vấn Đỉnh đè ép Vương Lâm, khiến danh hiệu Thiên Vận Thất Tử không thuộc về Vương Lâm."}],"tuViMoc":[],"tuVi":"Tu vi Vấn Đỉnh.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Sư huynh đồng môn Tử hệ","ghiChu":"Đè ép Vương Lâm, gây ân oán."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0498"]},{"id":"hac-y-nam-tu-mat-seo","name":"Hắc y nhân (mặt sẹo)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0500","importance":"normal","tieuDe":"Mất Thiên Quỷ, bỏ thân chạy nguyên thần","text":"Trong trận với Vương Lâm, hắn thu Quỷ ảnh (Thiên Quỷ) nhưng bị Vương Lâm áp chế bằng Hóa ma chỉ; Thiên Quỷ tự sinh hắc quang bỏ trốn. Hắn dồn gần 90% quỷ tiên lực vào tiểu cầu hủy diệt, nhưng khi Vương Lâm mở Xạ Thần Xa thả Hồn thú, hắn buộc phải vỗ mi tâm cho nguyên thần rời cơ thể chạy trốn, để lại thân xác không hồn cho tiểu cầu lao tới."}],"tuViMoc":[{"chuong":"@c0500","canhGioi":"Anh Biến hậu kỳ đại viên mãn","text":"Tự xưng Anh Biến hậu kỳ đại viên mãn, hơn Vương Lâm một bậc, dựa vào quỷ tiên lực và Thiên Quỷ hấp thu hồn.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Đối thủ sinh tử","ghiChu":"Bị Vương Lâm áp chế, mất Thiên Quỷ, cuối cùng bỏ thân xác cho nguyên thần chạy trốn."}],"tuiDo":{"phapBao":[{"ten":"Thiên Quỷ (Quỷ ảnh)","loai":"khac","trangThai":"mat","moTa":"Quỷ vật chuyên nuốt hồn thể để tăng quỷ lực; bị ép tới mức tự sinh hắc quang bỏ trốn khỏi chủ nhân.","nguon":"@c0500"}],"congPhap":[{"ten":"Thuật khống chế Quỷ ảnh","moTa":"Dùng tơ mảnh màu đen từ ngực và tay để thu hồi và khống chế Thiên Quỷ; phải đặt tay phải trên ngực giữ thuật khỏi bị phá.","nguon":"@c0500"}],"khac":[]}},"nguon":["@c0500"]},{"id":"quy-chan-nhan","name":"Quỷ Chân Nhân","gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"trangThai":"khong-ro","blurb":"Sư tôn của La Vân thuộc Thiên Quỷ Đạo, được nói địa vị ngang hàng Thiên Vận Tử.","vaiTro":"Nhân vật được nhắc tên — mầm xung đột tương lai","tinhCach":[],"tabs":{"diem":[],"kinhLich":[{"chuong":"@c0501","importance":"minor","tieuDe":"Được nhắc qua lời La Vân","text":"La Vân dọa Vương Lâm rằng sư tôn Quỷ Chân Nhân sẽ báo thù, người này gặp Thiên Vận Tử cũng phải nói chuyện ngang hàng."}],"tuViMoc":[],"nhanMach":[{"ten":"La Vân","tag":"su-mon","quanHe":"Đệ tử","ghiChu":"@c0501"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0501"]},{"id":"la-van","name":"La Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"tu-vong","blurb":"Tu sĩ thân phận tôn quý của Thiên Quỷ Đạo, bị Vương Lâm hấp thu ký ức; bản mạng quỷ linh của hắn phản chủ do tu luyện quá ngắn.","vaiTro":"Phản diện thoáng qua","tinhCach":[{"text":"Toan tính, sẵn sàng giết người ngoài để đoạt yêu lực còn thiếu.","chuong":"@c0502"}],"tabs":{"diem":[{"text":"Thân phận tôn quý ở Thiên Quỷ Đạo, được Sư tôn ban cho một trong chín bản mạng quỷ linh phòng thân.","chuong":"@c0502"}],"kinhLich":[{"chuong":"@c0502","importance":"normal","tieuDe":"Bị đoạt ký ức và yêu tinh","text":"La Vân dựa kinh nghiệm tổ tiên Thiên Quỷ Đạo lưu lại, định kế hoạch nhập một quận trong vùng đất yêu linh để đạt chiến công, cần đủ ba giáp yêu lực nên muốn giết Vương Lâm để đoạt nốt một giáp còn thiếu. Kết cục hắn bị Vương Lâm hấp thu trọn ký ức và lấy đi yêu tinh hai giáp; bản mạng Thiên quỷ của hắn cũng phản chủ vì hắn tu luyện quá ngắn."}],"tuViMoc":[],"tuVi":"Yêu tinh trong nguyên thần đan điền tương đương hai giáp yêu lực.","nhanMach":[{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Người đoạt ký ức và yêu tinh của hắn","ghiChu":"La Vân định giết Vương Lâm để đoạt giáp yêu lực, ngược lại bị Vương Lâm chế ngự."},{"ten":"Sư tôn của La Vân","tag":"su-mon","quanHe":"Sư tôn ban bản mạng quỷ linh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0502"]},{"id":"su-ton-cua-la-van","name":"Sư tôn của La Vân","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":[{"ten":"Thiên Quỷ Đạo","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"khong-ro","blurb":"Bậc trên ở Thiên Quỷ Đạo, tự tay đưa cho La Vân một trong chín bản mạng quỷ linh yếu nhất để phòng thân.","vaiTro":"Nhân vật nhắc tên","tinhCach":[],"tabs":{"diem":[{"text":"Nắm giữ chín bản mạng quỷ linh của Thiên Quỷ Đạo, ban cho La Vân một con yếu nhất.","chuong":"@c0502"}],"kinhLich":[{"chuong":"@c0502","importance":"minor","tieuDe":"Ban quỷ linh cho La Vân","text":"Được nhắc tới khi Vương Lâm giải thích nguồn gốc bản mạng quỷ linh của La Vân."}],"tuViMoc":[],"tuVi":"","nhanMach":[{"ten":"La Vân","tag":"su-mon","quanHe":"Đồ đệ được ban bản mạng quỷ linh"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0502"]},{"id":"thap-tam","name":"Thập Tam","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Tập thể tu luyện sơn cốc (Thiên Vận Tinh)","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","trangThai":"song","blurb":"Thanh niên ở Thiên Vận Tinh có ngộ tính trời sinh với Luyện Hồn Thuật, được Vương Lâm coi trọng và đích thân cứu khi sư tử cánh dài phản phệ.","vaiTro":"Đệ tử triển vọng nhất của nhóm tu luyện Luyện Hồn Yêu Thuật trong sơn cốc của Vương Lâm.","tinhCach":[{"text":"Kính sợ và sùng kính Vương Lâm tới tận đáy lòng, cuồng nhiệt khao khát đạt tới thập/bách/thiên/vạn hồn phiên.","chuong":"@c0505"}],"tabs":{"diem":[{"text":"Ngộ tính trời sinh với Luyện Hồn Thuật, chỉ ba tháng đã tu tới giai đoạn ba, tốc độ khiến cả tiền nhân Độn Thiên cũng phải động dung.","chuong":"@c0505"}],"kinhLich":[{"chuong":"@c0505","importance":"normal","tieuDe":"Được Vương Lâm coi trọng trao ngọc giản","text":"Thập Tam chính là người Vương Lâm âm thầm theo dõi từ trước; sau ba tháng tu luyện tới giai đoạn ba, hắn được Vương Lâm gọi tới trao ngọc giản phương pháp chế hồn phiên mới, run rẩy kích động quỳ lạy ba lạy rồi lui ra toàn lực chế tạo."},{"chuong":"@c0505","importance":"normal","tieuDe":"Chế thành hồn phiên, bị sư tử phản phệ","text":"Sau ba lần thất bại, Thập Tam chế thành cây hồn phiên bảy thước đầu tiên và triệu được hồn phách sư tử cánh dài (luyện từ con sư tử trọng thương trong rừng); khi hắn hô “Thu!”, sư tử quay đầu lao thẳng vào hắn đầy sát khí, Thập Tam bị một lực vô hình giam cầm suýt chết, được Vương Lâm ra tay chấn nhiếp cứu mạng."},{"chuong":"@c0506","importance":"normal","tieuDe":"Chinh phạt động dưới lòng đất","text":"Khí chất trầm ổn kiên nghị hơn trước, Thập Tam cùng Âu Dương Hoa dẫn mười nam nhân đánh hạ bộ tộc trong động dưới lòng đất sau năm ngày. Hắn gọi chủ hồn sư tử nuốt gọn trưởng lão đối phương rồi luyện hóa hồn phách ngay trước mặt ngoại tộc, có được chủ hồn thứ hai."},{"bridge":true,"khoang":"@c0506–@c0506","text":"Được Vương Lâm ban chủ hồn sư tử cho Hồn Phiên kèm lời cảnh cáo về rủi ro phản phệ; đã luyện hóa bảy cây Hồn Phiên với hai chủ hồn."}],"tuViMoc":[{"chuong":"@c0505","canhGioi":"Giai đoạn ba (Luyện Hồn Yêu Thuật)","text":"Trời sinh ngộ tính, tu luyện Luyện Hồn Yêu Thuật ba tháng đã đạt giai đoạn ba — vượt xa đại bộ phận hai bảy người trong sơn cốc còn ở giai đoạn một. Đây là thành tựu thuộc hệ Luyện Hồn Thuật.","importance":"minor"}],"nhanMach":[{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Thượng tiên hắn sùng kính","ghiChu":"Vương Lâm âm thầm theo dõi, coi trọng, trao phương pháp mới và cứu hắn khỏi sư tử phản phệ."},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Tiền bối nhường đường","ghiChu":"Âu Dương Hoa chế xong hồn phiên trước nhưng nhường cơ hội cho Thập Tam và triệu chim sẻ cứu hắn."},{"ten":"Vương Lâm","tag":"su-mon","quanHe":"‘Thượng tiên’ dạy Luyện Hồn Thuật và ban chủ hồn","ghiChu":""},{"ten":"Âu Dương Hoa","tag":"dong-minh","quanHe":"Cùng làm chủ công trong các trận chinh phạt","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Hồn phiên thay thế (Thiên Vận Tinh)","loai":"phap-bao","trangThai":"dang-co","moTa":"Cây hồn phiên bảy thước Thập Tam tự chế thành sau ba lần thất bại, phong ấn hồn phách sư tử cánh dài.","nguon":"@c0505"}],"congPhap":[{"ten":"Luyện Hồn Thuật","loai":"cong-phap","moTa":"Thần thông Luyện Hồn Tông nhất mạch do Vương Lâm truyền, Thập Tam tu tới giai đoạn ba.","nguon":"@c0505"}]}},"nguon":["@c0505","@c0506"]}]};
